-- Poems batch 162
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ccc6f43f-9dd0-4d62-91cf-6a8fe7c13851','句  其四','辛棄疾','宋','宋诗','song-poetry','','[]','來看紅衫百子圖。',8,'全唐诗/poet.song.162000.json','["來看紅衫百子圖。"]'),
('014b9656-fb96-49a4-86c7-515a6be399aa','句  其五','辛棄疾','宋','宋诗','song-poetry','','[]','歲月都將麴糵埋。',8,'全唐诗/poet.song.162000.json','["歲月都將麴糵埋。"]'),
('c2227026-1798-4027-83cb-2c44f279711b','御書閣額  其一','辛棄疾','宋','宋诗','song-poetry','','[]','傑閣侵霄漢，宸章煥壁奎。',48,'全唐诗/poet.song.162000.json','["傑閣侵霄漢，宸章煥壁奎。", "內廷頒寶宴，中使揭璇題。", "信誓山河固，恩寵雨露低。", "寒儒倚天祿，目斷五雲西。"]'),
('967c70cb-8bd7-478c-a91c-827b9cf578b7','御書閣額  其二','辛棄疾','宋','宋诗','song-poetry','','[]','功掩蕭何第，名越崔氏堂。',48,'全唐诗/poet.song.162000.json','["功掩蕭何第，名越崔氏堂。", "孤忠扶社稷，一德契穹蒼。", "金碧飛翬外，鸞虬結綺旁。", "落成紛燕賀，弱羽得高翔。"]'),
('061f7a80-dcff-4390-a5ba-56ebaca21f78','存目  其一','辛棄疾','宋','宋诗','song-poetry','','[]','詩題：贈黄冠首句：秋至憶乘槎。',15,'全唐诗/poet.song.162000.json','["詩題：贈黄冠首句：秋至憶乘槎。"]'),
('db3e90fd-a623-40a3-942c-513ef9f0f563','存目  其二','辛棄疾','宋','宋诗','song-poetry','','[]','詩題：鵝湖夜坐首句：士生始墮地。',16,'全唐诗/poet.song.162000.json','["詩題：鵝湖夜坐首句：士生始墮地。"]'),
('ad574308-e484-455c-8351-4d47dfb9d209','三岡湖觀月','魏叔介','宋','宋诗','song-poetry','','[]','波月互吐吞，清光忽下上。',48,'全唐诗/poet.song.162000.json','["波月互吐吞，清光忽下上。", "風來山影開，空水相磨盪。", "烟樹映交加，碎入漁家網。", "仿佛華子岡，吟詩獨來往。"]'),
('3c91b071-8ab1-430d-9651-679a960d124e','火後寄詮老','木待問','宋','宋诗','song-poetry','','[]','攙槍墮九霄，列缺亂阡陌。',144,'全唐诗/poet.song.162000.json','["攙槍墮九霄，列缺亂阡陌。", "西城若黔廬，東墟已堆甓。", "幽栖僅容膝，隠市意自適。", "天公不我相，同此編戶厄。", "平生一丘壑，未信天地窄。", "終焉感窮途，萬慮集中夕。", "載觀宇宙內，在在等公宅。", "鄙夫六尺軀，俯仰歎逼仄。", "炙手事當路，快意已爛額。", "野子今兀然，乘除付陳迹。", "此身亦何有，而復身外惑。", "相逢肯分山，試面九年壁。"]'),
('116daa21-d692-4512-8426-0d22beb70f8a','千里思','木待問','宋','宋诗','song-poetry','','[]','君行千里輕所歷，妾馳千里心匪石。',64,'全唐诗/poet.song.162000.json','["君行千里輕所歷，妾馳千里心匪石。", "春房酌酒意匆匆，愁不在離愁在憶。", "鴛鴦瓦上昏無色，鸚鵡杯中塵更積。", "燈前獨坐製君衣，淚濕剪刀裁不得。"]'),
('2d1114fa-8ed1-4cdc-a265-a28196953318','郊寺','木待問','宋','宋诗','song-poetry','','[]','紅委牆陰花寂寂，翠滋亭角草纖纖。',32,'全唐诗/poet.song.162000.json','["紅委牆陰花寂寂，翠滋亭角草纖纖。", "風翻書葉常交案，雨壓爐煙不過簾。"]'),
('9698e251-6d0a-42f0-ac7b-b2e56d6db2ec','留別楊慈湖之鵝湖','沈煥','宋','宋诗','song-poetry','','[]','任地從天景孰真，何須向北定三辰。',64,'全唐诗/poet.song.162000.json','["任地從天景孰真，何須向北定三辰。", "天涯未遇蜃樓市，仙嶠偏多採藥人。", "分手傳資每歧路，知心講道更情親。", "離亭信宿梅花驛，只恐霏霏雨雪頻。"]'),
('297c6da9-301d-4cce-9a5d-bc0817a3251d','句','沈煥','宋','宋诗','song-poetry','','[]','爲學未能識肩背，讀書萬卷空亡羊。',16,'全唐诗/poet.song.162000.json','["爲學未能識肩背，讀書萬卷空亡羊。"]'),
('1c9b2ee4-cd25-4b66-bb48-632cc30a1048','神秀樓落成','趙汝愚','宋','宋诗','song-poetry','','[]','魯侯作南門，春秋書不時。',204,'全唐诗/poet.song.162000.json','["魯侯作南門，春秋書不時。", "嗟予春暮來，復遣秋暮歸。", "巖巖龍固山，迢迢括蒼溪。", "孤城煨燼餘，棟宇烟塵飛。", "悠悠客行路，一夕固藩籬。", "城中十萬家，奠枕將何期。", "賓僚賈馬儔，邑下循良師。", "經營有餘地，所就踰前規。", "西風散黄菊，天宇澄清暉。", "浩歌留飛仙，擊鼓驚馮夷。", "分題雜險怪，醉墨翻淋漓。", "別來冊府英，往往夢見之。", "恍然今夕游，似夢疑復非。", "夜深燈火闌，露下星斗移。", "父老呼童兒，挽裳或褰衣。", "來飲史君酒，聽歌史君詞。", "有淚不忍彈，恐遂行人悲。"]'),
('0e60fe34-be3f-4011-b97f-fdfd0341d3b2','劉阮廟','趙汝愚','宋','宋诗','song-poetry','','[]','當年劉阮意何窮，莫謂仙凡事不同。',32,'全唐诗/poet.song.162000.json','["當年劉阮意何窮，莫謂仙凡事不同。", "解到瓊臺雙闕下，遥知道骨與僊風。"]'),
('e7408e19-a0fd-4bfc-816a-03096ef4b14f','石橋','趙汝愚','宋','宋诗','song-poetry','','[]','法身遍滿三千界，影現天台水石間。',32,'全唐诗/poet.song.162000.json','["法身遍滿三千界，影現天台水石間。", "我欲直從心地見，來看磊磈聽淙潺。"]'),
('4394c835-27f3-4416-b302-86ff23292053','送學士汪大猷歸鄞','趙汝愚','宋','宋诗','song-poetry','','[]','尚書天官貴，持經侍帷幄。',96,'全唐诗/poet.song.162000.json','["尚書天官貴，持經侍帷幄。", "青冥欲無際，白首非故約。", "連檣動南浦，父老望巖壑。", "下車入里門，執手問歡樂。", "十年幾風雨，寒雞叫屋角。", "勤勞畢吾分，帝賚出寵渥。", "殊適奉香火，禁直連六閣。", "遂令宣室思，從今問晦朔。"]'),
('154340a2-2729-42ad-a4fe-19e0320a46aa','題竹贈衛清叔之潭州','趙汝愚','宋','宋诗','song-poetry','','[]','颸颸忽見青鸞尾，掃遍翠崖岡上頭。',32,'全唐诗/poet.song.162000.json','["颸颸忽見青鸞尾，掃遍翠崖岡上頭。", "昨夜月明仙子過，玉笙吹徹萬山秋。"]'),
('62d7ddf6-da6f-4148-a8da-1fd427af5283','致爽軒','趙汝愚','宋','宋诗','song-poetry','','[]','濃陰夾道水流渠，吹盡殘花不復餘。',32,'全唐诗/poet.song.162000.json','["濃陰夾道水流渠，吹盡殘花不復餘。", "唯有范家千畝竹，青青依舊色侵書。"]'),
('2b4710e0-07b8-4254-9dde-68b9ca47590e','同林擇之姚宏甫游鼓山','趙汝愚','宋','宋诗','song-poetry','','[]','幾年奔走厭塵埃，此日登臨亦快哉。',64,'全唐诗/poet.song.162000.json','["幾年奔走厭塵埃，此日登臨亦快哉。", "江月不隨流水去，天風直送海濤來。", "故人契闊情何厚，禪客飄零事已灰。", "堪歎世人祇如此，危欄獨倚更徘徊。"]'),
('6e4c0ede-1bfe-484f-ad5b-5651848a945b','金溪寺梅花','趙汝愚','宋','宋诗','song-poetry','','[]','金溪有梅花矗矗，平生愛之看不足。',96,'全唐诗/poet.song.162000.json','["金溪有梅花矗矗，平生愛之看不足。", "故人愛我如愛梅，來共寒窗伴幽獨。", "紛紛俗子何足云，眼看桃李醉紅裙。", "酒狂耳熱仰天笑，不特惡我仍憎君。", "但令梅花繞僧屋，梅裏扶疎萬竿竹。", "相逢歲晚兩依依，故人冰清我如玉。"]'),
('cd8b5e8d-a84b-440c-af87-56c88c16bb29','句  其一','趙汝愚','宋','宋诗','song-poetry','','[]','早晚扁舟會東下，莫占衡岳問歸程。',16,'全唐诗/poet.song.162000.json','["早晚扁舟會東下，莫占衡岳問歸程。"]'),
('b9d9fc50-3e8e-4538-b40e-c64f5067ed0c','句  其二','趙汝愚','宋','宋诗','song-poetry','','[]','寒雪冥濛外，山雲顯晦中。',12,'全唐诗/poet.song.162000.json','["寒雪冥濛外，山雲顯晦中。"]'),
('5d3b6de2-7b51-4ae9-8cb4-2f458430cf30','哭趙忠定  其一','范模','宋','宋诗','song-poetry','','[]','日月開黄道，乾坤奠渾儀。',48,'全唐诗/poet.song.162000.json','["日月開黄道，乾坤奠渾儀。", "斯人今已矣，吾道竟何之。", "玉鉉憂思苦，金縢感慨遲。", "仆碑今復立，恨不見封彝。"]'),
('15af5794-d512-4537-84ab-3edf84d90c63','哭趙忠定  其二','范模','宋','宋诗','song-poetry','','[]','鼂董青冥上，夔龍紫極邊。',48,'全唐诗/poet.song.162000.json','["鼂董青冥上，夔龍紫極邊。", "五龍方夾日，九虎已當天。", "夷險丹心直，安危白髮卷。", "吊湘人不去，何用解膠弦。"]'),
('fdce1944-adf2-400b-ae6f-9e8c5a6563f3','致爽軒','劉永叔','宋','宋诗','song-poetry','','[]','近山已作巖壑想，道邊名園堪稅鞅。',32,'全唐诗/poet.song.162000.json','["近山已作巖壑想，道邊名園堪稅鞅。", "誰家屋上無青山，惟有心清見山爽。"]'),
('4d1672f7-63fd-4f3a-85ab-c33be668d4ed','芹齋詩','林光宗','宋','宋诗','song-poetry','','[]','春風芹下足遲留，白鳥平田憶舊遊。',64,'全唐诗/poet.song.162000.json','["春風芹下足遲留，白鳥平田憶舊遊。", "閲盡軒裳還過眼，讀殘書卷復從頭。", "偶逢隠几何須問，不到投簪便擬休。", "平世聲名如皦日，欲將何地置巢由。"]'),
('197afdca-4432-4cf5-a38f-66a4f7dcfd7a','次韻奉酬趙校書子直','林光宗','宋','宋诗','song-poetry','','[]','雁塔新題墨未乾，去年燈火向秋闌。',64,'全唐诗/poet.song.162000.json','["雁塔新題墨未乾，去年燈火向秋闌。", "趣看天祿青藜杖，怕著王孫紫綺冠。", "好在三山尋浩渺，何如一紙問平安。", "觚稜皎月無人到，玉糝初成許共餐。"]'),
('732a3b73-20de-4edd-a0f7-51c0d0ddf716','九日同出真珠園再用前韻','林光宗','宋','宋诗','song-poetry','','[]','來自清源葛已覃，君王問獵我猶堪。',64,'全唐诗/poet.song.162000.json','["來自清源葛已覃，君王問獵我猶堪。", "百年耆舊如重見，九日登臨得縱談。", "才子不知汾水上，仙人長在大江南。", "明珠夜照應無數，要是層波更好探。"]'),
('60c6d521-341d-4e24-8c98-3bd0c7cdf167','辭衆偈','釋法祚','宋','宋诗','song-poetry','','[]','七十七年，幻緣忽破。',20,'全唐诗/poet.song.162000.json','["七十七年，幻緣忽破。", "秋水無痕，霜天月墮。"]'),
('b076f533-7b0b-4665-9def-1698eb584f81','宗老堂','吳鎰','宋','宋诗','song-poetry','','[]','八十郎君類若翁，一門兩世壽吾宗。',64,'全唐诗/poet.song.162000.json','["八十郎君類若翁，一門兩世壽吾宗。", "晴空矯矯歸來鶴，冬嶺槃槃晚秀松。", "重見堂懸宗老牓，大勝身襲列封侯。", "宦遊良苦端居樂，小弟輸兄冰雪容。"]'),
('4661db1c-1316-48f9-b91b-61fab1cd77a9','崇仙觀  其一','吳鎰','宋','宋诗','song-poetry','','[]','浮丘仙袂風中挹，子晉吹笙月下聞。',32,'全唐诗/poet.song.162000.json','["浮丘仙袂風中挹，子晉吹笙月下聞。", "翠蓋霓裳君過我，尻輿神馬我從君。"]'),
('81f17488-d82e-48a5-9fe5-024c535a757c','崇仙觀  其二','吳鎰','宋','宋诗','song-poetry','','[]','人生塵土不可耐，天上高寒定自嘉。',32,'全唐诗/poet.song.162000.json','["人生塵土不可耐，天上高寒定自嘉。", "但約麻姑擘麟脯，莫尋句漏問丹砂。"]'),
('1800bfc7-368e-43c4-b584-253d7a54cc9d','送客香山寺','吳鎰','宋','宋诗','song-poetry','','[]','十里香山寺，三年到幾回。',48,'全唐诗/poet.song.162000.json','["十里香山寺，三年到幾回。", "不嫌送客遠，端是愛山來。", "老木生僧住，閒雲爲我開。", "歸鞍意未足，城鼓莫相催。"]'),
('709cb748-9c7f-40f6-9c15-c3330934b216','野石巖','吳鎰','宋','宋诗','song-poetry','','[]','夏夜深如秋氣清，夢回風露濕桃笙。',32,'全唐诗/poet.song.162000.json','["夏夜深如秋氣清，夢回風露濕桃笙。", "漸忻月色分山色，所恨蛙聲亂水聲。"]'),
('3486f1aa-2392-4dfc-8b32-71e819c2d996','題敬榮堂','王自中','宋','宋诗','song-poetry','','[]','白首同居四弟兄，由渠能敬故能榮。',64,'全唐诗/poet.song.162000.json','["白首同居四弟兄，由渠能敬故能榮。", "細看鴻雁飛翔意，可見鳲鳩均一情。", "絕少分甘貧亦樂，較長爭奪勢終傾。", "黄堂今日親行酒，欲與邦人作範程。"]'),
('e3da69e2-ba7d-40c1-8f94-d1800d6d19a6','迓楊誠齋','王自中','宋','宋诗','song-poetry','','[]','江東使者行部歸，信帆一隻槳四枝。',64,'全唐诗/poet.song.162000.json','["江東使者行部歸，信帆一隻槳四枝。", "昨夜水深泥三尺，繫在誰家屋外籬。", "我欲遣人問消息，箇樣船多人不識。", "却有一事差可徵，隔船聽得哦詩聲。"]'),
('249bf592-ea88-4181-bff8-dadfec47f0b6','玉泉瀑','蔡必勝','宋','宋诗','song-poetry','','[]','珠箔飛空澗布流，卷舒曾不用銀鈎。',64,'全唐诗/poet.song.162000.json','["珠箔飛空澗布流，卷舒曾不用銀鈎。", "懸崖灑灑清涵雪，越壑溶溶冷澀秋。", "勢動羽鱗應若是，韵諧宮徵亦相侔。", "水晶不礙晴峰月，分付山靈夜莫收。"]'),
('24d6bf27-3b31-4455-9c17-767551961cdb','題嘉祐院東軒','林師蒧','宋','宋诗','song-poetry','','[]','到處已無花可吹，東風猶自舞殘枝。',32,'全唐诗/poet.song.162000.json','["到處已無花可吹，東風猶自舞殘枝。", "山僧只解關門睡，春去春來總不知。"]'),
('37733227-1520-47e6-a0c7-26d409310ab6','熊守子復左史刻九朝宸翰寘于台學賦詩記之','林師蒧','宋','宋诗','song-poetry','','[]','皇天祐宋實歷昌，列聖功德高虞唐。',288,'全唐诗/poet.song.162000.json','["皇天祐宋實歷昌，列聖功德高虞唐。", "萬機餘暇不自逸，銀鈎鐵畫揮天章。", "洋洋謨訓揭日月，留心庶事寧少忘。", "當時賜予皆賢傑，至今緹襲爲珍藏。", "丹邱史君武夷仙，快凌紫清登玉堂。", "親從芸閣獲墨本，寶如金玉留巾箱。", "承明厭直暫出守，邦人盡喜來龔黄。", "公餘鈴齋靜無事，祖宗盛烈思發敭。", "編摩允屬大手筆，白玉鏤牒陳膠庠。", "要令衿佩覩盛事，端拜伏讀思激昂。", "明如星斗麗霄漢，奎躔壁宿紛光芒。", "翻如和氣結雲霧，氛氳融液爲嘉祥。", "龍蛇委迤欲飛舉，鸞鳳宛轉爭翺翔。", "晉唐數君無出右，王顔諸子難比方。", "史君一旦出奇祕，豈與劉洎爭升床。", "亟聆飛詔下丹闕，指日入覲登明光。", "雲龍風虎慶會遇，股肱元首歌明良。", "邦人頌戴自今始，爲公紀德龜趺旁。"]'),
('b19b8674-5a30-4c53-902d-1a3217eb511d','詩二首  其一','王恕','宋','宋诗','song-poetry','','[]','地高風易作，天漏雨偏多。',24,'全唐诗/poet.song.162000.json','["地高風易作，天漏雨偏多。", "訪橘蘇仙井，看碑義帝坡。"]'),
('0fc06880-3075-4be7-b798-d915ecbc1912','詩二首  其二','王恕','宋','宋诗','song-poetry','','[]','憶昔韓退之，南征過吾州。',24,'全唐诗/poet.song.162000.json','["憶昔韓退之，南征過吾州。", "持觴看叉魚，妙句落芳洲。"]'),
('480f1ee9-ca9c-4e8d-9d8f-0ab019a55f2e','句','王恕','宋','宋诗','song-poetry','','[]','太守班春五嶺邊。',8,'全唐诗/poet.song.162000.json','["太守班春五嶺邊。"]'),
('fb6d9746-7476-4c78-b347-cc816543576c','句','呂辨','宋','宋诗','song-poetry','','[]','仰看宮殿浮天半，想見笙簫在月中。',16,'全唐诗/poet.song.162000.json','["仰看宮殿浮天半，想見笙簫在月中。"]'),
('840756b8-a11d-4e38-b455-a9d713ecd54e','劉敬子心所題桂林棲霞洞詩見寄夢想之餘次韵奉酬','楊絳','宋','宋诗','song-poetry','','[]','從教擾擾校虧成，且可蘧蘧了死生。',32,'全唐诗/poet.song.162000.json','["從教擾擾校虧成，且可蘧蘧了死生。", "八極神遊應有分，幾時杖屨得同行。"]'),
('96973d3d-d880-4747-aa18-dc9530f3be69','垂虹亭','楊絳','宋','宋诗','song-poetry','','[]','垂虹臨絕景，仙隠寄人間。',48,'全唐诗/poet.song.162000.json','["垂虹臨絕景，仙隠寄人間。", "遠水吞平野，歸雲補斷山。", "空明寬眼界，秀迥破天慳。", "深羨鴟夷子，扁舟竟不還。"]'),
('8d227513-daa6-4046-8bb2-e7876803cfbd','謹次府判朝議江公之韻 道中二首 其一','陳邦慶','宋','宋诗','song-poetry','','[]','未分中厚長夜曼，果聞胡虜膽先寒。',32,'全唐诗/poet.song.162000.json','["未分中厚長夜曼，果聞胡虜膽先寒。", "乾坤正頼英豪整，肯賦詩人行路難。"]'),
('64e1c6e7-30e3-4a00-8dc3-84dd28e2ef52','謹次府判朝議江公之韻 道中二首 其二','陳邦慶','宋','宋诗','song-poetry','','[]','別駕來臨值晚晴，眼中黑白甚分明。',32,'全唐诗/poet.song.162000.json','["別駕來臨值晚晴，眼中黑白甚分明。", "飛黄此去騰夷路，應念區區負弩迎。"]'),
('1f9e09bc-40d6-4e9a-bd00-3c167b68223a','謹次府判朝議江公之韻 遊陽華','陳邦慶','宋','宋诗','song-poetry','','[]','斷崖藏勝境，別是一壺天。',48,'全唐诗/poet.song.162000.json','["斷崖藏勝境，別是一壺天。", "怪石垂雲乳，飛虹跨玉泉。", "丹青難下筆，造化不知年。", "文字工題品，漫郎優史遷。"]'),
('8571fc67-be3f-4da5-bd06-e20ca9d9591f','遊武夷','葉樞','宋','宋诗','song-poetry','','[]','孤臺起天半，羣峰羅崔巍。',108,'全唐诗/poet.song.162000.json','["孤臺起天半，羣峰羅崔巍。", "大王挺其間，玉女相因依。", "上攀牛斗墟，下窺鷗鷺磯。", "神仙遥可接，靈草正秋肥。", "念此結綢繆，豈謂賞心違。", "浮雲亂幽壑，明月流清輝。", "白雲凄以寒，游子各言歸。", "玄鶴向我鳴，秋風吹我衣。", "願借凌風翮，送君西北飛。"]'),
('14f2d2b0-69cb-4dbd-89c0-edb58bb7c502','蔣洋道中望太姥山四首  其一','陳嘉言','宋','宋诗','song-poetry','','[]','問俗驅王事，齋宮耐可期。',48,'全唐诗/poet.song.162000.json','["問俗驅王事，齋宮耐可期。", "寒花明絳節，孤月映摩尼。", "縹渺浮虛廓，蒼茫弄晚曦。", "三山如可接，莫遣漢臣歸。"]'),
('d45fecce-456a-40db-a134-0e9176f8ec2e','蔣洋道中望太姥山四首  其二','陳嘉言','宋','宋诗','song-poetry','','[]','望裏仙蹤渺，烟霞滄海東。',48,'全唐诗/poet.song.162000.json','["望裏仙蹤渺，烟霞滄海東。", "逕迷丹竈外，人轉大還中。", "虬偃千林日，鸞吹一夕風。", "停驂遲太姥，藍水洗塵容。"]'),
('f6def700-60d5-4695-a59e-f2e5bee07326','蔣洋道中望太姥山四首  其三','陳嘉言','宋','宋诗','song-poetry','','[]','絕巘雲霄外，嵯峨杳靄間。',48,'全唐诗/poet.song.162000.json','["絕巘雲霄外，嵯峨杳靄間。", "雲將山岫溼，鶴伴月華閒。", "流水溪溪靜，琪花樹樹殷。", "攀躋猶未得，清夢遶禪關。"]'),
('4d44ba1e-7251-4080-ac79-dd1bbe093fa0','蔣洋道中望太姥山四首  其四','陳嘉言','宋','宋诗','song-poetry','','[]','層崖緣石澗，孤樹聳危橋。',48,'全唐诗/poet.song.162000.json','["層崖緣石澗，孤樹聳危橋。", "海色侵衣袂，松風破泬寥。", "佛門苔蘚古，山寺薜蘿饒。", "回首斜陽外，神仙未可招。"]'),
('d64fe585-3ccd-4d71-ae32-bca7c108b82b','四賢堂','湯起巖','宋','宋诗','song-poetry','','[]','猗與四公，棠棣之華。',195,'全唐诗/poet.song.162000.json','["猗與四公，棠棣之華。", "秀韡一時，茂興兩家。", "宋公聯翩，鄂不相鮮。", "萬里風雲，上負青天。", "連公戾契，淵冰澂結。", "進而蹩躃，砥礪其節。", "其光曄曄。", "追惟平生，法興是儀。", "邑人之思，右史之詞。", "雨箔風楹，歲環幾經，築此特堂。", "吾今令君，令君勤民。", "民燕其德，振滯補弊，此焉居一。", "于時四公，序集其觴。", "生氣津津，冠佩有光。", "古之爲政，崇德尚賢。", "居今篤古，令君有焉。", "君系隴西，紹祖維名。", "起巖作詩，輯和厥聲。", "敢告典者，毋替其承。"]'),
('c3eda1d6-86e7-4ef6-a3a9-d3fb75946be4','拜于湖張狀元墓留題','朱曠','宋','宋诗','song-poetry','','[]','瘦馬踏亂山，盤折度村塢。',156,'全唐诗/poet.song.162000.json','["瘦馬踏亂山，盤折度村塢。", "處處花柳明，耕鋤徧壠畝。", "麥苗見膚寸，拳屈方出土。", "乃知去夏旱，布種坐遲暮。", "夏租竟如何，未免催迫苦。", "投鞭扣蕭寺，來謁張公墓。", "再拜拭淚行，疇昔感知遇。", "盛年厭紛華，騎鯨上天去。", "校讎三洞章，飛仙自儔侶。", "笑唾人間世，一品竟何補。", "世人患死生，未究死生故。", "是生本不滅，來往若寒暑。", "休矣勿復言，僧窗睡春雨。"]'),
('12441dd1-cd51-4c32-9501-03212b83b501','題辛稼軒齋','彭止','宋','宋诗','song-poetry','','[]','棋子聲乾案接塵，午窗詩夢暖於春。',32,'全唐诗/poet.song.162000.json','["棋子聲乾案接塵，午窗詩夢暖於春。", "清風不動階前竹，誰道今朝有故人。"]'),
('61beb3bb-b51c-4538-a9dd-7a9e5844a0ac','四賢古風壽帥閫 老聃子','彭止','宋','宋诗','song-poetry','','[]','昔在羲皇前，遂有鬰華子。',120,'全唐诗/poet.song.162000.json','["昔在羲皇前，遂有鬰華子。", "蒼姬握圖籙，更出爲柱史。", "應世抑何久，萬有千餘祀。", "一日將度關，崑崙且西指。", "短車駕青犢，上有紫雲起。", "占風知聖人，再拜勤尹喜。", "授之五千言，試一撮玄旨。", "是身求不殆，其要在知止。", "萬事皆倘來，軒冕直寄耳。", "乘雲遊太清，坐進長生理。"]'),
('86122cee-696d-4b8f-abfb-04b11cde6f77','四賢古風壽帥閫 廣成子','彭止','宋','宋诗','song-poetry','','[]','崆峒鬰岧嶢，直上萬丈强。',144,'全唐诗/poet.song.162000.json','["崆峒鬰岧嶢，直上萬丈强。", "中有廣成居，白石砌華房。", "抱神靡自役，室靜藹生光。", "歲丁千二百，來今詎可量。", "土德方在御，齋心造其旁。", "至道顧何在，願一示其方。", "雲飛不待族，木落不待黄。", "形勞精則摇，於道未相當。", "失之下爲士，得者上爲皇。", "妙訓閟玄局，爲公發天藏。", "誠能守其一，智故兼相忘。", "往遊無極樂，二儀久相長。"]'),
('55db6ca2-fc99-4608-b425-72912de19224','四賢古風壽帥閫 赤松子','彭止','宋','宋诗','song-poetry','','[]','古之得道士，住世詎可期。',120,'全唐诗/poet.song.162000.json','["古之得道士，住世詎可期。", "吾觀赤松子，宛在神農時。", "隨飈欻上下，分職爲雨師。", "炎皇女得仙，馭氣常追隨。", "帝降以逮王，嬴氏接蒼姬。", "更革非一代，隠見不可知。", "赤精制六合，子房定王基。", "功成應天道，挺身往從之。", "名列太玄童，玉女如嬰兒。", "願言踵高躅，壽命一如斯。"]'),
('e548f2cc-02a4-4af6-bfe0-7e711545a990','四賢古風壽帥閫 和安老人','彭止','宋','宋诗','song-poetry','','[]','煌煌王侯族，富貴甘如蜜。',180,'全唐诗/poet.song.162000.json','["煌煌王侯族，富貴甘如蜜。", "飄飄學仙侶，翅舉自蓬蓽。", "且如王子晉，玉笙吹已畢。", "白鶴忽來尋，乘虛氣何逸。", "劉安振其後，飛騰聞舉室。", "微如雞犬類，雲間詎相失。", "斯乃帝王孫，安在岩穴出。", "至今和安老，千載與相匹。", "沙土暨雲陽，聞諸經所述。", "此地可長生，得之養形質。", "乃知朝市隠，勝彼山林日。", "和平能毓氣，安靜常抱一。", "號名豈虛假，是謂練形術。", "焉用採昌陽，寧須茹芝朮。", "從今列仙傳，當續更生筆。"]'),
('aab52281-9f19-4576-8ec0-94657aa91625','句  其一','彭止','宋','宋诗','song-poetry','','[]','天西玉一鈎。',6,'全唐诗/poet.song.162000.json','["天西玉一鈎。"]'),
('b214b6a1-12ac-4235-b03c-25cad9b20bec','句  其二','彭止','宋','宋诗','song-poetry','','[]','吾生良可嗟。',6,'全唐诗/poet.song.162000.json','["吾生良可嗟。"]'),
('a708f655-fbdd-4174-9591-72a2d348f9b0','句  其三','彭止','宋','宋诗','song-poetry','','[]','可憐蹤跡似流萍。',8,'全唐诗/poet.song.162000.json','["可憐蹤跡似流萍。"]'),
('6626e679-7ff4-4e08-8d1d-c7e079eae792','賦滕王閣謁辛稼軒','胡時可','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王高閣臨江渚，帝子不來春已暮。',32,'全唐诗/poet.song.162000.json','["滕王高閣臨江渚，帝子不來春已暮。", "鶑啼紅樹柳摇風，猶似當年舊歌舞。"]'),
('419d21e5-ff84-443d-b0d2-fa8f7eb7515a','歌','莎衣道人','宋','宋诗','song-poetry','','[]','胡孫死，閙啾啾，也須還我一百州。',16,'全唐诗/poet.song.162000.json','["胡孫死，閙啾啾，也須還我一百州。"]'),
('e4f628c5-b672-4e6f-96b4-3df0b69ff317','餞張平甫折海棠贈之','蔡戡','宋','宋诗','song-poetry','','[]','天公作晚晴，得得送行客。',72,'全唐诗/poet.song.162000.json','["天公作晚晴，得得送行客。", "海棠新過雨，染就胭脂色。", "醉臉嬌未勻，啼粧紅欲滴。", "勸君白玉巵，一醉不足惜。", "我生酷愛花，爲君須小摘。", "後夜月滿船，持此伴幽寂。"]'),
('77b41a5e-a294-4822-84de-8479cf3f328e','同張叔囦顧致堯遊金山受之憚於涉險爽約不行因以詩簡之','蔡戡','宋','宋诗','song-poetry','','[]','我昔遊天都，策足蓬萊山。',240,'全唐诗/poet.song.162000.json','["我昔遊天都，策足蓬萊山。", "風日不到處，意謂非人寰。", "一涉勢利塗，未免塵埃間。", "了知此身累，痛自鎸冥頑。", "浩然動歸志，暫得浮心閒。", "金焦勝絕地，自古名東南。", "兩峰鬰相望，宛若雙雲鬟。", "我欲事幽討，不憚涉險艱。", "同行二三子，壯氣不可干。", "欣然從我遊，竟日勞躋攀。", "江神亦可人，爲我風少慳。", "要知仗忠信，可以行百蠻。", "阿連有童心，平生怯波瀾。", "欲去足先澀，未語膽已寒。", "謂有性命憂，力勉終辭難。", "我行自不惡，盡得奇絕觀。", "匆匆理回棹，此興殊未闌。", "阿連驚我歸，喜氣形眉端。", "殷勤爲我賀，不意能生還。", "索酒共一醉，相對俱歡顔。"]'),
('f4e18b67-0e28-41ee-b1ad-abab5e678ed4','憶小兒','蔡戡','宋','宋诗','song-poetry','','[]','中年再舉子，可喜亦可憐。',96,'全唐诗/poet.song.162000.json','["中年再舉子，可喜亦可憐。", "半晬已知父，舉手拊我肩。", "欲別不忍去，離懷重悽然。", "兒生苦多病，此念有拳拳。", "江聲鏖旅枕，展轉不得眠。", "恍若聞兒聲，常如在目前。", "我思不能已，汝病何當痊。", "王事相促迫，平明又加鞭。"]'),
('accc34f2-c4c4-4df4-913d-bf57596b96f1','趙季若染髭走筆簡之','蔡戡','宋','宋诗','song-poetry','','[]','趙子方五十，鬚鬢何斑斑。',120,'全唐诗/poet.song.162000.json','["趙子方五十，鬚鬢何斑斑。", "身老心未伏，攬鏡嗟衰殘。", "染髭學年少，整容向雲鬟。", "世間有仙訣，坐使壯歲還。", "霜華喜頓改，霞脚驚先斕。", "乃知人力窮，欲奪造化難。", "黑白變朝暮，相對真面謾。", "眉目且作僞，而况方寸間。", "勸君循天理，頹然任蒼顔。", "漢廷方貴老，白首尚握蘭。"]'),
('423043c6-5e55-48fc-9df2-8d22dfe9139e','瓊花','蔡戡','宋','宋诗','song-poetry','','[]','平生湖海氣，浪自青雲期。',180,'全唐诗/poet.song.162000.json','["平生湖海氣，浪自青雲期。", "一爲蓬萊遊，時動泉石思。", "徒糜太倉粟，飽食終日嬉。", "尸素亦已甚，勇退夫何疑。", "直道無所愧，願學柳士師。", "歸來食不足，三歎汝墳詩。", "親老尚擇祿，富貴當何時。", "捧檄强自喜，安敢辭驅馳。", "顧我性蕭散，軒裳縛伊尼。", "何當出幕府，還把江海麾。", "思親匪懷土，此意惟君知。", "君抱四方志，扁舟羨鴟夷。", "要先句踐霸，乃以西子隨。", "不妨食肉相，兼有絕俗姿。", "暫淹芙蓉幕，亟歸鳳凰池。"]'),
('fff492bc-5cc9-4e3c-a414-0cc6cb910c0e','姚幹舜陟約觀瓊花因循未能往以詩相促因次前韻','蔡戡','宋','宋诗','song-poetry','','[]','少年逐春心，作意酬花期。',192,'全唐诗/poet.song.162000.json','["少年逐春心，作意酬花期。", "壯大頗更事，舉足先三思。", "况有簡書畏，本非倦游嬉。", "姚子磊落人，自信了不疑。", "應變似乃祖，未肯爲獵師。", "婉畫多暇日，餘事長于詩。", "秀句摹勝景，清尊樂芳時。", "對花不忍去，唯恐光景馳。", "愧我但局促，潔心似毗尼。", "門牆可羅雀，敢作揚雄麾。", "高軒時過我，不遣俗客知。", "幕中向無事，世路方坦夷。", "要當休沐日，飛蓋還相隨。", "靈祠花藥麗，皎皎方含姿。", "何妨修禊事，流杯宴瑶池。", "我欲爲親壽，憑君折繁枝。"]'),
('8c4ba1ca-1668-47da-94ad-cfe578619a5f','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','我家本儒素，爲吏廉而貧。',48,'全唐诗/poet.song.162000.json','["我家本儒素，爲吏廉而貧。", "所仰斗升祿，役役常苦辛。", "無地可置錐，有釜多生塵。", "空餘清白操，以此遺後人。"]'),
('3df95bc9-3c5b-4356-a4fc-64d93f654341','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','憶昔少年日，抗志期青雲。',48,'全唐诗/poet.song.162000.json','["憶昔少年日，抗志期青雲。", "宦遊三十載，所歷多艱勤。", "四持湖海節，再餉江淮軍。", "全家得飽暖，何以報吾君。"]'),
('307bd387-bd36-4075-8bff-3ecd0c2e8652','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其三','蔡戡','宋','宋诗','song-poetry','','[]','獨醒衆所忌，尸素心懷慚。',48,'全唐诗/poet.song.162000.json','["獨醒衆所忌，尸素心懷慚。", "既有不堪七，豈止宜休三。", "再刖皆自取，百謫其猶甘。", "歸歟一邱壑，卜築蘭陵南。"]'),
('8a40d634-4557-4b5a-bff5-851369fc815b','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其四','蔡戡','宋','宋诗','song-poetry','','[]','晏子近囂塵，蕭何處窮僻。',48,'全唐诗/poet.song.162000.json','["晏子近囂塵，蕭何處窮僻。", "我居城市間，而有山林適。", "一水带清泚，萬竹環翠密。", "亦足了此生，人壽稀七十。"]'),
('a963d4c3-3d49-4728-9ba5-b4a290061d16','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其五','蔡戡','宋','宋诗','song-poetry','','[]','南軒款佳客，北堂奉高年。',48,'全唐诗/poet.song.162000.json','["南軒款佳客，北堂奉高年。", "兩廡闢數舍，幼累聊伏跧。", "未能大門閭，豈暇週牆垣。", "求足何時足，萬事姑隨緣。"]'),
('9a2d7312-834a-4ce9-b3f0-88824261c2f8','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其六','蔡戡','宋','宋诗','song-poetry','','[]','我居本寬餘，湫隘良有以。',48,'全唐诗/poet.song.162000.json','["我居本寬餘，湫隘良有以。", "子舍雖不多，聚族五百指。", "月俸均薄少，晨炊共甘美。", "憂責叢一身，冥行不知止。"]'),
('bd0f178a-77b2-4dc0-accf-fa0474bb2167','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其七','蔡戡','宋','宋诗','song-poetry','','[]','庭前植三桂，門外栽五柳。',48,'全唐诗/poet.song.162000.json','["庭前植三桂，門外栽五柳。", "有禽號仙客，愛蓮呼靜友。", "鄰牆竹千挺，晚色落杯酒。", "終日對此君，烏知非我有。"]'),
('9e40edff-4def-433e-a88d-e2ecf86a4dae','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其八','蔡戡','宋','宋诗','song-poetry','','[]','旁有十畝園，荒穢久不理。',48,'全唐诗/poet.song.162000.json','["旁有十畝園，荒穢久不理。", "荷鋤薙榛蕪，連筒灌桃李。", "因高築小坡，就下鑿深沚。", "杖屨日往來，居閒頼有此。"]'),
('d46fc308-c5cb-40fe-91a1-0af59509af87','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其九','蔡戡','宋','宋诗','song-poetry','','[]','我亦大癡人，勸者多不足。',48,'全唐诗/poet.song.162000.json','["我亦大癡人，勸者多不足。", "抖擻囊中金，傾倒囷內粟。", "雖云壁徒立，尚有田可鬻。", "百口勿啼饑，張頤仰看屋。"]'),
('6638f136-c719-4155-b9cf-4dcb16645f15','新居用韓昌黎詩辛勤三十年以有此屋廬爲韻作十詩  其一○','蔡戡','宋','宋诗','song-poetry','','[]','平生湖海氣，志廣更才疎。',48,'全唐诗/poet.song.162000.json','["平生湖海氣，志廣更才疎。", "致君初無術，許身一何愚。", "慨念天下士，四海無家居。", "但願庇廣厦，不唯愛吾廬。"]'),
('884ecbad-7c04-4e3c-aa2e-6f39fec0f824','朱丈朝宗索壺村落成之集次韻簡之','蔡戡','宋','宋诗','song-poetry','','[]','我本巖壑姿，浪謂蓬瀛客。',240,'全唐诗/poet.song.162000.json','["我本巖壑姿，浪謂蓬瀛客。", "下惠猶三黜，孟公甘百謫。", "况如腹背毛，敢意青雲翮。", "一麾江海去，自分仙凡隔。", "稅駕荆溪東，屏居在幽穴。", "雖無二頃田，頼有一區宅。", "壺村咫尺地，聊以適其適。", "公家百畝園，下視雲夢窄。", "風雲滿襟袖，煙霞拂巾幘。", "清溪一派流，端疑巨靈擘。", "桃李自成蹊，皆公手封植。", "顧我鄶無譏，敢比齊楚國。", "大厦未落成，何事先促迫。", "一笑真莫逆，兩賢豈相厄。", "我貧釜生魚，傳家尚清白。", "八珍絕肥甘，一枕但甜黑。", "抹月批清風，客至聊具食。", "乃知造物公，獨此每無擇。", "書生耳目寒，得之即聲色。", "公若肯一來，與公分所得。"]'),
('ee6cd903-1612-4958-8361-7f5bb2b7a773','病中紀事','蔡戡','宋','宋诗','song-poetry','','[]','我生天地間，甲子倏一周。',216,'全唐诗/poet.song.162000.json','["我生天地間，甲子倏一周。", "歲與命相迫，災釁非人謀。", "抱病卧漳浦，荏苒久不瘳。", "傴僂腰欲折，偃仰筋如抽。", "痛楚徹心膂，呻吟損咽喉。", "浹背汗淋瀝，環膝寒颼飀。", "晨興服絺綌，夜卧重衾裯。", "垢膩生蟣蝨，爬搔變瘡疣。", "寢食殆俱廢，起處寧自由。", "跬步遠千里，窘局如拘囚。", "艾火既妄灼，藥劑還輕投。", "以此千金軀，寄命庸醫流。", "展轉幾十旬，初夏俄清秋。", "去死一間耳，自歎如浮漚。", "有身即有患，無生乃無憂。", "彭殤齊壽夭，螻蟻同王侯。", "四大非我有，外物何勞求。", "委心以待盡，死生任浮休。"]'),
('45d939c2-dd56-4fa5-93ed-5752fddc3e7f','效白樂天體自詠二十韻','蔡戡','宋','宋诗','song-poetry','','[]','人生七十稀，我今六十六。',240,'全唐诗/poet.song.162000.json','["人生七十稀，我今六十六。", "幼小承門資，長大竊科目。", "平步登瀛洲，超遷應郎宿。", "省寺久徊翔，京華厭馳逐。", "七持使者節，三剖刺史竹。", "晚玷兩禁班，濫紆三品服。", "游宦四十年，徒糜太倉粟。", "君恩無以報，捫心自慙恧。", "吾聞老氏言，知足乃不辱。", "力辭會稽組，願賦祠庭祿。", "舉首謝鵷鴻，甘心友麋鹿。", "家有十頃田，居多數椽屋。", "長子通朝籍，二女歸仕族。", "貤恩沾弟姪，餘俸贍親屬。", "始望豈及此，平生不啻足。", "無奈百病侵，齒豁頭已禿。", "指攣足蹣跚，背駝腰屈曲。", "消長自乘除，禍福多倚伏。", "枚數親舊間，十九登鬼錄。", "自憐衰病翁，詎知不爲福。"]'),
('a245fc9a-44a8-4751-933f-4296367f191e','又自詠效樂天體','蔡戡','宋','宋诗','song-poetry','','[]','我家曾高來，享年稀六十。',120,'全唐诗/poet.song.162000.json','["我家曾高來，享年稀六十。", "吾祖逾九齡，屈指十之一。", "嗟予蒲柳姿，不覺開七秩。", "雖幸延殘年，其奈嬰末疾。", "人生一世間，無異駒過隙。", "孔跖俱塵埃，彭殤漫欣戚。", "苟免饑寒憂，况又婚嫁畢。", "生亦何可戀，死固不足惜。", "棺槨已素具，墳壠漸加葺。", "委順以待時，臘月三十日。"]'),
('82a53fd0-f78c-45fc-bb04-c0f96deea051','題端約喜神詩','蔡戡','宋','宋诗','song-poetry','','[]','高樓結蜃橋垂虹，人間夢幻色即空。',144,'全唐诗/poet.song.162000.json','["高樓結蜃橋垂虹，人間夢幻色即空。", "何勞愚智徒相攻，無異蠻觸戰蝸蟲。", "先生學道尤溫恭，皎然明月來窗櫳。", "幅巾宛有林下風，身雖隠約聲如鏞。", "何人爲寫冰雪容，屹若山立凝神鋒。", "長松詰曲盤虯龍，朱藤緩步行松中。", "治世乃有商山翁，青鞋不踏京塵紅。", "宦遊已悟禽入籠，誰能薄祿仰釜鍾。", "百年駒隙成匆匆，一廛可老荆谿東。"]'),
('e413ee6b-d40e-4c54-b52b-e29856d07aab','家父約端約飯端約以疾辭乃作古風併送臘梅數枝因次前韻','蔡戡','宋','宋诗','song-poetry','','[]','詩仙逸氣舒長虹，一洗萬古凡馬空。',144,'全唐诗/poet.song.162000.json','["詩仙逸氣舒長虹，一洗萬古凡馬空。", "五車蠹字勤且攻，不肯區區辨魚蟲。", "雪中鶴氅如王恭，誰能低唱深簾櫳。", "年來何事怯霜風，閉門索句鳴笙鏞。", "新詩爲我開愁容，退避豈敢爭詞鋒。", "君不可屈真卧龍，小窗獨坐時一中。", "故折金蓓贈我翁，絕勝桃杏漫山紅。", "君詩當得碧紗籠，此花宜侑琉璃鍾。", "走筆寄謝仍匆匆，昏暮叩戶驚隣東。"]'),
('794644d8-9780-4ce8-b819-5d0c230c3546','再用前韻酬端約','蔡戡','宋','宋诗','song-poetry','','[]','君才千丈騰彩虹，揮毫落紙萬象空。',144,'全唐诗/poet.song.162000.json','["君才千丈騰彩虹，揮毫落紙萬象空。", "我猶頑石不可攻，愁吟嘈雜鳴寒蟲。", "典刑况有先文恭，短檠終夜臨書櫳。", "騷雅不減陶謝風，簫韶迭奏鼓與鏞。", "顧我羞澀難爲容，鉛刀一割無餘鋒。", "古人相遇如雲龍，交情自得氣槩中。", "翛然坐對兩臞翁，一笑莫逆醉臉紅。", "世間萬事空牢籠，信知我輩情所鍾。", "舉杯屬君無匆匆，人生聚散西復東。"]'),
('90090294-ac21-40dc-a9c9-f39affaeded5','送張安國舍人','蔡戡','宋','宋诗','song-poetry','','[]','若有人兮下天陬，乘雲戲作人間遊。',272,'全唐诗/poet.song.162000.json','["若有人兮下天陬，乘雲戲作人間遊。", "飄飄逸氣橫九州，明光射策動冕旒。", "一揮坐遣千人休，老生瑟縮徒包羞。", "餘子走僵汗且流，自顧跛鼈驚驊騮。", "大兒文舉小兒脩，眼高四海非吾儔。", "堂堂人物傾曹劉，冰壺玉尺懸清秋。", "胸次二十八宿周，筆力乃與造化侔。", "揮毫落紙蟠龍虯，殘篇醉墨人爭收。", "蚤年嬉笑登瀛洲，螭坳鳳閣增皇猷。", "出典方面分顧憂，昔襦今袴歡成謳。", "六州父老思故侯，往往在處甘棠留。", "祠庭均逸心夷猶，祇恐富貴來相求。", "公今起自曲江頭，蒲帆十幅風颼飀。", "微官拘縛如楚囚，雖欲從公嗟無由。", "君王仄席勤咨諏，姓字當已覆金甌。", "入登廊廟參籌謀，勳庸併使書銀鈎。", "他時東閣羅枚鄒，賤子還許登門不。"]'),
('0586fe72-c41c-4d4d-b0b7-88e856442187','送莫子漳還朝','蔡戡','宋','宋诗','song-poetry','','[]','長安車馬聲隆隆，千官朝入明光宮。',384,'全唐诗/poet.song.162000.json','["長安車馬聲隆隆，千官朝入明光宮。", "我時迹通金閨籍，猥以麋鹿參鵷鴻。", "魏闕聯鑣競趨走，漢殿屬袂陪肅雍。", "銀章朱紱赤縣令，一見傾蓋稠人中。", "搢紳交口譽盛美，政有三異如魯恭。", "不勞烹鮮撫赤子，不憚拔薤鋤强宗。", "二年惠澤洽百里，一日治行聞九重。", "帝曰卿才當大用，乃使驥騄試蟻封。", "毗陵今日股肱郡，往來水陸當其衝。", "比年積蠹寖不治，公私赤立帑廩空。", "與我共理二千石，無以踰此强項公。", "割鷄焉用庖丁手，斲鼻乃見匠石工。", "公初下車問疾苦，萬家和氣生春風。", "政平訟理百廢舉，昔襦今袴喧兒童。", "鈴齋宴坐未暖席，宣室趣召還追鋒。", "公來邦人歎何暮，不謂公去仍匆匆。", "依劉多士願莫遂，借寇千里嗟無從。", "聖朝籲俊方重內，此行自與登仙同。", "高士不妨爲主簿，先儒蓋亦嘗司農。", "功名富貴儻來物，寧論小釜與大鍾。", "古人立朝有始末，出處進退常雍容。", "君家伯氏典刑在，願君勉力追前蹤。", "贈言敢竊仁者號，聊以寫我磊磈胸。", "方今天子堯舜上，安得稷契輸誠衷。"]'),
('647479de-72d3-4e7d-95f6-fc69c40cba72','長風沙','蔡戡','宋','宋诗','song-poetry','','[]','舟人指點長風沙，寂寞煙村三數家。',64,'全唐诗/poet.song.162000.json','["舟人指點長風沙，寂寞煙村三數家。", "寒日熒熒照楓葉，霜風槭槭飛蘆花。", "江頭景物自不惡，買魚沽酒時獨酌。", "扁舟日日弄煙波，此生空羨漁家樂。"]'),
('12cf49a3-c8d7-4da3-b1f3-bea7b6fe07dc','和楊廷秀游蒲澗之什','蔡戡','宋','宋诗','song-poetry','','[]','我來戲作南海游，兩驚落葉鳴新秋。',256,'全唐诗/poet.song.162000.json','["我來戲作南海游，兩驚落葉鳴新秋。", "文書暇日得勝侶，登臨清賞追遨頭。", "萬壑爭流如爪裂，天公幻出神仙窟。", "巖前滴水七月寒，巖下飛濤四時雪。", "要當躡履携枯藤，躋攀石磴褰裳行。", "勿令俗物敗人意，暫止喝道聽松聲。", "安期已去寧復見，井竈漫傳丹九轉。", "尚餘玉舄在人間，特特追尋不辭遠。", "脚力已盡病莫興，好山無窮相送迎。", "山林鐘鼎雖異趣，嶔崎犖确皆勞生。", "更上危樓臨峭壁，時見疎林鳥飛白。", "一峰突兀鬰相望，萬頃滄波湛空碧。", "此身疑是在蓬壺，下瞰城郭如盤盂。", "恨無詩才可八斗，領略羣山但巵酒。", "人生上壽不百年，白雲駕我我即仙。", "從此去天只尺五，俯仰人間自今古。"]'),
('aa812faf-e839-4943-96c1-2481bf429203','筇竹杖歌','蔡戡','宋','宋诗','song-poetry','','["\u8861\u5c71"]','我有一枝筇，夭矯如游龍。',232,'全唐诗/poet.song.162000.json','["我有一枝筇，夭矯如游龍。", "由來博望使西域，萬里持寄衰病翁。", "自蜀歷楚入吳越，名山勝地多留蹤。", "先排衡山雲，直上南臺升祝融。", "次登峴山首，北望京洛浮塵中。", "白鷺洲前弄明月，黄鶴樓上迎清風。", "東遊秦望探禹穴，天台鴈蕩觀奇峰。", "孤根端有歲寒操，勁節肯染京塵紅。", "飄然飛去不可執，西山南浦聊從容。", "放行天地無障礙，倚觀宇宙皆虛空。", "橫挑斜曳任所適，去來無定如飛鴻。", "提携九節常在手，四方上下俱相從。", "我常病足不能履，頼汝左右扶持功。", "老形已具身傴僂，詎可一日無此公。", "杖兮切勿化龍去，留取百歲扶衰慵。"]'),
('c050054b-d9c5-4e57-b983-07674d0eaf61','奉和子真學士詠雪之什','蔡戡','宋','宋诗','song-poetry','','[]','千里同雲欲曛黑，風掠寒郊聲摵摵。',224,'全唐诗/poet.song.162000.json','["千里同雲欲曛黑，風掠寒郊聲摵摵。", "初疑窗外忽增明，俄見階前已紛積。", "曉來戲作漫天飛，臘後喜占平地尺。", "回飆凌亂競穿簾，作態橫斜巧投隙。", "乾坤浩蕩迷俯仰，唯有寒江湛空碧。", "扁舟遠訪漫乘興，敗履徐行間留跡。", "向晚漁蓑入畫圖，清夜雞窗映文籍。", "從教高卧野人廬，未饒低謁王侯宅。", "灞橋才子更清絕，强把枯腸苦搜索。", "最憐擾擾雪中人，晨突無煙有饑色。", "何當三白兆豐年，盡挽八荒歸樂國。", "不但新春壓災瘴，且喜明年飫麩麥。", "我家頼有二頃田，老去功名慵轉劇。", "人生一飽復何求，卒歲優游聊自得。"]'),
('7a407ce1-cf29-4e64-89ee-887c9690ece3','再次前韻上呈','蔡戡','宋','宋诗','song-poetry','','[]','雲幙四垂頭上黑，微霰飛霙初摵摵。',224,'全唐诗/poet.song.162000.json','["雲幙四垂頭上黑，微霰飛霙初摵摵。", "衾裯不暖夜更寒，庭戶無聲曉仍積。", "漫空龍鳳落萬家，入地螟蝗想千尺。", "因風作響爭敲窗，得月交光先透隙。", "園林巧綴鬭新奇，樓觀勻鋪失金碧。", "今朝知是謫仙來，門前踏作瓊瑶迹。", "雪車句好憶劉叉，縞带詩成走張籍。", "但得同傾北海尊，不妨屢過揚雄宅。", "須知里社樂有餘，正恐太倉米徒索。", "愁吟時作郊島寒，飽食幸無陳蔡色。", "破賊空慙李常侍，仗節未許蘇屬國。", "祇今力穡學老農，剩喜流膏滋宿麥。", "杜陵一飯不忘君，憂國丹心老彌劇。", "願言玉燭常均調，萬物忻忻俱自得。"]'),
('5a35efe5-fdf3-4076-9f51-77969f108595','大雪不止再次前韻','蔡戡','宋','宋诗','song-poetry','','[]','玄冥一怒天地黑，巽二前驅聲摵摵。',224,'全唐诗/poet.song.162000.json','["玄冥一怒天地黑，巽二前驅聲摵摵。", "須臾白帝振軒裳，龍鳳幡旂交委積。", "舊傳洛邑深丈餘，今比常山纔數尺。", "天公作意逞陰機，翦水裁霜巧無隙。", "雲濤萬頃俱浩蕩，海風吹散琉璃碧。", "坤軸摧壓幾欲頹，日輪埋沒渾無跡。", "定知謫墮萬玉妃，紫府清都削名籍。", "可惜飛瓊天不管，等閒幻作神仙宅。", "詩人嘲弄困萬象，苦思不妨閉門索。", "攢眉呵手撚凍髯，得意忻然見顔色。", "英詞逸氣吞江湖，竊比君才如楚國。", "看花君子待新晴，又見春風摇燕麥。", "我方疊石築小坡，人笑老翁似兒劇。", "何當躡履共登臨，一覽山川皆盡得。"]'),
('321cf37a-f182-46e6-9539-71d2d09f5ed2','子真新篇愈出愈工壓倒元白三歎不已勉强再次前韻','蔡戡','宋','宋诗','song-poetry','','[]','獨守寒窗坐昏黑，怪底打門聲摵摵。',224,'全唐诗/poet.song.162000.json','["獨守寒窗坐昏黑，怪底打門聲摵摵。", "呼童秉燭誦新詩，篋笥珠璣喜盈積。", "君家文焰萬丈長，愧我才慳真退尺。", "往來政自足風流，唱酬聊可供閒隙。", "劇談快飲坐生春，一笑相看眼俱碧。", "曉來百鳥報新晴，漸喜門前多轍迹。", "眼明頓覺有春意，耳冷况聞開樂籍。", "何勞空泛剡溪舟，不如沉醉高陽宅。", "樓迥吹殘玉笛寒，杯乾笑指銀瓶索。", "遥知塞上積雪深，千里關山同一色。", "夕烽罷警鐵衣閒，聘幣星馳交兩國。", "使華不用吞旃毛，邊吏何憂取溫麥。", "祇憐魚貫挽舟人，墮指裂膚聲苦劇。", "東風吹作一尺泥，山鳥却愁行不得。"]'),
('2612c673-dd63-446e-826f-7c3a45b053ab','朱朝宗割愛嫁遣侍兒忘情如此是可尚也因作忘情吟以道哀怨之意','蔡戡','宋','宋诗','song-poetry','','[]','風流漢署尚書郎，蛾眉列屋呈新粧。',318,'全唐诗/poet.song.162000.json','["風流漢署尚書郎，蛾眉列屋呈新粧。", "中有一人十四五，雪膚花艷傾後房。", "妬寵負恃亦常理，何乃棄置行路傍。", "妾如桃李眩顔色，君如鐵石爲心腸。", "憶昔贈君綠綺琴，佳期密意寓琴心。", "白雪陽春世寡和，高山流水誰知音。", "燕子樓中空寂寞，鳳凰臺上忍登臨。", "瓶沉簪斷不堪說，釵分鏡破何由尋。", "君不見韓退之，絳桃柳枝二侍兒。", "別來柳枝已飛去，故作鎮州初歸詩。", "又不見白樂天，小蠻樊素爭取憐。", "晚年樊素欲謝遣，因賦不能忘情篇。", "從來我輩情所鍾，綿綿此恨今古同。", "世間尤物最爲累，須信萬事浮雲空。", "二公號爲知道者，未免愛慾纏胸中。", "果能脫去如敝屣，自古未有賢於公。", "料得文君對長卿，小窗時鼓一再行。", "幽愁暗恨欲備寫，離鸞別鶴難成聲。", "知君手種堂前柳，春風披拂還輕盈。", "憐新棄舊似淺薄，如君未必真忘情。"]'),
('e1f74537-e795-45e2-a81a-71aadd9424e9','有感','蔡戡','宋','宋诗','song-poetry','','[]','人生一世間，常苦不自足。',138,'全唐诗/poet.song.162000.json','["人生一世間，常苦不自足。", "冬寒但重裘，日食唯一肉。", "所須能幾何，甘心事馳逐。", "何郎費萬錢，徒令厭僮僕。", "長卿乘駟馬，祇欲誇世俗。", "于我何有哉，浮榮不償辱。", "回思五鼎烹，焉用萬鍾祿。", "朱紫蒙陷穽，簪笏如桎梏。", "勿爲觳觫牛，寧作擁腫木。", "君看白玉堂，未比黄茅屋。", "卧聽元戎報五更，何如日高三丈春睡熟。"]'),
('00a213d0-56a8-449c-a312-5928111d497c','晚泊江皋','蔡戡','宋','宋诗','song-poetry','','[]','日暮西江遠，停橈傍水村。',48,'全唐诗/poet.song.162000.json','["日暮西江遠，停橈傍水村。", "葉舟橫野渡，茅店掩柴門。", "牧笛隨風遠，漁燈带雨昏。", "一枝梅照水，行客總消魂。"]'),
('cd3db20f-9ec0-40fe-b2ab-3edac048f95f','送介卿之官金臺  其一','蔡戡','宋','宋诗','song-poetry','','[]','四海皆兄弟，情親能幾人。',48,'全唐诗/poet.song.162000.json','["四海皆兄弟，情親能幾人。", "相看青眼舊，總作白頭新。", "直道何妨拙，微官祇爲貧。", "老來仍惜別，把酒話酸辛。"]'),
('08e4d177-eead-421c-b899-f87d98b58630','送介卿之官金臺  其二','蔡戡','宋','宋诗','song-poetry','','[]','淵明去彭澤，斯立佐藍田。',48,'全唐诗/poet.song.162000.json','["淵明去彭澤，斯立佐藍田。", "家近真良便，官閒任左遷。", "相望雖百里，此別又三年。", "擬辦登山屐，從君訪洞天。"]'),
('78c9f08d-849a-47c6-8164-da0796921375','夢介卿感而有作  其一','蔡戡','宋','宋诗','song-poetry','','[]','湖海三年別，關山萬里程。',48,'全唐诗/poet.song.162000.json','["湖海三年別，關山萬里程。", "故人頻入夢，游子若爲情。", "家近吳王苑，身居義帝城。", "平生雞黍約，何日更尋盟。"]'),
('b2ca54cf-9024-41d2-92ba-59c29760b6fa','夢介卿感而有作  其二','蔡戡','宋','宋诗','song-poetry','','[]','憶昔兒童日，光陰急鳥飛。',48,'全唐诗/poet.song.162000.json','["憶昔兒童日，光陰急鳥飛。", "舊遊渾似夢，倦客只思歸。", "青眼還如昨，朱顔漸覺非。", "郴陽縱無雁，音問未應稀。"]'),
('d693e454-f477-4853-afd4-6bff1e33c8dc','孝宗皇帝靈駕發引詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','曆數承堯禪，謳歌戴舜仁。',48,'全唐诗/poet.song.162000.json','["曆數承堯禪，謳歌戴舜仁。", "規模自宏遠，法度謹持循。", "儉約身先下，憂勤志在民。", "萬方無以報，雨泣但霑巾。"]'),
('5adf88d3-ae47-47b9-8afc-920c40e8bd92','孝宗皇帝靈駕發引詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','舜禹相傳日，元非倦萬幾。',48,'全唐诗/poet.song.162000.json','["舜禹相傳日，元非倦萬幾。", "慈闈躬至養，別殿奉遺衣。", "易月心何忍，通喪禮不違。", "煌煌新廟號，萬古播音徽。"]'),
('138f9f0a-cfbd-4917-9e58-c818ef472924','巖仲八兄有苕溪之行草酌話別而次何叔養正十二兄爽約不至坐客唯三人因以詩紀之','蔡戡','宋','宋诗','song-poetry','','[]','自古推同姓，相從弟與兄。',48,'全唐诗/poet.song.162000.json','["自古推同姓，相從弟與兄。", "已占東井聚，誰謂泰階平。", "龍友當爲首，鵷行近有聲。", "同堅歲寒操，終始勿渝盟。"]'),
('1ce3eef9-a175-4466-a6b7-4ea273e74f80','即席和端約韻','蔡戡','宋','宋诗','song-poetry','','[]','竹溪追勝槩，得侶最爲多。',48,'全唐诗/poet.song.162000.json','["竹溪追勝槩，得侶最爲多。", "自覺功名懶，空嗟歲月磨。", "夢驚風落葉，心破雨鳴荷。", "無此杯中物，其如良夜何。"]'),
('a5109805-e811-459c-aec3-da0c86783d9a','舟行有感','蔡戡','宋','宋诗','song-poetry','','[]','仕路多艱棘，人生更轉篷。',48,'全唐诗/poet.song.162000.json','["仕路多艱棘，人生更轉篷。", "浮雲偏蔽日，駭浪不因風。", "世事愁眉外，人情醉眼中。", "老來齊得喪，方寸等虛空。"]'),
('8ec2a973-e444-48e7-b30c-f9cb405ac015','予頃歲持節湖湘今二十四年白首重來親舊十無二三感而有作','蔡戡','宋','宋诗','song-poetry','','[]','落日放扁舟，瀟湘生暮愁。',48,'全唐诗/poet.song.162000.json','["落日放扁舟，瀟湘生暮愁。", "故人疑不見，離思渺難收。", "鼓瑟空遺恨，吹簫憶舊游。", "劉郎今老矣，霜鬢不禁秋。"]'),
('98f4da12-95c4-4749-a02f-6516a8273ccd','秋日書懷  其一','蔡戡','宋','宋诗','song-poetry','','[]','遊宦輕千里，閒愁度一秋。',48,'全唐诗/poet.song.162000.json','["遊宦輕千里，閒愁度一秋。", "衰顔慵攬鏡，病足怯登樓。", "事業因循廢，功名取次休。", "人生聊復爾，一飽更何求。"]'),
('101a5506-a237-48e6-bb29-eb514bbc23a9','秋日書懷  其二','蔡戡','宋','宋诗','song-poetry','','[]','刻意搜詩句，清心玩易爻。',48,'全唐诗/poet.song.162000.json','["刻意搜詩句，清心玩易爻。", "几塵留鼠迹，窗影印梅梢。", "泉石頻招隠，壺觴已絕交。", "橫挑一楖栗，在處寄僧包。"]'),
('ad0aa94b-0f43-4206-b1a4-8d6f94305638','送九兄僉書歸二首  其一','蔡戡','宋','宋诗','song-poetry','','[]','離別一何久，漂流不記年。',48,'全唐诗/poet.song.162000.json','["離別一何久，漂流不記年。", "昔君猶壯歲，今我亦華鬋。", "隔闊疑如夢，從容喜欲顛。", "弟兄能有幾，及此對床眠。"]'),
('8db9810b-3c47-4d1f-a9f9-cd9a75dce92f','送九兄僉書歸二首  其二','蔡戡','宋','宋诗','song-poetry','','[]','中年仍再別，歸意苦難留。',48,'全唐诗/poet.song.162000.json','["中年仍再別，歸意苦難留。", "風雨傷心夜，江山滿目秋。", "西堂詩入夢，東閣酒添愁。", "他日荆溪上，無違具一舟。"]'),
('da40506c-228a-4adc-8aea-5167d9f463d1','先人嘗宰貴池今二十五年矣舟行經此不勝黯然','蔡戡','宋','宋诗','song-poetry','','[]','夜泊貴池口，此情殊黯然。',48,'全唐诗/poet.song.162000.json','["夜泊貴池口，此情殊黯然。", "思親空有泪，感舊不成眠。", "棠舍清陰在，桐鄉舊政傳。", "終天成永感，忍聽蓼莪篇。"]'),
('f3751caa-adce-472a-bf39-0734beda3cc1','至日書懷','蔡戡','宋','宋诗','song-poetry','','[]','病起逢佳節，羈懷只自傷。',48,'全唐诗/poet.song.162000.json','["病起逢佳節，羈懷只自傷。", "老來衰自至，身與世相忘。", "髮引千絲亂，愁添一綫長。", "功名真已矣，此意付滄浪。"]'),
('37b8d592-5ae8-468c-b477-79e4e3a88cd9','乙卯春病中書','蔡戡','宋','宋诗','song-poetry','','[]','老去那堪病，春來總自愁。',48,'全唐诗/poet.song.162000.json','["老去那堪病，春來總自愁。", "關心惟藥物，寄命向醫流。", "世事多翻覆，吾生任去留。", "一廛真可老，此外更何求。"]'),
('eb77d166-b8e5-4eb1-b62d-9a3bdf04cbbb','遣興  其一','蔡戡','宋','宋诗','song-poetry','','[]','世味只如許，人情亦可憐。',48,'全唐诗/poet.song.162000.json','["世味只如許，人情亦可憐。", "禪心甘寂寞，病體覺輕便。", "夢裏身非我，閒中日似年。", "還家真復樂，此去若登仙。"]'),
('45224699-2843-4ff4-bacc-f8ec82be8395','遣興  其二','蔡戡','宋','宋诗','song-poetry','','[]','醉裏乾坤大，閒中日月長。',48,'全唐诗/poet.song.162000.json','["醉裏乾坤大，閒中日月長。", "靜觀佛理妙，頓與世緣忘。", "晚景無多日，浮生有底忙。", "漁翁真得趣，一葉寄滄浪。"]'),
('75fff905-fc9b-4968-8a3b-66bf47de79a1','遣興  其三','蔡戡','宋','宋诗','song-poetry','','[]','江海倦遊客，乾坤老病身。',48,'全唐诗/poet.song.162000.json','["江海倦遊客，乾坤老病身。", "儻來皆外物，自在作閒人。", "睡足從吾懶，歡來任我真。", "治生且耕鑿，無愧葛天民。"]'),
('ea1874f2-71cb-4f8e-b388-371a2392a1e7','遣興  其四','蔡戡','宋','宋诗','song-poetry','','[]','衰病人應棄，窮愁孰與親。',48,'全唐诗/poet.song.162000.json','["衰病人應棄，窮愁孰與親。", "同行木上座，並卧竹夫人。", "習定調千息，談空外一身。", "轍環天下半，送老楚江濱。"]'),
('a875441d-ff32-46fe-bb81-108a5164575b','獨立','蔡戡','宋','宋诗','song-poetry','','[]','獨立寒江上，蕭然一禿翁。',48,'全唐诗/poet.song.162000.json','["獨立寒江上，蕭然一禿翁。", "夢魂驚雪浪，病骨怯霜風。", "遠樹斜陽外，荒村暮靄中。", "閒身無一事，樽酒與誰同。"]'),
('94f07a48-1c34-4daa-9b2c-d5d8b8a9272b','丐祠得請喜而有作示介卿  其一','蔡戡','宋','宋诗','song-poetry','','[]','多病身先懶，閒居樂有餘。',48,'全唐诗/poet.song.162000.json','["多病身先懶，閒居樂有餘。", "山林真可老，故事未應疎。", "性與禽魚適，身便水竹居。", "非無軒冕志，吾亦愛吾廬。"]'),
('d7c43775-8135-4531-bf50-98d2ae1440a8','丐祠得請喜而有作示介卿  其二','蔡戡','宋','宋诗','song-poetry','','[]','人心輕萬仞，吾志在兼山。',48,'全唐诗/poet.song.162000.json','["人心輕萬仞，吾志在兼山。", "知止今真止，求閒復得閒。", "天應念衰病，人免笑癡頑。", "二老風流在，何妨日往還。"]'),
('fb7a63ef-58d4-445f-80f5-a7a8df8a7232','丙辰罷郡得祠','蔡戡','宋','宋诗','song-poetry','','[]','世論可憐哉，無心任去來。',48,'全唐诗/poet.song.162000.json','["世論可憐哉，無心任去來。", "狙公徒自喜，鷗鳥浪相猜。", "塞馬寧非福，池魚枉見災。", "扁舟從此去，回首謝氛埃。"]'),
('be2769f4-fbeb-4ca7-a951-3c5b3d6c0d4e','水閣偶成二首  其一','蔡戡','宋','宋诗','song-poetry','','[]','小閣枕橫塘，荷花渡晚香。',48,'全唐诗/poet.song.162000.json','["小閣枕橫塘，荷花渡晚香。", "月華秋更白，水氣夜偏凉。", "地僻人稀到，心閒夢亦長。", "北窗聊寄傲，身世兩相忘。"]'),
('5dc71588-2af2-47bb-a714-5e91d3e94f85','水閣偶成二首  其二','蔡戡','宋','宋诗','song-poetry','','[]','徙倚危樓久，無言對夕暉。',48,'全唐诗/poet.song.162000.json','["徙倚危樓久，無言對夕暉。", "野花隨處發，水鳥傍人飛。", "自覺身無累，那知世有機。", "何勞戰蝸角，萬事轉頭非。"]'),
('a5450033-e97f-44d8-bf69-7ae4fc446a8e','書懷','蔡戡','宋','宋诗','song-poetry','','[]','消息觀天道，炎凉閲世情。',48,'全唐诗/poet.song.162000.json','["消息觀天道，炎凉閲世情。", "禪心了生死，病骨識陰晴。", "杜宇傷心切，梅花照眼清。", "焚香讀周易，頓覺此身輕。"]'),
('af688269-64a7-4fea-8181-4404d671282a','淳熙戊戌將命廣東侍親携孥十一月至安仁留雲錦驛一宿而去時晉卿姪偕行後二十三年分閫桂林晉卿主餘干簿復以是月來會于此把琖道舊爲之愴然因成一詩示晉卿','蔡戡','宋','宋诗','song-poetry','','[]','憶昨南遊日，今餘二十年。',48,'全唐诗/poet.song.162000.json','["憶昨南遊日，今餘二十年。", "扶輿潘母健，舉案孟光賢。", "遠宦徒勞耳，重來倍愴然。", "若非吾小阮，隻影更誰憐。"]'),
('c7ec5591-ad71-4016-9c75-a9bd664769c0','胡端約挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','一代風流盡，如公能幾人。',48,'全唐诗/poet.song.162000.json','["一代風流盡，如公能幾人。", "病來猶筆健，老去更詩新。", "握手言無間，傷心迹已陳。", "墨君時一玩，感慨淚霑巾。"]'),
('e48201c5-6742-4229-817c-d00e1a014d46','胡端約挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','長卿多酒病，子美太詩癯。',48,'全唐诗/poet.song.162000.json','["長卿多酒病，子美太詩癯。", "談笑隨時樂，風標絕代無。", "遺編應百卷，怪石漫千株。", "頼此青氈物，傳家有鳳雛。"]'),
('0a87e045-3f12-49a7-89fc-0b80e056453f','顔魯子挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','耆舊三朝望，廉平百吏師。',48,'全唐诗/poet.song.162000.json','["耆舊三朝望，廉平百吏師。", "愛民先節用，直道靡容私。", "自視一無愧，真成三不欺。", "遺民應罷市，淚墮峴山碑。"]'),
('3b11acba-df2b-456f-b326-cc832d351fff','顔魯子挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','昔年顔氏子，當代魯公孫。',48,'全唐诗/poet.song.162000.json','["昔年顔氏子，當代魯公孫。", "德行端能繼，典刑今尚存。", "平生窺聖閫，晚歲踏空門。", "歸即歸兜率，雲堂第幾尊。"]'),
('a175c0f4-6339-4ade-8433-0fbc082750c1','代趙儀可挽劉叔丙','蔡戡','宋','宋诗','song-poetry','','[]','此士不可得，鄉人今始思。',48,'全唐诗/poet.song.162000.json','["此士不可得，鄉人今始思。", "迎賓多事日，教子廢科時。", "望屋訟自止，弄丸爭者誰。", "京華携手處，憶著最傷悲。"]'),
('5c652fbb-8c9f-41c1-af0e-cb92ee63228e','王季立安撫挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','世襲樞庭貴，仍專帥府權。',48,'全唐诗/poet.song.162000.json','["世襲樞庭貴，仍專帥府權。", "公忠由性稟，清白自家傳。", "剖决神明速，安懷畏愛全。", "功名方迫逐，天不假長年。"]'),
('e038485f-8ffb-4a21-b7bc-ec83286247af','王季立安撫挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','相門叨下客，帥幕得佳賓。',48,'全唐诗/poet.song.162000.json','["相門叨下客，帥幕得佳賓。", "玉樹連階砌，芙蕖泛水濱。", "通家仍有契，論世豈無人。", "埋玉空遺恨，潸然淚滿襟。"]'),
('e75ba149-f41f-4ad1-b08d-f74328e6a7c7','康素居士邵君挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','當代求遺逸，斯人尚典刑。',48,'全唐诗/poet.song.162000.json','["當代求遺逸，斯人尚典刑。", "雲愁富春渚，月掩少微星。", "易簀無多語，空籯但一經。", "遺休宜有後，蘭玉滿階庭。"]'),
('0e9234d9-8f19-454e-97e0-a1ce50eba6fc','康素居士邵君挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','世儒多戶牖，家學自淵源。',48,'全唐诗/poet.song.162000.json','["世儒多戶牖，家學自淵源。", "處士名兼美，先王道益尊。", "黄金散閭里，白玉揜丘原。", "猿鶴空凄怨，清江遶故園。"]'),
('acd81665-d9df-4cf9-ba30-3de51396ff2c','提舉中奉程公挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','典午源流遠，安鄉世胄隆。',48,'全唐诗/poet.song.162000.json','["典午源流遠，安鄉世胄隆。", "廉平儒者政，樸素古人風。", "五福身兼備，三尊德最崇。", "善人無復見，忍看一旌紅。"]'),
('936b6607-1fab-4129-a125-2f779069c2ba','提舉中奉程公挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','靜退身無累，安閒意有餘。',48,'全唐诗/poet.song.162000.json','["靜退身無累，安閒意有餘。", "一麾真漫爾，三徑盍歸與。", "肯酌貪泉水，甘乘下澤車。", "後生知敬慕，遺行藹鄉閭。"]'),
('c9c2f3dc-207f-4122-9f50-6d4fe215024c','張有年提舉挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','天上張公子，家聲四海知。',48,'全唐诗/poet.song.162000.json','["天上張公子，家聲四海知。", "晚方持使節，聊復擁州麾。", "嶺嶠多遺愛，蕃人亦去思。", "遠民應罷市，泪墮峴山碑。"]'),
('35b3f710-fd6f-429b-bfe7-c3c16b1e0c5c','張有年提舉挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','挺出英雄後，居多長者稱。',48,'全唐诗/poet.song.162000.json','["挺出英雄後，居多長者稱。", "祖風知未泯，世德自相承。", "口不談臧否，人應寡怨憎。", "善人宜有後，衮衮看鶱騰。"]'),
('f227c93a-8db9-4540-9d53-89b815f0b4dc','丁收仲寺丞挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','元祐名卿後，甘盤舊學臣。',48,'全唐诗/poet.song.162000.json','["元祐名卿後，甘盤舊學臣。", "肯堂真有子，論世豈無人。", "仕至二千石，年垂八十春。", "哀榮子毋憾，全福更誰倫。"]'),
('e2923f8f-f4e3-4f24-be81-837160b38a9c','丁收仲寺丞挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','耆舊凋零盡，吾猶及此公。',48,'全唐诗/poet.song.162000.json','["耆舊凋零盡，吾猶及此公。", "典刑前輩近，氣概古人同。", "抵掌談如在，掀髯笑已空。", "堂堂寧復見，蕭瑟九原中。"]'),
('43609050-88ab-4794-a975-c80bad3f6240','丁收仲寺丞挽詩  其三','蔡戡','宋','宋诗','song-poetry','','[]','華屋平生處，傷心事已非。',48,'全唐诗/poet.song.162000.json','["華屋平生處，傷心事已非。", "綵衣方共樂，寶劍忽雙飛。", "漫說乘鸞去，終期化鶴歸。", "長年知有淚，感慨一沾衣。"]'),
('c733b14d-7d63-430f-998d-35165c718185','沈朝議之淵挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','早擅雲間譽，唯公伯仲賢。',48,'全唐诗/poet.song.162000.json','["早擅雲間譽，唯公伯仲賢。", "諫篇餘祖烈，經學自家傳。", "出處無餘恨，哀榮得兩全。", "善人今已矣，埋玉向新阡。"]'),
('3a95c9ef-13ef-4b00-94c9-79fff9ac9c65','沈朝議之淵挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','仕至二千石，年餘七十秋。',48,'全唐诗/poet.song.162000.json','["仕至二千石，年餘七十秋。", "長生應有訣，勇退復何求。", "耆舊凋零盡，功名取次休。", "莫陪蒿里餞，東望隴雲愁。"]'),
('c85904cb-baec-41c6-8277-d44ce5af8388','故廬陵府君葛公挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','家風惟孝友，世系本神僊。',48,'全唐诗/poet.song.162000.json','["家風惟孝友，世系本神僊。", "丹藥能延壽，衣冠不乏賢。", "享齡餘七十，積行滿三千。", "存歿無遺恨，青氈有子傳。"]'),
('ec95929c-d194-4c7f-8f43-72ae2393b57c','故廬陵府君葛公挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','耆舊如公少，明時豈棄材。',48,'全唐诗/poet.song.162000.json','["耆舊如公少，明時豈棄材。", "一麾聊出守，三徑即歸來。", "白璧人何在，黄粱夢已回。", "秋風正摇落，楚挽不勝哀。"]'),
('bc68d0b8-5fcd-4ebb-b498-dd31bb231013','張晉英侍郎挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','當代推耆舊，如公能幾人。',48,'全唐诗/poet.song.162000.json','["當代推耆舊，如公能幾人。", "典刑唐閣老，風采漢廷臣。", "直筆書青史，巍冠侍紫宸。", "壺公非不遇，猶未究經綸。"]'),
('14cc2217-dd78-490f-bb32-0f346032bb28','張晉英侍郎挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','賈傅年方少，詞場屢策勳。',48,'全唐诗/poet.song.162000.json','["賈傅年方少，詞場屢策勳。", "賢關馳雋譽，仕路藹清芬。", "德望三朝重，聲名四海聞。", "僊遊向何許，地下亦修文。"]'),
('a43f7a21-8480-45d5-9b86-c2455775cb34','韓子溫母秦國太夫人挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','際會中興日，來歸異姓王。',48,'全唐诗/poet.song.162000.json','["際會中興日，來歸異姓王。", "艱危從戰陳，淑謹自閨房。", "眼看兒孫盛，身膺福壽長。", "平生修凈業，一念即西方。"]'),
('47155a78-bd65-4b27-b6be-ab3dd1ce08fe','韓子溫母秦國太夫人挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','八座太夫人，疏封大國秦。',48,'全唐诗/poet.song.162000.json','["八座太夫人，疏封大國秦。", "酇侯仍有子，陶母不憂貧。", "四紀恩光渥，三朝錫賚頻。", "哀榮極終始，當代更誰倫。"]'),
('3751d391-dafb-4462-af02-b253ba69f27e','齊子餘母太夫人王氏挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','江左推門地，華陽接洞天。',48,'全唐诗/poet.song.162000.json','["江左推門地，華陽接洞天。", "嬪夫成宅相，教子作時賢。", "富貴三從備，哀榮五福全。", "平生勤事佛，兜率是良緣。"]'),
('1c112754-d336-4951-9142-b605ccca1f3a','齊子餘母太夫人王氏挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','向來小宗伯，日侍太夫人。',48,'全唐诗/poet.song.162000.json','["向來小宗伯，日侍太夫人。", "地占梁溪勝，風流峴首春。", "版輿隨處樂，綵服逐時新。", "欻斷萱堂夢，居然迹已陳。"]'),
('23175c8f-66ce-4d0d-82cd-b73977015db4','齊子餘母太夫人王氏挽詩  其三','蔡戡','宋','宋诗','song-poetry','','[]','石窌恩雖渥，蘭陔事已非。',48,'全唐诗/poet.song.162000.json','["石窌恩雖渥，蘭陔事已非。", "升堂人不見，執紼淚頻揮。", "樹競晚風急，草明朝露晞。", "他年黄閤宴，不及奉慈闈。"]'),
('f349160f-fadb-42c1-b38b-31896a5fe505','趙從善母吉國夫人劉氏挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','鍾英推后族，擇配得王孫。',48,'全唐诗/poet.song.162000.json','["鍾英推后族，擇配得王孫。", "兩大夫仍貴，三從母益尊。", "版輿欣就養，鈿軸屢承恩。", "尚想平反日，慈顔一笑溫。"]'),
('ec88ca18-4444-488b-a5c8-f51fdd7577d4','趙從善母吉國夫人劉氏挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','令子方通顯，神京更浩穰。',48,'全唐诗/poet.song.162000.json','["令子方通顯，神京更浩穰。", "珍羞供鼎食，綵服賁金章。", "大國初封吉，佳城忽葬防。", "貳卿哀慕切，老淚浥千行。"]'),
('f0a2f910-9f4b-4d42-844b-2f1412d51a7f','劉公實母夫人董氏挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','杏圃僊遊遠，桃源往事虧。',48,'全唐诗/poet.song.162000.json','["杏圃僊遊遠，桃源往事虧。", "名高孝婦傳，詞掞外孫碑。", "孟鼎方知貴，萊衣不復嬉。", "生男有如此，天道豈無知。"]'),
('0c514b65-e78b-413e-b9a2-1422786395e4','劉公實母夫人董氏挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','列寺名卿重，慈闈壽母尊。',48,'全唐诗/poet.song.162000.json','["列寺名卿重，慈闈壽母尊。", "眼中看五世，膝下擁重孫。", "九九登遐算，三三達妙門。", "哀榮極終始，全福更何言。"]'),
('b60deaa0-e8c1-4a22-8c61-7562622259ee','感事','蔡戡','宋','宋诗','song-poetry','','[]','親舊頻凋喪，于今能幾人。',72,'全唐诗/poet.song.162000.json','["親舊頻凋喪，于今能幾人。", "光陰雙轉轂，富貴一微塵。", "自歎癡頑老，人憐衰病身。", "直饒心似鐵，未免鬢如銀。", "安樂能延壽，憂勞漫損神。", "平生齊得喪，六十六年春。"]'),
('514683be-f9f3-4397-8f5c-34459a508179','送張子儀尚書起鎮東陽','蔡戡','宋','宋诗','song-poetry','','[]','自古雙溪山水鄉，風流仍繼沈東陽。',64,'全唐诗/poet.song.162000.json','["自古雙溪山水鄉，風流仍繼沈東陽。", "禁庭久曳尚書履，輔郡方懷太守章。", "再世甘棠留勿翦，百年喬木鬰相望。", "公家况有青氈在，會見登庸坐廟堂。"]'),
('c304ea24-b75f-41dc-a05a-88b8171323ee','送蔣子立赴河南試  其一','蔡戡','宋','宋诗','song-poetry','','[]','槐花拂拂弄輕黄，白紵雲趨翰墨場。',64,'全唐诗/poet.song.162000.json','["槐花拂拂弄輕黄，白紵雲趨翰墨場。", "魯國儒冠能有幾，長沙舞袖頗相妨。", "英材自是千人敵，小試猶爭一日長。", "來歲皇都春色好，馬蹄應带百花香。"]'),
('904d99ea-9221-4f48-9907-bf7dab60af64','送蔣子立赴河南試  其二','蔡戡','宋','宋诗','song-poetry','','[]','平生天上張公子，一旦翻從地下游。',64,'全唐诗/poet.song.162000.json','["平生天上張公子，一旦翻從地下游。", "不特文章傳籍湜，定知禮樂付程仇。", "高山流水無真賞，白璧明珠勿暗投。", "他日大廷承顧問，好將忠讜薦宸旒。"]'),
('aabe84c5-95a7-4865-9f75-9a0fb1d9f429','觀雪  其一','蔡戡','宋','宋诗','song-poetry','','[]','天公一笑喜生春，坐見丘原物物新。',64,'全唐诗/poet.song.162000.json','["天公一笑喜生春，坐見丘原物物新。", "素色連空迷俯仰，寒光借月作精神。", "千金子宴無虛日，萬玉妃來不動塵。", "斗米如珠薪比桂，可憐擾擾雪中人。"]'),
('42e5d038-add5-4b41-a22d-f84db0124523','觀雪  其二','蔡戡','宋','宋诗','song-poetry','','[]','乾坤浩蕩渺無涯，龍鳳縱橫落萬家。',64,'全唐诗/poet.song.162000.json','["乾坤浩蕩渺無涯，龍鳳縱橫落萬家。", "似與宓妃矜態度，未應姑射並容華。", "排簷巧綴纖纖玉，著樹齊開種種花。", "料得瓊瑶天不惜，等閒狼籍委泥沙。"]'),
('fa396fa9-5281-4dab-a764-fa91751318e0','用前韻  其一','蔡戡','宋','宋诗','song-poetry','','[]','裁霜翦水戲成春，瓊蕊瑶華巧鬭新。',64,'全唐诗/poet.song.162000.json','["裁霜翦水戲成春，瓊蕊瑶華巧鬭新。", "馿帽清寒詩得助，漁簑幽絕畫通神。", "峰巒幻出千尋玉，宇宙空無一點塵。", "我欲乘風入閶闔，不知飛珮更何人。"]'),
('0fa4fc43-cae6-4234-b76e-958916b48b92','用前韻  其二','蔡戡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江梅欺壓任橫斜，愁殺西湖處士家。',64,'全唐诗/poet.song.162000.json','["江梅欺壓任橫斜，愁殺西湖處士家。", "頼有凍醪供熟醉，斷無傑句寫芳華。", "玉樓不夜家家月，瓊樹先春處處花。", "想見寒江最奇絕，扁舟簑笠釣雲沙。"]'),
('148a9c84-11b0-4539-9987-789bf06a844a','再用前韻  其一','蔡戡','宋','宋诗','song-poetry','','[]','東君作意欲先春，故放千林火速新。',64,'全唐诗/poet.song.162000.json','["東君作意欲先春，故放千林火速新。", "風急亂飄初眩眼，地空遠望忽迷神。", "簷楹不動垂冰柱，庭戶無聲糝玉塵。", "留取寒光待元夕，一時燈月付遊人。"]'),
('af3597fb-bbda-4f4c-9a08-952e4a23c758','再用前韻  其二','蔡戡','宋','宋诗','song-poetry','','[]','不用扁舟尋故友，但穿敗履訪鄰家。',64,'全唐诗/poet.song.162000.json','["不用扁舟尋故友，但穿敗履訪鄰家。", "雪堂歸去東坡老，雲馭飛來萼綠華。", "稚子歡呼驚柳絮，佳人疑悞認梅花。", "出門天地俱無礙，却意江空月在沙。"]'),
('af236655-f1f0-4421-8a1b-7bad5558f7eb','雪中端約相招因以詩簡之','蔡戡','宋','宋诗','song-poetry','','[]','纖纖暮雨變飛霙，夜聽敲窗瀉竹聲。',64,'全唐诗/poet.song.162000.json','["纖纖暮雨變飛霙，夜聽敲窗瀉竹聲。", "柳絮因風誠可擬，梅花带月有餘清。", "梁園公子方開宴，姑射神人最賦情。", "可笑寒儒無秀句，一詩聊欲問前盟。"]'),
('16693beb-7da7-4e1b-9ccb-b5e5caf544ec','易地湖外喜而有作','蔡戡','宋','宋诗','song-poetry','','[]','平生何意作南遊，直爲饑驅不自由。',64,'全唐诗/poet.song.162000.json','["平生何意作南遊，直爲饑驅不自由。", "天外飛鳶驚昨夢，峰前回雁喚離愁。", "再賡漢節君恩重，一笑潘輿喜氣浮。", "慚愧向來三百指，團欒歸去更何求。"]'),
('e1eda76c-20c0-43ce-aef4-1f3ba0b2509f','爲趙氏題三桂堂','蔡戡','宋','宋诗','song-poetry','','[]','千佛聯名未足多，書生榮遇已如何。',64,'全唐诗/poet.song.162000.json','["千佛聯名未足多，書生榮遇已如何。", "鍾英况出神明胄，接武仍登甲乙科。", "郗氏一枝猶可貴，燕山五桂未能過。", "矧君四世推良吏，信史垂芳永不磨。"]'),
('c986467e-4291-4fba-aae9-d363881619a4','觀雪','蔡戡','宋','宋诗','song-poetry','','[]','卧聽跳珠落瓦溝，曉來飛雪凍雲稠。',64,'全唐诗/poet.song.162000.json','["卧聽跳珠落瓦溝，曉來飛雪凍雲稠。", "晃觀佛國三千界，幻出僊家十二樓。", "公子休誇梁苑宴，高人空泛剡溪舟。", "何如縛取吳元濟，夜半銜枚入蔡州。"]'),
('592c3e85-590d-439d-b3f0-725ceab0f9a3','再用觀雪韻','蔡戡','宋','宋诗','song-poetry','','[]','幽居窮僻傍邗溝，晚歲天寒雪意稠。',64,'全唐诗/poet.song.162000.json','["幽居窮僻傍邗溝，晚歲天寒雪意稠。", "高卧但知深閉戶，縱觀何敢共登樓。", "寒驚遠塞孤飛雁，重壓清江獨釣舟。", "遥想千官馳入賀，葱葱和氣滿皇州。"]'),
('799d9073-4b03-4f91-aab8-0786d7d17bdc','憶故園梅花','蔡戡','宋','宋诗','song-poetry','','[]','遥憶家山千樹梅，幾年心力費栽培。',64,'全唐诗/poet.song.162000.json','["遥憶家山千樹梅，幾年心力費栽培。", "雪中最喜登樓望，月下偏宜傍水開。", "東閣自憐詩興懶，平泉不見信音來。", "主人行矣休官去，怨鶴驚猿勿浪猜。"]'),
('7017397b-0859-4e28-b488-57c42df7f993','鴈蕩','蔡戡','宋','宋诗','song-poetry','','[]','又持一節向東州，自怪平生欠此遊。',64,'全唐诗/poet.song.162000.json','["又持一節向東州，自怪平生欠此遊。", "勝地百年開鴈蕩，漏天千古瀉龍湫。", "雲生半岫輕隨足，泉落空巖急打頭。", "却恨昔賢無轍迹，謝公嶺上更遲留。"]'),
('66df1868-1152-4771-8ac8-28b901b53057','道中述懷','蔡戡','宋','宋诗','song-poetry','','[]','分閫南來兩見秋，不才多病合歸休。',64,'全唐诗/poet.song.162000.json','["分閫南來兩見秋，不才多病合歸休。", "奔馳水陸三千里，經歷江湖十四洲。", "鱸鱠蓴絲懷古里，梅花雪片送行舟。", "自慚尸素終無補，只爲憂邊白盡頭。"]'),
('0212ec11-de9e-4414-b57e-d7a8aa42abee','送胡季玉還毗陵','蔡戡','宋','宋诗','song-poetry','','[]','瘴雨蠻烟晝不開，問君底事亦南來。',64,'全唐诗/poet.song.162000.json','["瘴雨蠻烟晝不開，問君底事亦南來。", "外臺總計慙無術，內府輸珍信有才。", "我去鴈峰同北鄉，子行梅嶺带春回。", "故園花竹平安否，何日從容共一杯。"]'),
('f8dd2a36-7c6c-42bb-b05b-e8d843d54ca1','元夕出遊','蔡戡','宋','宋诗','song-poetry','','[]','九衢燈火萬家春，嶺外風光自可人。',64,'全唐诗/poet.song.162000.json','["九衢燈火萬家春，嶺外風光自可人。", "剩喜豐登好時節，會須打撲困精神。", "嬉遊要屬風流帥，衰懶何堪老病身。", "勉意追陪非得已，由來憂樂本吾民。"]'),
('84e8bb15-c221-4488-8344-accabc5df14e','思歸  其一','蔡戡','宋','宋诗','song-poetry','','[]','世事端如一局碁，光陰還若擲梭飛。',64,'全唐诗/poet.song.162000.json','["世事端如一局碁，光陰還若擲梭飛。", "亡弓休問人得失，佩劍那知孰是非。", "每對西山看不厭，何當南浦送將歸。", "不如從此扁舟去，江上秋高蟹正肥。"]'),
('f70f1a58-503e-42e5-9ee9-25d01e1d26af','思歸  其二','蔡戡','宋','宋诗','song-poetry','','[]','久留瘴嶺苦思歸，安得身如越鳥飛。',64,'全唐诗/poet.song.162000.json','["久留瘴嶺苦思歸，安得身如越鳥飛。", "老去宦情真是薄，年來樂事覺全稀。", "衰顔得酒還如少，病骨添衣却似肥。", "只爲蓴鱸動歸思，非關勇退早知幾。"]'),
('759be385-fc5f-4290-932a-01c095d6bf45','登榕溪閣','蔡戡','宋','宋诗','song-poetry','','[]','公餘贏得暫時休，歸騎匆匆更少留。',64,'全唐诗/poet.song.162000.json','["公餘贏得暫時休，歸騎匆匆更少留。", "古木千章環美蔭，危亭百尺枕清流。", "詩翁僊去留遺跡，病守重來訪昔遊。", "坐久西山銜落照，一行鷗鷺起汀洲。"]'),
('59d0bb61-e767-4e2b-823b-77aa31db68b6','陪憲使登榕溪閣','蔡戡','宋','宋诗','song-poetry','','[]','歸途重約使軺臨，爲愛榕溪十畝陰。',64,'全唐诗/poet.song.162000.json','["歸途重約使軺臨，爲愛榕溪十畝陰。", "俯瞰江流青一带，坐看山色碧千尋。", "共拚沉醉酬佳節，暫駐斜暉縱賞心。", "因念玉關人已老，不堪摇落又秋深。"]'),
('e61e5928-357e-42db-98a4-a61f697dfbf8','用前韻成二首一以謝憲使和章一以述懷  其一','蔡戡','宋','宋诗','song-poetry','','[]','五嶺何煩漢節臨，暫來南國種棠陰。',64,'全唐诗/poet.song.162000.json','["五嶺何煩漢節臨，暫來南國種棠陰。", "詩親老杜真無敵，迹訪涪翁尚可尋。", "登覽漫窮千里目，衰遲唯有五湖心。", "江山彈壓歸詩伯，詩賦梅花雪片深。"]'),
('13c046da-b1b5-4dc6-bf69-8da47d0158b2','用前韻成二首一以謝憲使和章一以述懷  其二','蔡戡','宋','宋诗','song-poetry','','[]','老去重陽又再臨，等閒駒隙度光陰。',64,'全唐诗/poet.song.162000.json','["老去重陽又再臨，等閒駒隙度光陰。", "虛名何苦勞方寸，直道焉能枉尺尋。", "夜雨梧桐驚客夢，秋風鱸鱠動歸心。", "詔恩若許休官去，笑指山林遠更深。"]'),
('6bca1de3-91cf-48bc-bec3-b957537b88fc','再用前韻','蔡戡','宋','宋诗','song-poetry','','[]','當代名流共一臨，勝游應不減山陰。',64,'全唐诗/poet.song.162000.json','["當代名流共一臨，勝游應不減山陰。", "寸莛詎可撞千石，短綆徒勞汲百尋。", "松竹要堅三友操，金蘭默契二人心。", "時平歲稔文書省，緩引清觴莫厭深。"]'),
('17826133-564a-443e-80c3-fadfe6e0a2c4','丁未立春日讀白樂天浩歌行不覺身年四十七之句時方悼亡有感而作','蔡戡','宋','宋诗','song-poetry','','[]','不覺身年四十七，此身雖在鬢如霜。',64,'全唐诗/poet.song.162000.json','["不覺身年四十七，此身雖在鬢如霜。", "平生意氣空摧索，老去功名付渺茫。", "愁裏不知佳節至，尊前那復少年狂。", "梅花紙帳焚香坐，感舊傷懷淚兩行。"]'),
('9702ba5d-385c-48c7-acbb-c91b062ecf35','芍藥','蔡戡','宋','宋诗','song-poetry','','[]','自古維揚厥草夭，露紅煙紫不勝嬌。',64,'全唐诗/poet.song.162000.json','["自古維揚厥草夭，露紅煙紫不勝嬌。", "鄭風已久名溱洧，洛品猶堪壓魏姚。", "痛飲莫辭金鑿落，清標偏愛玉逍遥。", "楚狂小子嗟多病，坐對珍叢不自聊。"]'),
('75833a7c-8ead-4080-9b03-4b83442f6b89','過鄱陽湖適遇便風湖面如鏡喜而有作','蔡戡','宋','宋诗','song-poetry','','[]','多謝江神不世情，爲憐逐客送歸程。',64,'全唐诗/poet.song.162000.json','["多謝江神不世情，爲憐逐客送歸程。", "一帆風力如飛疾，千里湖光似掌平。", "要是吾生仗忠信，自然此意格神明。", "反思宦路風波惡，屢觸危機夢亦驚。"]'),
('9cfa9ef5-d419-4cf3-b5e2-f5bcba1da9bd','十月十六日發南昌下半月過建康便風順流日行二百里舟人云未有如此速者','蔡戡','宋','宋诗','song-poetry','','[]','鍾陵一水下金陵，輕舸何勞半月程。',64,'全唐诗/poet.song.162000.json','["鍾陵一水下金陵，輕舸何勞半月程。", "千里快風衝雪浪，一天寒日弄霜晴。", "天公有意如相念，川后安流自不驚。", "料得還家時節近，買羊沽酒互逢迎。"]'),
('53533744-96b3-4150-8d9f-568fe6f45751','南昌大閲','蔡戡','宋','宋诗','song-poetry','','[]','自昔洪都地望雄，劍光直與斗牛通。',64,'全唐诗/poet.song.162000.json','["自昔洪都地望雄，劍光直與斗牛通。", "角聲悲壯秋風裏，旗影橫斜晚照中。", "簾幕萬家觀小隊，弓刀千騎擁元戎。", "此身雖老心猶壯，自笑憑鞍矍鑠翁。"]'),
('12827f19-626a-4d15-ad4a-3a633497cf45','滕王閣','蔡戡','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','傑閣崢嶸枕古城，公餘扶病一登臨。',64,'全唐诗/poet.song.162000.json','["傑閣崢嶸枕古城，公餘扶病一登臨。", "西山拄笏增詩興，南浦飛帆動客心。", "白鳥去邊迎落日，青林斷處認遥岑。", "摩挲石刻空三嘆，吏部文章絕古今。"]'),
('a3ad08ad-3024-4a22-832a-6bdc3f853ffe','至日書懷','蔡戡','宋','宋诗','song-poetry','','[]','自笑癡兒得許忙，閉門便覺日舒長。',64,'全唐诗/poet.song.162000.json','["自笑癡兒得許忙，閉門便覺日舒長。", "作詩擬學江西派，起疾多求海上方。", "老去光陰空嘆息，病逢時節轉凄凉。", "可憐隻影無聊頼，兒女三人各一方。"]'),
('e24fa337-bc76-4dab-8e33-c0148e16e313','詠雪和介卿韻','蔡戡','宋','宋诗','song-poetry','','[]','詩翁咳唾自成珠，畫筆新傳粉墨圖。',64,'全唐诗/poet.song.162000.json','["詩翁咳唾自成珠，畫筆新傳粉墨圖。", "大白賡酬金瀲灧，小紅團坐錦糢糊。", "縱觀佛界成銀色，疑入僊家醉玉壺。", "應笑陰何用心苦，愁吟終夜撥寒爐。"]'),
('b3c29c56-fbec-496d-93b2-beef54d174d6','再和前韻','蔡戡','宋','宋诗','song-poetry','','[]','郢客清歌若貫珠，迴風妙舞巧難圖。',64,'全唐诗/poet.song.162000.json','["郢客清歌若貫珠，迴風妙舞巧難圖。", "漫空片片勻如翦，投隙紛紛密似糊。", "溪月一鈎窺玉鏡，江梅千樹插冰壺。", "何人乞我僊家帽，共傲禪床與藥爐。"]'),
('d35c3991-3dea-4f0f-ab19-5dce49dd298b','浙東憲司會同年八人以詩記之','蔡戡','宋','宋诗','song-poetry','','[]','乾道龍飛二紀前，一時再會八同年。',64,'全唐诗/poet.song.162000.json','["乾道龍飛二紀前，一時再會八同年。", "諸公誰念廣文冷，三已方知令尹賢。", "別乘達尊人共敬，軺車並駕我叨先。", "蘭亭又見羣賢集，盛事宜將琬琰鎸。"]'),
('ada2c3e2-6f72-4f5e-8b0d-7c27488ae101','重九日陪諸公遊花田  其一','蔡戡','宋','宋诗','song-poetry','','[]','天遣奇花擇地生，爲憐體素更輕盈。',64,'全唐诗/poet.song.162000.json','["天遣奇花擇地生，爲憐體素更輕盈。", "一天秋色風光好，十頃寒香露氣清。", "不特爐熏資賸馥，最宜寶髻綴繁英。", "憑誰移向瓊林去，乞與江梅作弟兄。"]'),
('c94ae7b9-7ef3-489e-b838-d2d8eedfe98a','重九日陪諸公遊花田  其二','蔡戡','宋','宋诗','song-poetry','','[]','此花亦是可憐生，刻玉融酥萬數盈。',64,'全唐诗/poet.song.162000.json','["此花亦是可憐生，刻玉融酥萬數盈。", "素質更兼秋色靜，幽香暗逐曉風清。", "不須籬菊浮纖蕊，好學官梅綴落英。", "來歲龍山高會在，又呼張丈喚殷兄。"]'),
('2966c833-a27c-41d4-a1d3-a4979bb2a83a','重九日陪諸公遊花田  其三','蔡戡','宋','宋诗','song-poetry','','[]','作意登臨快此生，愛花莫惜酒杯盈。',64,'全唐诗/poet.song.162000.json','["作意登臨快此生，愛花莫惜酒杯盈。", "水沉風味香仍遠，冰雪肌膚韻更清。", "名字不須聯十友，品題猶頼有三英。", "定知茉莉真瓜葛，連璧誰家弟與兄。"]'),
('2a5f151c-7420-4c2d-b64e-02b7c7400200','重九日陪諸公遊花田  其四','蔡戡','宋','宋诗','song-poetry','','[]','瑞叶嘉禾亦旅生，瓊田十頃足豐盈。',64,'全唐诗/poet.song.162000.json','["瑞叶嘉禾亦旅生，瓊田十頃足豐盈。", "色侵粉面人爭羨，香入奇熏心自清。", "寶蓋緝成雙縞带，筠籠采盡萬瓊英。", "若逢靖節爲佳妃，肯讓黄花作女兄。"]'),
('291c3acc-6f8a-4a5a-a4ad-389dfb8e4cb2','再成二詩錄呈諸公  其一','蔡戡','宋','宋诗','song-poetry','','[]','漸老尋花學後生，瓊玫折得我懷盈。',64,'全唐诗/poet.song.162000.json','["漸老尋花學後生，瓊玫折得我懷盈。", "纖枝瘦葉還相稱，道骨僊風得許清。", "懶共山礬對春色，攙先籬菊薦秋英。", "由來玉樹階庭秀，不減風流謝氏兄。"]'),
('4fe9264b-ee75-4fea-ab2f-913290c48950','再成二詩錄呈諸公  其二','蔡戡','宋','宋诗','song-poetry','','[]','爲嫌桃李太麤生，晚殿羣芳不自盈。',64,'全唐诗/poet.song.162000.json','["爲嫌桃李太麤生，晚殿羣芳不自盈。", "冷艷坐消三伏暑，高標獨占九秋清。", "簪花擬欲酬佳節，落帽從教笑衆英。", "最有詩翁被花惱，從今喚作友于兄。"]'),
('7f53ccf2-e337-4dad-89f7-5558655476fe','再用韻呈薛士昭提舉','蔡戡','宋','宋诗','song-poetry','','[]','天公作戲爲誰生，不數芳蘭九畹盈。',64,'全唐诗/poet.song.162000.json','["天公作戲爲誰生，不數芳蘭九畹盈。", "美景良辰無限好，奇花妙句有餘清。", "一枝瀟灑閨中秀，百卉紛華糞上英。", "聞道河東有三鳳，詩名還是屬難兄。"]'),
('3669d336-7c05-4994-8936-908cc97ead59','撥置吏牘再作一詩以酬相惱之什','蔡戡','宋','宋诗','song-poetry','','[]','朝來衙集事還生，不覺文書几上盈。',64,'全唐诗/poet.song.162000.json','["朝來衙集事還生，不覺文書几上盈。", "顧我塵埃敗佳思，羨君心迹得雙清。", "也知靜色撩詩興，無奈蕪辭愧俊英。", "得句已推三昧手，論交當拜十年兄。"]'),
('9f0c58e5-2565-4557-98c0-d0a51d55cca7','偶得兄字再成一詩','蔡戡','宋','宋诗','song-poetry','','[]','年來習氣尚書生，喜得珠璣篋笥盈。',64,'全唐诗/poet.song.162000.json','["年來習氣尚書生，喜得珠璣篋笥盈。", "不羨奇葩爭嫵媚，且看麗藻鬭新清。", "禪心欲向花前定，佳句難酬座上英。", "知是詩人故相惱，只愁無處問家兄。"]'),
('5bf57bd1-f817-4f86-a731-cfa1bc2a0e97','再用前韻  其一','蔡戡','宋','宋诗','song-poetry','','[]','秋著寒花取次生，千叢向曉露珠盈。',64,'全唐诗/poet.song.162000.json','["秋著寒花取次生，千叢向曉露珠盈。", "根靈不止芝房秀，香遠仍分桂子清。", "弄雪飄颻疑玉女，迎風綽約認瑶英。", "品題自是推詞伯，誰道詩中只庶兄。"]'),
('f0b47b83-93c7-4fbb-9565-0a26b5b6f22c','再用前韻  其二','蔡戡','宋','宋诗','song-poetry','','[]','梅花料得是前生，楚些招魂魄已盈。',64,'全唐诗/poet.song.162000.json','["梅花料得是前生，楚些招魂魄已盈。", "却笑橫枝太消瘦，不堪淡月助凄清。", "風流有客傳花譜，火速無人集韻英。", "江左詩僧渾壓倒，每慚得句犯師兄。"]'),
('3d75f97f-0b34-4900-b9fc-a792fe47751b','用前韻簡趙薛二丈  其一','蔡戡','宋','宋诗','song-poetry','','[]','誰遣閒愁百種生，消除惟有酒尊盈。',64,'全唐诗/poet.song.162000.json','["誰遣閒愁百種生，消除惟有酒尊盈。", "自知老去風流盡，暫得官閒氣味清。", "香閣寂寥謾隣女，羅幃調護想宗英。", "二君此舉宜先罰，大白先浮伯雅兄。"]'),
('b53aead4-7c1e-432b-a9f3-70f6961df6f6','用前韻簡趙薛二丈  其二','蔡戡','宋','宋诗','song-poetry','','[]','滿目凄凉秋思生，寒香萬本綠疇盈。',64,'全唐诗/poet.song.162000.json','["滿目凄凉秋思生，寒香萬本綠疇盈。", "風回蘭蕙由來遠，露浥薔薇分外清。", "取次梳妝呈素面，等閒流落惜芳英。", "鳳樓大手須公等，好把蠻箋寄老兄。"]'),
('0dd944f0-b736-4783-afae-30ea784357eb','用前韻簡趙薛二丈  其三','蔡戡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','瓜時正值一陽生，已見眉間喜氣盈。',64,'全唐诗/poet.song.162000.json','["瓜時正值一陽生，已見眉間喜氣盈。", "詔下鰲頭恩數寵，香含雞舌省曹清。", "西湖好去窮清賞，南國無從戀蕣英。", "自此達尊兼德爵，不唯年事合推兄。"]'),
('c22a254b-5f29-4833-8bed-5dba806219ff','遊歸來園追想主人高風恨不及見因賦二詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','相門戚畹昔無鄰，令代衣冠不乏人。',64,'全唐诗/poet.song.162000.json','["相門戚畹昔無鄰，令代衣冠不乏人。", "怪底山林成獨往，從渠鐘鼎漫橫陳。", "居官政自風流在，教子空餘翰墨新。", "蕙帳寂寥人不見，幾多花鳥怨青春。"]'),
('bff50aa0-e71a-4e6d-8383-37daaf3c8bb9','遊歸來園追想主人高風恨不及見因賦二詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','幾年奔走困塵埃，愧仰高風得得來。',64,'全唐诗/poet.song.162000.json','["幾年奔走困塵埃，愧仰高風得得來。", "喬木參天應手種，好花夾路爲誰開。", "芳辰不惜終朝醉，晚色何堪惡雨催。", "極目青林無限意，歸鞍欲去更徘徊。"]'),
('336a99ff-9604-4f75-8159-82575c5b5571','歲暮有感','蔡戡','宋','宋诗','song-poetry','','[]','久困京塵厭劇煩，一麾江海養衰殘。',64,'全唐诗/poet.song.162000.json','["久困京塵厭劇煩，一麾江海養衰殘。", "簿書叢裏身空老，鼓角聲中歲又闌。", "贏得星星雙鬢白，空餘耿耿寸心丹。", "自憐憔悴今如許，盍向明時早掛冠。"]'),
('4f536472-29d5-4c6f-b01e-9446320c6bf3','同顧廣文遊西湖','蔡戡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老來多病盍歸休，祇爲江山得少留。',64,'全唐诗/poet.song.162000.json','["老來多病盍歸休，祇爲江山得少留。", "萬頃澄波環勝境，千峰倒影漾中流。", "十年兩作西湖長，一日同爲北牖遊。", "預約他時官事了，與君重醉百花洲。"]'),
('b82bfd40-e7fe-4f44-a8b4-be6ec40fc0d7','登岸山觀用前韻','蔡戡','宋','宋诗','song-poetry','','[]','病足蹣跚好罷休，又登絕頂故遲留。',64,'全唐诗/poet.song.162000.json','["病足蹣跚好罷休，又登絕頂故遲留。", "霜明楓葉紅如染，露挹嵐光翠欲流。", "遠目無窮休更望，賞心未足卜重遊。", "超然勝絕非人世，疑是身居麟鳳洲。"]'),
('6ad742f3-e352-4635-9c65-95aafdc54a7e','水梔','蔡戡','宋','宋诗','song-poetry','','[]','誰移花本瓦盆中，怪底幽香度曉風。',64,'全唐诗/poet.song.162000.json','["誰移花本瓦盆中，怪底幽香度曉風。", "白石清泉助瀟灑，疎枝瘦葉綴玲瓏。", "晴窗坐對情無那，午枕清眠夢亦通。", "小品紛敷生意足，信知人力奪天工。"]'),
('c248347c-fa00-433c-8f33-39a4e6d630f3','不寐','蔡戡','宋','宋诗','song-poetry','','[]','獨卧虛齋百念衰，枕邊猶有數枝梅。',64,'全唐诗/poet.song.162000.json','["獨卧虛齋百念衰，枕邊猶有數枝梅。", "青燈看盡愁腸斷，畫角吹殘旅夢回。", "髮爲憂時渾欲雪，心存報國未全灰。", "功名蹭蹬身先老，那更駸駸急景催。"]'),
('31570434-4e8b-489c-9272-135c8183d574','有感  其一','蔡戡','宋','宋诗','song-poetry','','[]','宦塗慾海久沉冥，自念虛爲一世人。',64,'全唐诗/poet.song.162000.json','["宦塗慾海久沉冥，自念虛爲一世人。", "不向精微窮性理，多于蹇淺敝精神。", "休論今古無窮事，且乞江湖自在身。", "富貴功名付兒輩，一邱一壑任吾真。"]'),
('476f88c3-fad4-43d5-9898-f2efe33291b7','有感  其二','蔡戡','宋','宋诗','song-poetry','','[]','仕路驅馳老不堪，自憐蹤跡徧東南。',64,'全唐诗/poet.song.162000.json','["仕路驅馳老不堪，自憐蹤跡徧東南。", "人間失意常八九，海內同心無二三。", "蝴蝶夢中心自適，蝸牛角上戰方酣。", "要知世事皆虛幻，且向禪林更飽參。"]'),
('de3893bf-61fb-49a2-9f91-57b470276e16','有感  其三','蔡戡','宋','宋诗','song-poetry','','[]','老來觸目總堪悲，點檢尊前事已非。',64,'全唐诗/poet.song.162000.json','["老來觸目總堪悲，點檢尊前事已非。", "方歎嬌嬈隨月落，何堪樊素與春歸。", "梨花著雨還空委，柳絮因風只欲飛。", "唯有庭前柏子樹，歲寒相對兩依依。"]'),
('6a0f8e25-9f46-4c58-8344-963e906a7c70','有感  其四','蔡戡','宋','宋诗','song-poetry','','[]','蚤歲登瀛浪自期，一爲俗吏困驅馳。',64,'全唐诗/poet.song.162000.json','["蚤歲登瀛浪自期，一爲俗吏困驅馳。", "平生不得文章力，老去寧求世俗知。", "到底粗官是男子，從渠了事笑癡兒。", "全家飽暖還知否，欲報君恩力已疲。"]'),
('28bbe322-f22f-4cc6-b370-1cffcbb9fa0f','有感  其五','蔡戡','宋','宋诗','song-poetry','','[]','我本湖山一老僧，業緣未斷尚貪榮。',64,'全唐诗/poet.song.162000.json','["我本湖山一老僧，業緣未斷尚貪榮。", "重來且了前生債，死去寧須後世名。", "已絕塵嗔心不競，那堪衰老病相縈。", "散花天女今何用，爲問維摩作麽生。"]'),
('2e7dffa1-eee3-4095-896f-3e8041f7bff3','有感  其六','蔡戡','宋','宋诗','song-poetry','','[]','百年光景急如梭，攬鏡登樓奈若何。',64,'全唐诗/poet.song.162000.json','["百年光景急如梭，攬鏡登樓奈若何。", "歲月不堪供把玩，親朋已覺漸消磨。", "功名自是身心懶，憂懼端由患難多。", "富貴儻來非我有，恍如一枕夢南柯。"]'),
('95613656-ee29-4cce-bed3-5569ca0f2761','自詠  其一','蔡戡','宋','宋诗','song-poetry','','[]','自憐衰病力難勝，豈不懷歸畏友朋。',64,'全唐诗/poet.song.162000.json','["自憐衰病力難勝，豈不懷歸畏友朋。", "隨牒偶來真漫士，打包即去類孤僧。", "頭顱種種何勞問，面目稜稜自取憎。", "頼有一廛今可老，不妨飲水曲吾肱。"]'),
('b7bcf08c-2a85-474c-84f6-df2b6d366200','自詠  其二','蔡戡','宋','宋诗','song-poetry','','[]','浮生一夢疾南柯，白髮人間所閲多。',64,'全唐诗/poet.song.162000.json','["浮生一夢疾南柯，白髮人間所閲多。", "土木形骸齊物我，萍蓬蹤跡慣風波。", "可憐造化小兒耳，其奈癡頑老子何。", "毀譽是非何足較，百年顔跖共山阿。"]'),
('75d42358-6749-46a2-9b74-9e146f1f20c4','奉祠東歸  其一','蔡戡','宋','宋诗','song-poetry','','[]','老來不復歎飄零，游宦真如水上萍。',64,'全唐诗/poet.song.162000.json','["老來不復歎飄零，游宦真如水上萍。", "綿力何堪分閫寄，寬恩猶許奉祠庭。", "休誇仙去騎鯨李，剩喜歸來化鶴丁。", "料得親朋相慰藉，還驚雙鬢失青青。"]'),
('f9148da4-f456-4865-a966-484ba056c7ee','奉祠東歸  其二','蔡戡','宋','宋诗','song-poetry','','[]','書生賤分動多奇，浪得聲名毀亦隨。',64,'全唐诗/poet.song.162000.json','["書生賤分動多奇，浪得聲名毀亦隨。", "絕口不須談世事，捫心唯有仗天知。", "人間變態渾如戲，眼底風光總是詩。", "白石清泉無限好，掛冠神武未爲遲。"]'),
('d510dcce-6752-48ec-8617-a35e5f5c5580','書懷','蔡戡','宋','宋诗','song-poetry','','[]','扁舟東下自夷猶，胸次渾無一物留。',64,'全唐诗/poet.song.162000.json','["扁舟東下自夷猶，胸次渾無一物留。", "世味橫陳如嚼蠟，人生變滅似浮漚。", "休休且畢山林願，去去空懷畎畝憂。", "自念秋毫皆帝力，銜環結草若爲酬。"]'),
('152324e1-ba8f-47b7-88c1-2c117d5134ff','江行阻風','蔡戡','宋','宋诗','song-poetry','','[]','鴈峰飄泊又經年，却憶槎頭縮項鯿。',64,'全唐诗/poet.song.162000.json','["鴈峰飄泊又經年，却憶槎頭縮項鯿。", "三伏炎光真爍石，重湖駭浪遠連天。", "快風坐閲千帆過，上水徒勞百丈牽。", "坎止流行隨所遇，便當歸去訪林泉。"]'),
('ed943e0c-4faf-4592-83c6-9dc4b222207d','舟過池陽許倉蔡守留飲不果赴以詩謝之','蔡戡','宋','宋诗','song-poetry','','[]','小泊池陽暮靄中，故人留我一尊同。',64,'全唐诗/poet.song.162000.json','["小泊池陽暮靄中，故人留我一尊同。", "歸心已逐東流水，快意仍逢下水風。", "自念相逢非草草，也知別去太匆匆。", "歸來獨酌寒江上，空想賓筵蠟炬紅。"]'),
('712d83a1-66b4-44b4-926d-679fb9cbf1e4','夜宿交石峽凌晨舟行適遇便風俄頃至小孤山','蔡戡','宋','宋诗','song-poetry','','[]','好風特特送征帆，百里俄驚指顧間。',64,'全唐诗/poet.song.162000.json','["好風特特送征帆，百里俄驚指顧間。", "薄暮暫留交石峽，遲明已到小孤山。", "峰巒過目非吾有，鷗鷺無心似我閒。", "幸得年豐歸去好，長腰玉粒未應慳。"]'),
('aed9ba9e-82e5-4a93-b030-041a332a3664','金陵道中','蔡戡','宋','宋诗','song-poetry','','[]','蚤年遊歷徧諸方，觸處無心是道場。',64,'全唐诗/poet.song.162000.json','["蚤年遊歷徧諸方，觸處無心是道場。", "三已不須形喜慍，兩來寧肯異炎凉。", "落霞孤鶩仍秋水，衰草殘雲又夕陽。", "天假一帆風力便，回頭五日到家鄉。"]'),
('899d8abf-e310-4ef0-a3fb-76f5eff973ee','東歸喜而有作','蔡戡','宋','宋诗','song-poetry','','[]','投老何堪再落南，病軀寧敢望生還。',64,'全唐诗/poet.song.162000.json','["投老何堪再落南，病軀寧敢望生還。", "空慙馬援標銅柱，自分班超老玉關。", "萬里梅花愁思外，五湖煙水夢魂間。", "詔恩幸喜歸田里，旋築新堂榜愛閒。"]'),
('db7361ce-4798-466e-84f8-ebd6f7422eb0','荆溪即事','蔡戡','宋','宋诗','song-poetry','','[]','我愛荆溪擬卜居，萬家人物在蓬壺。',64,'全唐诗/poet.song.162000.json','["我愛荆溪擬卜居，萬家人物在蓬壺。", "湖光瀲灧新磨鏡，山色葱蘢罨畫圖。", "顧渚茶甘風袂爽，石亭梅老月輪孤。", "功名已矣君休問，一舸從教寄五湖。"]'),
('76a2a8d3-7438-42b3-b7bf-ffd1775d1533','新居偶成二詩示鄰人李子真  其一','蔡戡','宋','宋诗','song-poetry','','[]','薄宦歸來卜數椽，慳囊倍費買山錢。',64,'全唐诗/poet.song.162000.json','["薄宦歸來卜數椽，慳囊倍費買山錢。", "地幽不減林泉盛，天闊渾疑風月偏。", "事與心違方問舍，客將老至合歸田。", "平生豪氣今如此，百尺樓高空自憐。"]'),
('65ac4e96-4f56-46e0-ade8-d563873a495f','新居偶成二詩示鄰人李子真  其二','蔡戡','宋','宋诗','song-poetry','','[]','我得祇園十畝間，清溝一带巧縈環。',64,'全唐诗/poet.song.162000.json','["我得祇園十畝間，清溝一带巧縈環。", "芟夷叢竹通幽徑，指點荒城當遠山。", "欹枕清宵聞鶴唳，凭欄終日伴鷗閒。", "西鄰頼有詩人在，二老風流任往還。"]'),
('b4750271-4cd5-4f71-a8f3-0801a7aec420','愛閒堂','蔡戡','宋','宋诗','song-poetry','','[]','歸來築室傍城陰，旋揭新名雅意深。',64,'全唐诗/poet.song.162000.json','["歸來築室傍城陰，旋揭新名雅意深。", "因病愛閒多得趣，逢場作戲亦何心。", "鳥魚飛泳全真性，水石風流有至音。", "衰朽自知無所用，量才祇合在山林。"]'),
('19b24ed0-7b78-4e06-bb9e-168d8e48616e','劉公實以淮白爲餉喜而作詩','蔡戡','宋','宋诗','song-poetry','','[]','食指朝來應吉占，淮魚遠寄喜開奩。',64,'全唐诗/poet.song.162000.json','["食指朝來應吉占，淮魚遠寄喜開奩。", "肥鮮正自資糟粕，甘美何勞佐酪鹽。", "未信鹿頭堪並進，定知熊掌不能兼。", "慈闈一笑嘗珍味，留與兒童例屬饜。"]'),
('b392963c-9b09-45e3-8fa9-dd191856c26c','以淮白南京山藥爲子真太夫人壽即用前韻','蔡戡','宋','宋诗','song-poetry','','[]','鵲噪虛簷喜可占，奇薰得得出珍奩。',64,'全唐诗/poet.song.162000.json','["鵲噪虛簷喜可占，奇薰得得出珍奩。", "山藷尚带中原土，淮白仍餘東海鹽。", "北物遠來難再致，南烹久飫喜相兼。", "分甘擬作親庭壽，料想齊眉亦共饜。"]'),
('c3c03bee-7c50-4101-93b7-8ea58c792a26','和李子真八月十四日夜賞月之什','蔡戡','宋','宋诗','song-poetry','','[]','西園清夜喜追隨，唯恐冰輪出海遲。',64,'全唐诗/poet.song.162000.json','["西園清夜喜追隨，唯恐冰輪出海遲。", "不但曠懷皆我輩，要知痛飲是吾師。", "十分未放蟾盈魄，三匝先驚鵲遶枝。", "此夕清歡那復有，世間能得幾人知。"]'),
('b03a3e87-d85a-4d96-8e8c-2ffb56216231','詠橘','蔡戡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江上霜明十月寒，枝頭顆顆綴金丸。',64,'全唐诗/poet.song.162000.json','["江上霜明十月寒，枝頭顆顆綴金丸。", "王孫拋却黄金彈，酒伴收歸白玉槃。", "乍見渾疑盧橘熟，初嘗猶带越梅酸。", "洞庭風味真相似，試與尊前比並看。"]'),
('b6d5dc71-39a9-4001-ac47-744dc71e6c4d','以蓮實餉李子真作詩爲謝因用其韻','蔡戡','宋','宋诗','song-poetry','','[]','窮巷深居擺俗緣，幽芳偏愛小池蓮。',64,'全唐诗/poet.song.162000.json','["窮巷深居擺俗緣，幽芳偏愛小池蓮。", "戲將凈色供齋鉢，走送新房薦酒船。", "懷橘孰無慈母念，覓梨應有小兒憐。", "行看綠水芙蕖麗，漫遣登臨憶仲宣。"]'),
('e1e984a9-62af-4557-b317-7d5485510c67','金壇燈市甚盛介卿見招不能往以詩謝之','蔡戡','宋','宋诗','song-poetry','','[]','可堪回首少年强，燈夕追遊得許忙。',64,'全唐诗/poet.song.162000.json','["可堪回首少年强，燈夕追遊得許忙。", "老去情懷甘寂寞，年來節物轉凄凉。", "出門有礙身如絆，異縣相望道且長。", "漫想故人行樂處，水晶宮裏醉霞觴。"]'),
('38fa39d4-8410-4620-b311-dd4c932d46f7','燈夕不出偶成','蔡戡','宋','宋诗','song-poetry','','[]','晚歲光陰只自驚，眼中樂事歎何曾。',64,'全唐诗/poet.song.162000.json','["晚歲光陰只自驚，眼中樂事歎何曾。", "雕鞍繡幰多游子，紙帳蒲龕一病僧。", "塵翳掃除方寸地，光明散作百千燈。", "維摩丈室跏趺坐，千息調勻喚不譍。"]'),
('830d9b59-274a-4ecb-a81c-f16d2036b090','奉酬介卿惜春之什','蔡戡','宋','宋诗','song-poetry','','[]','屈指駸駸向六旬，每於春事尚關情。',64,'全唐诗/poet.song.162000.json','["屈指駸駸向六旬，每於春事尚關情。", "病逢時節還虛度，老去光陰只暗驚。", "剩喜清新詩句好，休辭瀲灧酒盃盈。", "榮枯代謝年年事，怪底鶑聲訴不平。"]'),
('ce74ec5d-594f-441e-a21a-24f854e4339e','介卿送方竹杖以詩謝之','蔡戡','宋','宋诗','song-poetry','','[]','何必窮搜到大宛，仰山龍種出天然。',64,'全唐诗/poet.song.162000.json','["何必窮搜到大宛，仰山龍種出天然。", "直方自得坤爻動，堅瘦宜居靈壽先。", "剩喜登山扶病足，不妨倚壁伴清眠。", "故人若問今無恙，不似山僧故削圓。"]'),
('25ad1889-b90b-4d2a-90d5-8b0940c24ad2','遊金山','蔡戡','宋','宋诗','song-poetry','','[]','襆被歸來萬事輕，此行得得爲登臨。',64,'全唐诗/poet.song.162000.json','["襆被歸來萬事輕，此行得得爲登臨。", "蒼崖斗絕山浮玉，碧瓦鱗差地布金。", "千里江淮窮遠目，十年塵土愧初心。", "何人爲擊中流楫，北望神州淚滿襟。"]'),
('83293ee6-3c37-4c5a-a623-3d6f595e55f2','題東皋','蔡戡','宋','宋诗','song-poetry','','[]','歸來相望築東皋，千載風流獨慕陶。',64,'全唐诗/poet.song.162000.json','["歸來相望築東皋，千載風流獨慕陶。", "兩地林泉俱勝絕，二難人物總孤高。", "地連衡嶽浮空翠，天與湘江隔世鏖。", "祇恐山靈回俗駕，可容暇日再遊遨。"]'),
('1700019d-6444-44b9-a985-4d6f302492d8','燕坐小閣','蔡戡','宋','宋诗','song-poetry','','[]','丈室翛然一物無，平生習氣痛消除。',64,'全唐诗/poet.song.162000.json','["丈室翛然一物無，平生習氣痛消除。", "藥爐經卷常爲伴，酒盞茶瓶自作疎。", "老去頭顱休更問，本來面目竟何如。", "泛觀博覽渾無用，且讀西方貝葉書。"]'),
('0d5d1c5d-ac27-42ad-a864-65f5806f901c','雪中用王使君韻招介卿','蔡戡','宋','宋诗','song-poetry','','[]','江南雪片一冬深，欺壓梅花瘦不禁。',64,'全唐诗/poet.song.162000.json','["江南雪片一冬深，欺壓梅花瘦不禁。", "入地遺蝗應掃迹，連阡宿麥始抽心。", "幻成玉界清無滓，踏碎瑶階迹可尋。", "剩喜扁舟來訪我，何妨乘興共清斟。"]'),
('e3df3813-bd19-4119-a023-b262b25c820e','雪中用前韻示汝咨汝功二姪','蔡戡','宋','宋诗','song-poetry','','[]','策試中庭雪已深，玉樓凍合冷難禁。',64,'全唐诗/poet.song.162000.json','["策試中庭雪已深，玉樓凍合冷難禁。", "哦成風絮頻呵手，撥盡寒灰苦用心。", "梁苑巧粧花滿樹，藍田幻出玉千尋。", "吾家二謝多才思，莫惜高吟更淺斟。"]'),
('b391afb8-a570-40db-8acb-202d6e1351d4','次蔡介卿雪中見寄  其一','蔡戡','宋','宋诗','song-poetry','','[]','玄冥作意逞雄豪，陵壓東君慘不驕。',64,'全唐诗/poet.song.162000.json','["玄冥作意逞雄豪，陵壓東君慘不驕。", "一氣回春何太晚，羣陰見睍未全消。", "漫誇呈瑞宜新麥，那似爲霖救旱苗。", "造物深機雖莫測，願言六氣自均調。"]'),
('e35ff67b-2d0d-4adc-addd-4cdc8a31d2a8','次蔡介卿雪中見寄  其二','蔡戡','宋','宋诗','song-poetry','','[]','等閒栽遍小園花，賸擬春來賞物華。',64,'全唐诗/poet.song.162000.json','["等閒栽遍小園花，賸擬春來賞物華。", "不覺瓊英先滿樹，更看縞带暗隨車。", "光摇玉鏡冰初泮，凍屈金鈎草未芽。", "料得小橋人不到，江梅欺壓任橫斜。"]'),
('80dde11b-e128-45c8-b472-70522b2a53c0','病中書','蔡戡','宋','宋诗','song-poetry','','[]','短褐頹然一病僧，支離瘦骨伴枯藤。',64,'全唐诗/poet.song.162000.json','["短褐頹然一病僧，支離瘦骨伴枯藤。", "掃除習氣嗟猶在，擺脫塵緣愧未能。", "案上縱橫堆藥裹，篋中顛倒貯書縢。", "青鞋布襪從茲始，試叩如來大小乘。"]'),
('62a0bfbe-fd50-40fa-ba14-fbbe9baa21e5','挽胡通判','蔡戡','宋','宋诗','song-poetry','','[]','胡公家學本中庸，挺挺雲來有祖風。',64,'全唐诗/poet.song.162000.json','["胡公家學本中庸，挺挺雲來有祖風。", "但得年皆餘八十，何妨位不至三公。", "方期束帛迎申老，忽舉空衣葬葛洪。", "江左祇今推甲族，慶源衮衮自無窮。"]'),
('b3fc327a-b399-4693-93ee-ad5bd7738389','齊子餘侍郎挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','玉筍班中第一人，堂堂風采照公卿。',64,'全唐诗/poet.song.162000.json','["玉筍班中第一人，堂堂風采照公卿。", "箕裘四世儒科貴，簪橐三朝法從榮。", "廣厦細旃多啟沃，黄扉青瑣罄忠誠。", "經綸未了猶遺恨，信史空留後世名。"]'),
('ce16a5c7-2498-496d-b604-e1d59bb78aa3','齊子餘侍郎挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','哀榮終始冠當時，何况人生七十稀。',64,'全唐诗/poet.song.162000.json','["哀榮終始冠當時，何况人生七十稀。", "峴首正思羊叔子，宣城還憶謝玄暉。", "松階方俟甘泉對，蒿里俄驚朝露晞。", "他日西州忍重過，爲公回首一霑衣。"]'),
('a1b41a6e-0150-4b5c-96cf-79d0f52f3de7','李粹伯侍御挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','妙齡才氣已無雙，軍陣飛揚翰墨場。',64,'全唐诗/poet.song.162000.json','["妙齡才氣已無雙，軍陣飛揚翰墨場。", "白簡空餘遺藁在，錦囊應有近詩藏。", "生前且盡杯中物，死去猶堪地下郎。", "逸氣不應埋宿草，會看千丈吐光芒。"]'),
('03db4a81-8b80-4d06-8bd2-dc61d2b3547e','李粹伯侍御挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','猶記當年玉筍班，凜然風采動朝端。',64,'全唐诗/poet.song.162000.json','["猶記當年玉筍班，凜然風采動朝端。", "壯懷漫擬麒麟閣，直氣曾纓獬豸冠。", "太白風姿圖像見，衛公英爽夢魂寒。", "四州巷哭多遺愛，留取甘棠勿翦殘。"]'),
('3319a2dd-9530-44d1-ae65-a1a677b9ed3a','胡長文給事挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','中庸天下有胡公，儒者端宜給事中。',64,'全唐诗/poet.song.162000.json','["中庸天下有胡公，儒者端宜給事中。", "華國高文推大手，回天讜論罄孤忠。", "晨班玉筍人何在，夜賜金蓮事已空。", "惆悵故園招隠地，唯餘猿鶴怨西風。"]'),
('7addf682-6d2e-4b56-b8fb-4666b508421c','胡長文給事挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','大才深結九重知，親灑宸章出禁闈。',64,'全唐诗/poet.song.162000.json','["大才深結九重知，親灑宸章出禁闈。", "壺遂暮年非不遇，謝公雅志或相違。", "虎龍倍覺鍾山重，龜鶴還從蜀道歸。", "故吏門生半天下，空垂老淚一霑衣。"]'),
('6792d122-0bd7-4984-bd62-09e327b0c90f','錢大受挽詩  其一','蔡戡','宋','宋诗','song-poetry','','[]','少年豪氣已如虹，抵掌論兵一世雄。',64,'全唐诗/poet.song.162000.json','["少年豪氣已如虹，抵掌論兵一世雄。", "智略獨超倫輩上，功名只在笑談中。", "弄兵坐掃潢池盜，賣劍潜回渤海風。", "恢復未酬人奄忽，佳城那忍葬滕公。"]'),
('740f45b7-c454-4419-aebb-265ceea3fa17','錢大受挽詩  其二','蔡戡','宋','宋诗','song-poetry','','[]','淝水功名取次休，空令遺恨滿滄洲。',64,'全唐诗/poet.song.162000.json','["淝水功名取次休，空令遺恨滿滄洲。", "禁中新賜黄金带，天上俄成白玉樓。", "京峴兒童應墮淚，江淮草木亦生愁。", "一朝雙劍齊飛去，會見光芒射斗牛。"]'),
('a946fc10-cc08-490f-8134-8a5b63b991e8','和胡秉彝敷文巖桂四首  其一','蔡戡','宋','宋诗','song-poetry','','[]','翠葆金英天與奇，清香十里已先知。',32,'全唐诗/poet.song.162000.json','["翠葆金英天與奇，清香十里已先知。", "春光不似秋光好，桃李紛紛何所施。"]'),
('8188b4b3-aec5-4dae-8108-7f357cbf7700','和胡秉彝敷文巖桂四首  其二','蔡戡','宋','宋诗','song-poetry','','[]','移根月窟最珍奇，料得姮娥誰不知。',32,'全唐诗/poet.song.162000.json','["移根月窟最珍奇，料得姮娥誰不知。", "挽住西風拚一醉，玉杯從此不徒施。"]'),
('449d843e-bdf2-4de6-a3e7-017d86fb92db','和胡秉彝敷文巖桂四首  其三','蔡戡','宋','宋诗','song-poetry','','[]','獨占秋光自一奇，深藏巖壑少人知。',32,'全唐诗/poet.song.162000.json','["獨占秋光自一奇，深藏巖壑少人知。", "招還茉莉同爲伴，欺壓黄花不得施。"]'),
('a0fe1b18-90f8-4968-a62c-64a6ff1a356c','和胡秉彝敷文巖桂四首  其四','蔡戡','宋','宋诗','song-poetry','','[]','秋入東山景物奇，花開亦遣野人知。',32,'全唐诗/poet.song.162000.json','["秋入東山景物奇，花開亦遣野人知。", "二難佳句真連璧，顧我深慙嫫與施。"]'),
('bd669575-61a8-446f-8e0b-301dcfa2e093','端約遺墨梅以詩謝之  其一','蔡戡','宋','宋诗','song-poetry','','[]','先生出語已驚人，戲作梅花又逼真。',32,'全唐诗/poet.song.162000.json','["先生出語已驚人，戲作梅花又逼真。", "眼底江山詩有助，胸中丘壑畫精神。"]'),
('e85773d8-ee42-4700-a476-77d38efc43d8','端約遺墨梅以詩謝之  其二','蔡戡','宋','宋诗','song-poetry','','[]','清香素質惱詩情，更倩揮毫爲寫真。',32,'全唐诗/poet.song.162000.json','["清香素質惱詩情，更倩揮毫爲寫真。", "共挽東風拚一醉，不須摹倣費精神。"]'),
('fb8057b5-ed16-47bb-9056-c8ccb20be3f1','龔彥則送水梔小盆口占爲謝','蔡戡','宋','宋诗','song-poetry','','[]','動人春色不須多，一點幽香叵奈何。',32,'全唐诗/poet.song.162000.json','["動人春色不須多，一點幽香叵奈何。", "薝蔔林中誰折得，故令相惱病維摩。"]'),
('a8737e21-5b9f-4877-980f-cd71c1ee4c01','王東卿惠墨戲副之以詩因次韻謝之  其一','蔡戡','宋','宋诗','song-poetry','','[]','戲拈禿筆聊復爾，一翦吳淞半江水。',32,'全唐诗/poet.song.162000.json','["戲拈禿筆聊復爾，一翦吳淞半江水。", "歸心已逐水東流，夢到家山四千里。"]'),
('ecfceef8-f41d-440f-a097-d7bc24fa5878','王東卿惠墨戲副之以詩因次韻謝之  其二','蔡戡','宋','宋诗','song-poetry','','[]','枯槎怪石出天然，筆力挽回三百年。',32,'全唐诗/poet.song.162000.json','["枯槎怪石出天然，筆力挽回三百年。", "但見毫端侔造化，不知胸次藴天淵。"]'),
('eb581354-da8c-4d0a-92db-ddfbf361893a','王東卿惠墨戲副之以詩因次韻謝之  其三','蔡戡','宋','宋诗','song-poetry','','[]','揮翰等閒遊戲爾，誰能十日畫一水。',32,'全唐诗/poet.song.162000.json','["揮翰等閒遊戲爾，誰能十日畫一水。", "煙雲杳靄咫尺間，遠勢應須論萬里。"]'),
('7b861036-93af-4546-b09b-0ac58ccbcd18','王東卿惠墨戲副之以詩因次韻謝之  其四','蔡戡','宋','宋诗','song-poetry','','[]','玉篸羅带故依然，吏部文章二百年。',32,'全唐诗/poet.song.162000.json','["玉篸羅带故依然，吏部文章二百年。", "畫筆詩篇兩奇絕，正須妙手寫龍淵。"]'),
('2ef3923c-e0af-44dd-97f8-6d77ef4c96c3','王東卿惠墨戲副之以詩因次韻謝之  其五','蔡戡','宋','宋诗','song-poetry','','[]','軒冕儻來真漫爾，穩泛瀟湘弄煙水。',32,'全唐诗/poet.song.162000.json','["軒冕儻來真漫爾，穩泛瀟湘弄煙水。", "憑君收入畫圖中，一抹雲山數千里。"]'),
('71275a7c-1eca-4b3f-aa1f-dedc3d63a513','王東卿惠墨戲副之以詩因次韻謝之  其六','蔡戡','宋','宋诗','song-poetry','','[]','近時畫手說超然，小景仍推趙大年。',32,'全唐诗/poet.song.162000.json','["近時畫手說超然，小景仍推趙大年。", "誰識當家老摩詰，有如珠玉韞深淵。"]'),
('f6342848-3480-4721-a871-f848d8add7f1','和胡端約巖桂六首  其一','蔡戡','宋','宋诗','song-poetry','','[]','萬妃蕊珮影珊珊，沉水薰肌栗玉顔。',32,'全唐诗/poet.song.162000.json','["萬妃蕊珮影珊珊，沉水薰肌栗玉顔。", "曾記廣寒宮裏見，誰移仙種下人間。"]'),
('896b8e37-24d5-41cc-9c32-b06d33815e2b','和胡端約巖桂六首  其二','蔡戡','宋','宋诗','song-poetry','','[]','薔薇清露染衣裳，綽約仙姿淡淡粧。',32,'全唐诗/poet.song.162000.json','["薔薇清露染衣裳，綽約仙姿淡淡粧。", "碧玉參差張翠幄，黄金錯落綴珠璫。"]'),
('c92b810b-698b-4004-a526-a2bf43fbfe9d','和胡端約巖桂六首  其三','蔡戡','宋','宋诗','song-poetry','','[]','羞澀東籬九日黄，拒霜粗俗不宜霜。',32,'全唐诗/poet.song.162000.json','["羞澀東籬九日黄，拒霜粗俗不宜霜。", "此花底事小如許，無那惱人風味長。"]'),
('c2388ec3-f038-42a9-b048-cfe6d9742942','和胡端約巖桂六首  其四','蔡戡','宋','宋诗','song-poetry','','[]','幽香拂拂影珊珊，宜在江梅伯仲間。',32,'全唐诗/poet.song.162000.json','["幽香拂拂影珊珊，宜在江梅伯仲間。", "懶對春風爭嫵媚，從他桃李自漫山。"]'),
('bb1bdfd3-7a65-47cf-95c0-db5f104f1635','和胡端約巖桂六首  其五','蔡戡','宋','宋诗','song-poetry','','[]','勿愁金蕊墮秋風，自是靈犀一點通。',32,'全唐诗/poet.song.162000.json','["勿愁金蕊墮秋風，自是靈犀一點通。", "醉魄薰成寶篝細，香脂勻就玉肌豐。"]'),
('a27ddf91-e095-4339-b9e6-b0b10373805e','和胡端約巖桂六首  其六','蔡戡','宋','宋诗','song-poetry','','[]','一枝小摘間簪冠，酌酒酬花莫作難。',32,'全唐诗/poet.song.162000.json','["一枝小摘間簪冠，酌酒酬花莫作難。", "唯有詩情被花惱，冥搜應作孟郊寒。"]'),
('171d0422-b2d9-46ae-ab01-02c8a0806520','題墨梅','蔡戡','宋','宋诗','song-poetry','','[]','誰作橫枝太逼真，枝頭的皪眼俱明。',32,'全唐诗/poet.song.162000.json','["誰作橫枝太逼真，枝頭的皪眼俱明。", "也知筆力窺天巧，無奈清香畫不成。"]'),
('9df2df72-4ed2-4161-af56-4d79c94b6f20','道中見梅','蔡戡','宋','宋诗','song-poetry','','[]','籃輿兀兀夢初回，怪底幽香觸鼻來。',32,'全唐诗/poet.song.162000.json','["籃輿兀兀夢初回，怪底幽香觸鼻來。", "日暮天寒正愁絕，誰家籬落數枝開。"]'),
('369547a5-29fa-44b8-a69d-53cbfeb33a9f','三孤山','蔡戡','宋','宋诗','song-poetry','','[]','小孤相去大孤山，一望烟波百里間。',32,'全唐诗/poet.song.162000.json','["小孤相去大孤山，一望烟波百里間。", "風日晴和江似鏡，兩峰對峙擁青鬟。"]'),
('40347818-3609-4a7b-b73d-85c0232be2c9','剡溪','蔡戡','宋','宋诗','song-poetry','','[]','六月衝炎出問囚，歸途因泛剡溪舟。',32,'全唐诗/poet.song.162000.json','["六月衝炎出問囚，歸途因泛剡溪舟。", "短篷塊坐如深甑，却羨清寒王子猷。"]'),
('1c7b3f95-fe91-491b-a21c-5a2d1944c80b','春郊即事','蔡戡','宋','宋诗','song-poetry','','[]','一犁春雨欲平塍，預卜今年穡事成。',32,'全唐诗/poet.song.162000.json','["一犁春雨欲平塍，預卜今年穡事成。", "天意却愁人意懶，故令布穀苦催耕。"]'),
('192e4e2b-9666-4851-82e0-8d3077db24bb','提壺','蔡戡','宋','宋诗','song-poetry','','[]','斗酒千金未易沽，聲聲何事勸提壺。',32,'全唐诗/poet.song.162000.json','["斗酒千金未易沽，聲聲何事勸提壺。", "山禽豈解知人意，不道思家飯也無。"]'),
('3436a93f-8543-44ba-a910-6d8181f27811','鷓鴣','蔡戡','宋','宋诗','song-poetry','','[]','年來隨牒走駸駸，險阻誰知客子心。',32,'全唐诗/poet.song.162000.json','["年來隨牒走駸駸，險阻誰知客子心。", "盡日只憂行不得，愛人猶頼有斯禽。"]'),
('2985d1b1-d81d-4213-affb-2744be11162b','竹鷄','蔡戡','宋','宋诗','song-poetry','','[]','積雨霖淫四月寒，春泥一尺未曾乾。',32,'全唐诗/poet.song.162000.json','["積雨霖淫四月寒，春泥一尺未曾乾。", "勃姑猶自相呼喚，不念征人行路難。"]'),
('ced991da-426f-4204-8d7b-7cd25577bfda','天柱峰','蔡戡','宋','宋诗','song-poetry','','[]','壁立千峰紫翠浮，一峰直上更孤遒。',32,'全唐诗/poet.song.162000.json','["壁立千峰紫翠浮，一峰直上更孤遒。", "世間有此擎天柱，何用人懷杞國憂。"]'),
('67f99718-18f9-4600-a730-7100df721ca2','日者鄭生謂余晚遇至人享上壽其詞多誕以詩簡之','蔡戡','宋','宋诗','song-poetry','','[]','鐘鼎山林不兩全，未聞富貴出神仙。',32,'全唐诗/poet.song.162000.json','["鐘鼎山林不兩全，未聞富貴出神仙。", "萬釘寶带何須此，九轉金丹未可憐。"]'),
('eac17612-a954-42f1-ad2f-aa18e7d9fdab','黄陵廟  其一','蔡戡','宋','宋诗','song-poetry','','[]','千載追崇古帝祠，不知世代幾推移。',32,'全唐诗/poet.song.162000.json','["千載追崇古帝祠，不知世代幾推移。", "未須回首叫虞舜，今日親逢虞舜時。"]'),
('5736eb8e-b2b2-4923-a37b-a30c9bebe144','黄陵廟  其二','蔡戡','宋','宋诗','song-poetry','','[]','蒼梧杳靄暮雲陰，尚記南巡歲月深。',32,'全唐诗/poet.song.162000.json','["蒼梧杳靄暮雲陰，尚記南巡歲月深。", "不但邦人嚴祀事，至今千古想韶音。"]'),
('a59849a2-4b7f-4635-a311-3e0bddce8b84','九宮壇齋居','蔡戡','宋','宋诗','song-poetry','','[]','齋居獨卧小禪房，暫得心閒氣味長。',32,'全唐诗/poet.song.162000.json','["齋居獨卧小禪房，暫得心閒氣味長。", "一炷爐熏春睡足，此身疑是在家鄉。"]'),
('6c8292bd-65b5-4d14-8bbb-174f27967743','六十','蔡戡','宋','宋诗','song-poetry','','[]','六十不歸何日歸，人生七十古來稀。',32,'全唐诗/poet.song.162000.json','["六十不歸何日歸，人生七十古來稀。", "憂愁疾病常相半，十載光陰轉矚非。"]'),
('e7444f91-1c96-4d0d-a2cb-59b7416b1ddc','登三高亭','蔡戡','宋','宋诗','song-poetry','','[]','我爲蓴鱸得得來，三高亭上且徘徊。',32,'全唐诗/poet.song.162000.json','["我爲蓴鱸得得來，三高亭上且徘徊。", "老來心事無機械，寄語羣鷗勿浪猜。"]'),
('61ce26dc-b376-4503-bf84-688e71014cf1','平山堂','蔡戡','宋','宋诗','song-poetry','','[]','平山堂上略從容，笑拍欄干萬事空。',32,'全唐诗/poet.song.162000.json','["平山堂上略從容，笑拍欄干萬事空。", "因念醉翁行樂地，不知還又幾春風。"]'),
('bb1ba6da-0f7b-4825-a22a-71fd90f437f7','于公參政舊居','蔡戡','宋','宋诗','song-poetry','','[]','勇退方名大丈夫，中興人物更誰如。',32,'全唐诗/poet.song.162000.json','["勇退方名大丈夫，中興人物更誰如。", "傳家不獨青氈在，况有南陽舊隠廬。"]'),
('544369fe-4d5b-48ad-a5f2-9d26bbdbe4fe','次張伯信韻題吳園畫軸','蔡戡','宋','宋诗','song-poetry','','[]','誰把吳園較輞川，畫圖猶復想當年。',32,'全唐诗/poet.song.162000.json','["誰把吳園較輞川，畫圖猶復想當年。", "要知故國非喬木，文采風流尚宛然。"]'),
('16adac05-0fab-41cd-8ffc-952584eaf9f7','紅菊','蔡戡','宋','宋诗','song-poetry','','[]','爲愛東籬九日黄，孤標正色占秋光。',32,'全唐诗/poet.song.162000.json','["爲愛東籬九日黄，孤標正色占秋光。", "如何却被臙脂污，也學人間時世妝。"]'),
('85c397b2-3da3-46cd-9313-ebfd84eec509','送葛謙問  其一','蔡戡','宋','宋诗','song-poetry','','[]','風流人物曹劉上，俊逸詩章鮑謝間。',32,'全唐诗/poet.song.162000.json','["風流人物曹劉上，俊逸詩章鮑謝間。", "好似騎鯨天上去，不應著脚向塵寰。"]'),
('45f71e33-bc9e-4112-8c5b-fe0bfbf661a8','送葛謙問  其二','蔡戡','宋','宋诗','song-poetry','','[]','禪心久已絕貪嗔，劇飲狂歌總是真。',32,'全唐诗/poet.song.162000.json','["禪心久已絕貪嗔，劇飲狂歌總是真。", "世態紛紛翻覆手，不圖復見葛天民。"]'),
('0fb5e816-0dfc-470d-a3cd-47b27e3c73ca','送葛謙問  其三','蔡戡','宋','宋诗','song-poetry','','[]','有酒盈尊客滿門，陳卿百謫不須聞。',32,'全唐诗/poet.song.162000.json','["有酒盈尊客滿門，陳卿百謫不須聞。", "癡兒官事何時了，我本無心出岫雲。"]'),
('cf1e9a60-811b-4906-b121-312d135e2eca','送葛謙問  其四','蔡戡','宋','宋诗','song-poetry','','[]','杯酒從容相勸酬，須臾墮幘自搔頭。',32,'全唐诗/poet.song.162000.json','["杯酒從容相勸酬，須臾墮幘自搔頭。", "玉山傾倒從人笑，我醉欲眠君罷休。"]'),
('a36b69a0-3329-4645-8a64-92316aad3437','送葛謙問  其五','蔡戡','宋','宋诗','song-poetry','','[]','功名固有更何疑，平步青雲不用梯。',32,'全唐诗/poet.song.162000.json','["功名固有更何疑，平步青雲不用梯。", "他日玉堂風雨夜，略移清夢到荆溪。"]'),
('c85d8b37-f234-4636-a4ff-32264bdb17e9','送葛謙問  其六','蔡戡','宋','宋诗','song-poetry','','[]','江上霜楓葉葉紅，不堪摇落又西風。',32,'全唐诗/poet.song.162000.json','["江上霜楓葉葉紅，不堪摇落又西風。", "只愁疊鼓催船去，千里相思月滿空。"]'),
('77111a74-696f-4aa2-b8d2-073402e8cf60','送葛謙問  其七','蔡戡','宋','宋诗','song-poetry','','[]','從來鐘鼎不關心，此去溪山更可人。',32,'全唐诗/poet.song.162000.json','["從來鐘鼎不關心，此去溪山更可人。", "儻有新詩摹勝槩，好憑尺素寄雙鱗。"]'),
('e1d8f262-d0e6-417c-ae70-d32441df495b','送葛謙問  其八','蔡戡','宋','宋诗','song-poetry','','[]','垂虹亭上少遲留，卧看冰輪萬里秋。',32,'全唐诗/poet.song.162000.json','["垂虹亭上少遲留，卧看冰輪萬里秋。", "正是蓴絲鱸鱠美，不妨乘興五湖舟。"]'),
('93ba0bc5-7f8e-4f7f-99a8-f090c52c0380','送葛謙問  其九','蔡戡','宋','宋诗','song-poetry','','[]','莫唱陽關墮淚聲，一杯相屬已酸辛。',32,'全唐诗/poet.song.162000.json','["莫唱陽關墮淚聲，一杯相屬已酸辛。", "丈夫感慨猶如此，應有偷彈玉筯人。"]'),
('889c6d8f-a19b-4d8d-a243-638d99577a48','送葛謙問  其一○','蔡戡','宋','宋诗','song-poetry','','[]','顧我窮途醉未醒，年來不復歎飄零。',32,'全唐诗/poet.song.162000.json','["顧我窮途醉未醒，年來不復歎飄零。", "道山朋舊如相問，爲說生涯一草亭。"]'),
('c15e11bb-661c-4aaf-9c51-61a2958b2887','乍寒','蔡戡','宋','宋诗','song-poetry','','[]','秀色芳心曉露叢，翩翩凉葉舞西風。',32,'全唐诗/poet.song.162000.json','["秀色芳心曉露叢，翩翩凉葉舞西風。", "虛簷四面摇翬扇，更遣清陰滿座中。"]'),
('fec9810d-3e02-477a-a56b-927a599440a8','盱眙','蔡戡','宋','宋诗','song-poetry','','[]','自古東南第一山，於今無異玉門關。',64,'全唐诗/poet.song.162000.json','["自古東南第一山，於今無異玉門關。", "亂雲衰草蒼茫外，赤縣神州指顧間。", "擊楫何人酬壯志，凭欄終日慘愁顔。", "中原父老應遺恨，祇見旃車歲往還。"]'),
('8e2bba15-1304-4117-9338-ee2ca71d7257','讀龔實之參政詩','蔡戡','宋','宋诗','song-poetry','','[]','耆舊頻凋喪，懷人念里閭。',48,'全唐诗/poet.song.162000.json','["耆舊頻凋喪，懷人念里閭。", "哦詩三歎息，廢卷一嗟噓。", "造膝言猶在，謀身計亦疎。", "功名今已矣，英爽竟何如。"]'),
('a4ecc474-e461-4243-a03c-3e7dec034934','偶作','蔡戡','宋','宋诗','song-poetry','','[]','老僧真是百無能，有口何嘗話葛藤。',64,'全唐诗/poet.song.162000.json','["老僧真是百無能，有口何嘗話葛藤。", "入定參禪良自苦，超凡入聖又誰曾。", "東西路別徒勞泣，南北宗分自取憎。", "箇裏無禪亦無佛，常行粥飯在家僧。"]'),
('1f3b26f9-65dc-4c05-9762-22a63f16201c','南巖','蔡戡','宋','宋诗','song-poetry','','[]','筍輿兀兀一南巖，人在千峰紫翠間。',32,'全唐诗/poet.song.162000.json','["筍輿兀兀一南巖，人在千峰紫翠間。", "剩欲日來陪杖屨，其如病足怯登山。"]'),
('f2901836-a586-4383-a0d2-1e94972a0ee0','存目','蔡戡','宋','宋诗','song-poetry','','[]','詩題：王侍中智興武略英奇敕授徐州節制，余因作此以記其事云首句：平生弓劍自相隨。',39,'全唐诗/poet.song.162000.json','["詩題：王侍中智興武略英奇敕授徐州節制，余因作此以記其事云首句：平生弓劍自相隨。"]'),
('1188a5cb-526c-4a4c-86d5-d769b090b34c','明堂禮成詩','楊簡','宋','宋诗','song-poetry','','[]','去臘陳三劄，茲秋奉九筵。',168,'全唐诗/poet.song.162000.json','["去臘陳三劄，茲秋奉九筵。", "羣英俱有賦，孤跡敢無篇。", "宗祀新隆禮，宸衷上格天。", "虛明融寂寞，大化合敷宣。", "近駭邊烽急，前驚內寇連。", "鬼神雖然佑，刑政謹將然。", "咸謂公私雜，希聆宰相賢。", "積深千萬弊，任止二三年。", "苟且姑循舊，嗟咨亦屢傳。", "旱蝗難熟視，殍殣慘相聯。", "寒後裘方索，薪間火已然。", "冕旒幾咫尺，軒陛隔天淵。", "善頌無諛語，愚衷有至虔。", "願兢兢業業，安止出剛乾。"]'),
('e48b1cfa-88d2-4293-9354-3d2f8ed87df2','內丹歌','楊簡','宋','宋诗','song-poetry','','[]','某聞內丹不可見，不待施工自成煉。',332,'全唐诗/poet.song.162000.json','["某聞內丹不可見，不待施工自成煉。", "羲皇以上幾春秋，何啻千千萬萬轉。", "到今晝夜流光湧，金烏夜照廣寒殿。", "餘輝散發綴碧落，稀稠紛糾珠玉濺。", "沖氣祥精騰太虛，舒卷飛浮態累變。", "映空曉景綠拖藍，錯綺晚凝紅染茜。", "有時震響轟冥濛，有時熠燿盤飛線。", "有時清潤垂冰絲，有時怱舞瓊花片。", "其間秀結成山川，密木繁林飛鳥蟲魚次第現。", "龍翔鳳鳴寶藏興，絪縕孕瑞生羣英。", "四明之麓鄞之曲，育神含和備五福。", "中有祥光兩派明，內虛外應無不燭。", "能聽能言能往復。", "屈伸俯仰天然奇，不知手舞蹈與足。", "二十年前忽轉移，驀過慈川天寶山之西。", "翠微曲複烟霞深，變化遊徙誰復知端倪。", "石魚樓閣雲氣低，比年往往暫此棲。", "御風兩渡浙河去，又尋歸路從桃蹊。", "桃源深處無人識，縱復經從當面迷。", "天實秘此丹，所見惟童顔。", "暫時一語露一班，不直知音又復還。"]'),
('e233f962-0335-4159-96be-cdbe0ca23fd4','登石魚樓','楊簡','宋','宋诗','song-poetry','','[]','樓欄倚碧空，綠樹正摇風。',144,'全唐诗/poet.song.162000.json','["樓欄倚碧空，綠樹正摇風。", "我獨來從容，笑歌於其中。", "微涼吹我衣，碧袂紗玲瓏。", "詩成自長吟，宛轉音和融。", "此意無人會，只許清風同。", "亦許空間雲，悠然西又東。", "亦許林間禽，幽囀聲無蹤。", "亦許山間翁，笑語天機通。", "前山對我吟，突兀青重重。", "終日賡我歌，知音無瞽宗。", "知音自古少，日月空臨照。", "天地終不秘，造化今未了。"]'),
('0d7675de-0285-459a-8f70-fd4092687af8','石魚樓  其一','楊簡','宋','宋诗','song-poetry','','[]','多謝天工意已勤，四時換樣示吾人。',64,'全唐诗/poet.song.162000.json','["多謝天工意已勤，四時換樣示吾人。", "碧桃丹杏分明了，綠艾紅榴次第陳。", "秋鴈聲中休鹵莽，雪梅枝上莫因循。", "機關踏著元非彼，正是吾家固有身。"]'),
('8512e1b7-c539-41e2-9ed3-af2292efb878','石魚樓  其二','楊簡','宋','宋诗','song-poetry','','[]','箇裏包坤更括乾，精神微動便紛然。',64,'全唐诗/poet.song.162000.json','["箇裏包坤更括乾，精神微動便紛然。", "桃紅柳綠春無跡，魚躍鳶飛妙不傳。", "菱浪豈緣風衮衮，荷珠不爲露涓涓。", "分明是了何言否，此事難容鄭氏箋。"]'),
('e6d1fa5a-88ba-4948-a8bb-2afa99b51a6b','寶蓮官舍偶作','楊簡','宋','宋诗','song-poetry','','[]','雲海湖山有主人，寶蓮峰頂露精神。',64,'全唐诗/poet.song.162000.json','["雲海湖山有主人，寶蓮峰頂露精神。", "有時領客登高去，親手挑窗對景新。", "萬里蒼茫融妙意，三杯虛白浴天真。", "出門更有慇懃在，爲奏松風又絕倫。"]'),
('9aa93b4c-8661-4f66-bfef-ffd58bc22d74','遊樂平明巖','楊簡','宋','宋诗','song-poetry','','[]','西風吹作明巖去，石屋高虛滴如乳。',32,'全唐诗/poet.song.162000.json','["西風吹作明巖去，石屋高虛滴如乳。", "是誰不是洞中仙，無人自信吾爲主。"]'),
('0255e7ce-eeea-4244-9141-d3e14a6fb78f','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其一','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "只今烟水平軒檻，觸目無非是孝慈。"]'),
('f1f4677f-014d-4034-91ae-f5a520469ec4','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其二','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "只今弄月吟風處，孔子明言是孝慈。"]'),
('5dfafc38-7bd3-4857-ad6d-11d6fe1588ad','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其三','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "只今山色連深翠，孔子明言是孝慈。"]'),
('55c713f2-be3c-44f2-be05-3441b31298fe','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其四','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "只今步步雲生足，底用思爲底用疑。"]'),
('2c2e17cc-82e1-47c7-afbd-d1d8e9278837','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其五','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "只今講學從遊地，一聽思爲一聽疑。"]'),
('3a474298-0515-49f1-9b60-04897c9c6b4f','嘉泰昭陽大淵獻築室董孝君祠之西下有湖焉某曰溪以董君慈孝而得名縣又以是名則是湖宜亦以慈名作詩曰  其六','楊簡','宋','宋诗','song-poetry','','[]','惜也天然一段奇，如何萬古罕人知。',32,'全唐诗/poet.song.162000.json','["惜也天然一段奇，如何萬古罕人知。", "慇懃爲語從遊子，孰是思爲孰是疑。"]'),
('8ed0f42d-c601-4e6f-92fc-861dfbdc1935','送黄文叔侍郎赴三山','楊簡','宋','宋诗','song-poetry','','[]','某信人心即大道，先聖遺言茲可考。',200,'全唐诗/poet.song.162000.json','["某信人心即大道，先聖遺言茲可考。", "心之精神是謂聖，詔告昭昭復皜皜。", "如何後學尚生疑，職由起意而支離。", "自此濫觴至滔襄，毋惑懷玉不自知。", "何思何慮心思靈，不識不知洞光明。", "意萌微動雪沾水，泯然無際澄且清。", "侍郎日用所自有，總是本原非左右。", "舉而措之於三山，的然民仰如父母。", "鑑明水止燭絲釐，變化云爲奇復奇。", "斯妙可言不可思，矧可傾耳而聽之。", "然而臯禹尚兢業，不作好惡生枝葉。", "聖賢相與告戒尚有斯，某也何敢不於侍郎之前獻此詩。"]'),
('dff0baf0-a74a-4833-91b7-a1628b9e30c0','熙光','楊簡','宋','宋诗','song-poetry','','[]','兢業初無蹊徑，緝熙本有光明。',56,'全唐诗/poet.song.162000.json','["兢業初無蹊徑，緝熙本有光明。", "自覺自知自信，何思何慮何營。", "鏡裏人情喜怒，空中雲氣紆縈。", "孔訓於仁用力，箕疇王道平平。"]'),
('47d4525e-d4c5-455e-8b32-0dc598f781d2','明融  其一','楊簡','宋','宋诗','song-poetry','','[]','妙妙融明樂未央，山川人物獻文章。',64,'全唐诗/poet.song.162000.json','["妙妙融明樂未央，山川人物獻文章。", "縱橫組織無邊巧，變化委蛇不可商。", "北麓林塘秋靜瑩，南山景氣曉蒼茫。", "欲吟無句方徐步，忽報相從注早香。"]'),
('da895f2b-6532-40dc-99e5-8a76b83b4e71','明融  其二','楊簡','宋','宋诗','song-poetry','','[]','妙絕虛明萬里光，融融靜靜渺茫茫。',64,'全唐诗/poet.song.162000.json','["妙絕虛明萬里光，融融靜靜渺茫茫。", "其間變化無蹤跡，却有方圓與短長。", "仰首看空閒顧盼，聚頭竊語足商量。", "竹稍忽作瀟然韻，正是雲門第一章。"]'),
('c10b8370-f892-468a-a255-e931e7ca29c5','明融  其三','楊簡','宋','宋诗','song-poetry','','[]','浄几橫琴晚寒，梅花落在絃間。',28,'全唐诗/poet.song.162000.json','["浄几橫琴晚寒，梅花落在絃間。", "我欲清吟無句，轉煩門外青山。"]'),
('6b124ef3-bce1-4a0a-8a9e-039924b3cce4','詠春','楊簡','宋','宋诗','song-poetry','','[]','日日看山不厭山，白雲吞吐翠微間。',32,'全唐诗/poet.song.162000.json','["日日看山不厭山，白雲吞吐翠微間。", "靜明光裏無窮樂，只是令人下語難。"]'),
('db658fe4-436e-46ac-8ebc-a456ef2865c5','丙子夏偶書  其一','楊簡','宋','宋诗','song-poetry','','[]','風從槐市過來涼，絲竹金英尚在堂。',64,'全唐诗/poet.song.162000.json','["風從槐市過來涼，絲竹金英尚在堂。", "惟有慈湖親聽得，近來吾黨亦專芳。", "如何鑽仰徒勞苦，要說精粗與短長。", "神氣風霆俱是教，四時代謝儘彰彰。"]'),
('38fd0691-2f98-4f9c-a4d7-51005d5a869e','丙子夏偶書  其二','楊簡','宋','宋诗','song-poetry','','[]','行年七十有六，隨世名言則然。',88,'全唐诗/poet.song.162000.json','["行年七十有六，隨世名言則然。", "應酬衮衮萬狀，變化離坎坤乾。", "人情曲折參錯，動靜多寡後先。", "孰有孰虛孰實，無高無下無邊。", "清明靡所不照，一語不可措焉。", "先聖爲是發憤忘食，某也何敢空度歲年。"]'),
('45e04b09-0005-4175-a33e-03885693fd0d','偶作  其一','楊簡','宋','宋诗','song-poetry','','[]','此道元來即是心，人人拋去却求深。',32,'全唐诗/poet.song.162000.json','["此道元來即是心，人人拋去却求深。", "不知求却翻成外，若是吾心底用尋。"]'),
('1e5ac0a9-a188-48b2-ab1d-92e0a485b473','偶作  其二','楊簡','宋','宋诗','song-poetry','','[]','誰省吾心即是仁，荷他先哲爲人深。',32,'全唐诗/poet.song.162000.json','["誰省吾心即是仁，荷他先哲爲人深。", "分明說了猶疑在，更問如何是本心。"]'),
('c9b015d4-c7ab-4cbf-b015-0b0eaee690eb','偶作  其三','楊簡','宋','宋诗','song-poetry','','[]','若問如何是此心，能思能索又能尋。',32,'全唐诗/poet.song.162000.json','["若問如何是此心，能思能索又能尋。", "汝心底用他人說，只是尋常用底心。"]'),
('dd22cf71-4749-4228-a0f1-45ba7c394ee9','偶作  其四','楊簡','宋','宋诗','song-poetry','','[]','此心用處沒蹤由，擬待思量是討愁。',32,'全唐诗/poet.song.162000.json','["此心用處沒蹤由，擬待思量是討愁。", "但只事親兼事長，只如此去莫回頭。"]'),
('f2696b82-7b60-40e9-a3e4-69adc0dc4053','偶作  其五','楊簡','宋','宋诗','song-poetry','','[]','可笑禪流錯用心，或思或罷兩追尋。',32,'全唐诗/poet.song.162000.json','["可笑禪流錯用心，或思或罷兩追尋。", "窮年費煞精神後，陷入泥途轉轉深。"]'),
('db627f6e-520f-483f-8447-ded244dc1a44','偶作  其六','楊簡','宋','宋诗','song-poetry','','[]','心裏虛明著太空，乾坤日月總包籠。',32,'全唐诗/poet.song.162000.json','["心裏虛明著太空，乾坤日月總包籠。", "從來箇片閒田地，難定西南與北東。"]'),
('26cf20ef-35e1-4c1d-9ceb-328613e63c54','偶作  其七','楊簡','宋','宋诗','song-poetry','','[]','莫將愛敬復雕鎸，一片真純幸自全。',32,'全唐诗/poet.song.162000.json','["莫將愛敬復雕鎸，一片真純幸自全。", "待得將心去鈎索，旋栽荆棘向芝田。"]'),
('3960024d-c07b-4664-aaac-aec97c5aa9b2','偶作  其八','楊簡','宋','宋诗','song-poetry','','[]','勿認胸中一團氣，一團氣裏空無地。',32,'全唐诗/poet.song.162000.json','["勿認胸中一團氣，一團氣裏空無地。", "既空何地更何義，此無廣狹無一二。"]'),
('85b790b6-3d8d-45a2-8d42-5ea4dffd5ff4','偶作  其九','楊簡','宋','宋诗','song-poetry','','[]','惡習起時能自訟，誰知此是天然勇。',32,'全唐诗/poet.song.162000.json','["惡習起時能自訟，誰知此是天然勇。", "多少禪流妄詆訶，不知此勇元不動。"]'),
('112987e4-8edc-4e35-a6e9-2865ccb48fa0','偶作  其一○','楊簡','宋','宋诗','song-poetry','','[]','囘心三月不違仁，已後元曾小失真。',32,'全唐诗/poet.song.162000.json','["囘心三月不違仁，已後元曾小失真。", "一片雪花輕著水，冥冥不復省漓醇。"]'),
('aabc0ae0-b749-4c4d-9ce6-e543b379e223','偶作  其一一','楊簡','宋','宋诗','song-poetry','','[]','有心切勿去鈎玄，鈎得玄來在外邊。',80,'全唐诗/poet.song.162000.json','["有心切勿去鈎玄，鈎得玄來在外邊。", "何以罷休依本分，孝慈忠信乃天然。", "此天然處不亦妙，費盡思量却不到。", "有時父召急趨前，不覺不知造淵奧。", "此時合勒承認狀，從古癡頑何不曉。"]'),
('c2916518-aa08-42b1-8746-fc95771f534a','偶作  其一二','楊簡','宋','宋诗','song-poetry','','[]','曩疑先聖嗇於言，何不明明細細傳。',32,'全唐诗/poet.song.162000.json','["曩疑先聖嗇於言，何不明明細細傳。", "今醒從前都錯認，更加詳後即紛然。"]'),
('1791d4b8-f937-4cc0-83bd-b66cbf97fe9a','偶作  其一三','楊簡','宋','宋诗','song-poetry','','[]','夫子文章不可爲，從心到口沒參差。',32,'全唐诗/poet.song.162000.json','["夫子文章不可爲，從心到口沒參差。", "咄哉韓子休汙我，却道詩葩與易奇。"]'),
('9a60e3b9-3fdc-4ab3-9959-57582e01f211','偶作  其一四','楊簡','宋','宋诗','song-poetry','','[]','雪月風花總不知，雕奇鏤巧學支離。',32,'全唐诗/poet.song.162000.json','["雪月風花總不知，雕奇鏤巧學支離。", "四時多少閒光景，無箇閒人領略伊。"]'),
('5a45c073-4a67-46b3-8d46-697af04ae595','偶作  其一五','楊簡','宋','宋诗','song-poetry','','[]','勿學唐人李杜癡，作詩雖作古人詩。',32,'全唐诗/poet.song.162000.json','["勿學唐人李杜癡，作詩雖作古人詩。", "世傳李杜文章伯，問著關雎恐不知。"]'),
('9bac9ecc-df6b-4f45-89a6-92ba7d835def','偶作  其一六','楊簡','宋','宋诗','song-poetry','','[]','詩癡正自不煩攻，只爲英才輒墮中。',32,'全唐诗/poet.song.162000.json','["詩癡正自不煩攻，只爲英才輒墮中。", "今日已成風俗後，後生箇箇入樊籠。"]'),
('72b1700a-65bc-4749-9eec-1af058fab902','偶作  其一七','楊簡','宋','宋诗','song-poetry','','[]','儒風一變至於道，此是堯夫未識儒。',32,'全唐诗/poet.song.162000.json','["儒風一變至於道，此是堯夫未識儒。", "除却儒風如更有，將馿騎了復求馿。"]'),
('0a0b2075-6d98-4f3b-be83-fd10db31830b','偶作  其一八','楊簡','宋','宋诗','song-poetry','','[]','道心非動靜，學者何難易。',144,'全唐诗/poet.song.162000.json','["道心非動靜，學者何難易。", "癡雲欲掃除，迅霆無異擬。", "無妄而徵疾，勿藥斯有喜。", "一輪秋月明，云爲豈思慮。", "太極奚可圖，可圖非太極。", "矧復贅無極，哀哉可太息。", "何不觀古聖，一一已默識。", "胡爲復作圖，交擾而曲屈。", "是孰知五行，五行皆妙質。", "不可離合論，渾渾體自一。", "安得孔子生，邪說俱蕩滌。", "哀哉復哀哉，太息復太息。"]'),
('5077784a-cde4-4364-9661-4fdbc417c8e3','偶作  其一九','楊簡','宋','宋诗','song-poetry','','[]','當敬不敬謂之悖，當正不正謂之諛。',32,'全唐诗/poet.song.162000.json','["當敬不敬謂之悖，當正不正謂之諛。", "是中適莫俱難著，意態微生已覺疏。"]'),
('07b8c8a2-fc2c-4982-b55a-6db01d9f4775','丁丑詠春偶成  其一','楊簡','宋','宋诗','song-poetry','','[]','葉葉枝枝都教女，紅紅白白儘呈人。',64,'全唐诗/poet.song.162000.json','["葉葉枝枝都教女，紅紅白白儘呈人。", "如何自古知音少，方到而今得句新。", "既遣鳥啼頻囑咐，又令鶴舞出精神。", "便將天作一張紙，難畫慈湖二月春。"]'),
('8c13617c-4478-46c4-994d-0b485d058925','丁丑詠春偶成  其二','楊簡','宋','宋诗','song-poetry','','[]','天造慈湖迥出塵，無冬無夏只長春。',64,'全唐诗/poet.song.162000.json','["天造慈湖迥出塵，無冬無夏只長春。", "四山桃李圍新錦，一邑風光讓絕倫。", "澗水簷旁談妙理，山禽柳外說天真。", "杏壇無限難傳意，付與憑欄寓目人。"]'),
('34787bdb-c662-4891-9939-ada44d7f0190','丁丑偶書  其一','楊簡','宋','宋诗','song-poetry','','[]','新年七十七，是虛不是實。',48,'全唐诗/poet.song.162000.json','["新年七十七，是虛不是實。", "我心包太空，有無混然一。", "比日腑臟作，示病而無疾。", "憑欄拱翠峰，可詠不可詰。"]'),
('93b10667-b93f-4ec9-bfb7-dac8d6ab87fe','丁丑偶書  其二','楊簡','宋','宋诗','song-poetry','','[]','物物皆吾體，心心是我思。',48,'全唐诗/poet.song.162000.json','["物物皆吾體，心心是我思。", "四時非代謝，萬說不支離。", "澗水談顔樂，松風詠晳詞。", "仲尼親許可，實語斷非欺。"]'),
('3df64960-b1e9-4244-b0b6-a3f179678e36','乾道撫琴有作','楊簡','宋','宋诗','song-poetry','','[]','蕭蕭指下生秋風，漸漸幽響颼寒空。',184,'全唐诗/poet.song.162000.json','["蕭蕭指下生秋風，漸漸幽響颼寒空。", "月明夜氣清入骨，何處仙佩摇丁東。", "野鶴驚起舞，流水噎復鳴。", "一唱三歎意未已，幽幽話出太古情。", "龍吟虎嘯遽神怪，千山萬壑風雨晦。", "海濤震蕩林木響，亂撒金盤冰雹碎。", "和氣囘春陽，縹緲孤鸞翔。", "三江五湖烟水闊，波聲飋飋鳴漁榔。", "悲猿臨澗欲渡不敢渡，但聞澗下蕭颯松風長。", "閒雲曳碧落，勢去還囘薄。", "神仙恍惚無定所，微吟似欲止所作。", "御風一笑歸蓬瀛，猶有餘音遶寥廓。"]'),
('f2a6da01-9635-429c-b716-de0d70540f14','侍象山先生遊西湖舟中胥必先周元忠弈  其一','楊簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百里平湖十里堤，新蕪苒苒綠齊齊。',64,'全唐诗/poet.song.162000.json','["百里平湖十里堤，新蕪苒苒綠齊齊。", "水晶宮裏光風靜，碧玉壺中遠近迷。", "局外有棋輸與我，口邊得句豈須題。", "流鶑却會幽人意，故向人間一兩啼。"]'),
('8f3d7a42-c3ab-4f48-9593-1c77b5ee2ecb','侍象山先生遊西湖舟中胥必先周元忠弈  其二','楊簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淺紅深翠綠高低，各出精神不肯齊。',64,'全唐诗/poet.song.162000.json','["淺紅深翠綠高低，各出精神不肯齊。", "山色好時新雨沐，湖光遠處淡烟迷。", "不知醉後無言句，逼近前來乞品題。", "我亦未能勤領略，只煩鶑囀與烏啼。"]'),
('066fd48a-f565-4a00-8a6e-a8a3b670ceaf','偶成  其一','楊簡','宋','宋诗','song-poetry','','[]','春入園林種種奇，化工施巧太精微。',64,'全唐诗/poet.song.162000.json','["春入園林種種奇，化工施巧太精微。", "山禽說我胸中事，烟柳藏他物外機。", "既遣杏桃呈似了，又令蜂蝶近前飛。", "如何有眼無人見，只解西郊看落暉。"]'),
('e57cf540-237e-4179-9781-865658ab7da0','偶成  其二','楊簡','宋','宋诗','song-poetry','','[]','脚踏和風步步春，石魚樓上等閒人。',64,'全唐诗/poet.song.162000.json','["脚踏和風步步春，石魚樓上等閒人。", "興來衝口都成句，眼去遊山不動塵。", "李白誰知他意思，桃紅漏洩我精神。", "忽逢借問難酬對，只恐流鶑說得真。"]'),
('f35475da-12cf-4bb0-bdab-930af97ec7ae','偶成  其三','楊簡','宋','宋诗','song-poetry','','[]','桃紅柳綠簇春華，燕語鶑啼盡日佳。',32,'全唐诗/poet.song.162000.json','["桃紅柳綠簇春華，燕語鶑啼盡日佳。", "誰信聲聲沂水詠，又知處處杏壇家。"]'),
('869757be-506c-471b-a74d-2ad06c3319ce','偶成  其四','楊簡','宋','宋诗','song-poetry','','[]','可惜有生都衮衮，如何終日只紛紛。',32,'全唐诗/poet.song.162000.json','["可惜有生都衮衮，如何終日只紛紛。", "滿前妙景無人識，到處清音獨我聞。"]'),
('3cbca698-9e98-4dea-b433-2afb2138eaab','偶成  其五','楊簡','宋','宋诗','song-poetry','','[]','我吟詩處鶑啼處，我起行時蝶舞時。',32,'全唐诗/poet.song.162000.json','["我吟詩處鶑啼處，我起行時蝶舞時。", "踏著此機何所似，陶然如醉又如癡。"]'),
('dd26cec5-b960-438b-864b-dae8835a7f06','夜蚊','楊簡','宋','宋诗','song-poetry','','[]','夜蚊告教一何奇，妙語都捐是與非。',64,'全唐诗/poet.song.162000.json','["夜蚊告教一何奇，妙語都捐是與非。", "偏向耳旁呈雅奏，直來面上發深機。", "惜哉頑固終難入，多是聾迷聽者希。", "費盡諄諄無領略，更煩明月到窗扉。"]'),
('e3bcde61-b1d3-4e5e-9700-9b90123f7f86','奉檄往哭象山復會葬及歸自金溪留宿本縣仙樂觀歸而作是詩  其一','楊簡','宋','宋诗','song-poetry','','[]','膏露奚爲降，傳聞不偶然。',48,'全唐诗/poet.song.162000.json','["膏露奚爲降，傳聞不偶然。", "兩晨呈瑞處，萬葉遶爐前。", "嘗審如飴味，誰操動物權。", "天權非遠近，不可向人宣。"]'),
('08ecf55f-352e-4814-ab89-009294034722','奉檄往哭象山復會葬及歸自金溪留宿本縣仙樂觀歸而作是詩  其二','楊簡','宋','宋诗','song-poetry','','[]','道士清晨喜告余，昨朝膏露降濡濡。',212,'全唐诗/poet.song.162000.json','["道士清晨喜告余，昨朝膏露降濡濡。", "夜來輿從留山觀，此瑞端呈邑大夫。", "我聞之言半疑信，踏破曉光上孤峻。", "巍然古殿漢天師，水遶丹爐葉明潤。", "旁觀復折取以前，連日祥應詎偶然。", "我亦嘗審甘如飴，是誰執此變化權。", "益信人心自靈妙，莫執人神定名號。", "此機不動萬象沈，此機一發靡不到。", "此機不屬上下中，此機非西南北東。", "此機無遠亦無近，此機至正而大公。", "此機夫人之所有，何不自貴自善守。", "寸善微萌天地知，小惡開元禍隨後。", "皇天無親亦無常，願言孜孜兢兢悠久而無疆。"]'),
('612c77b5-c654-459c-aec8-93116d5e18a5','張時可惠示甲乙藁','楊簡','宋','宋诗','song-poetry','','[]','凌晨带月上竹輿，荷君封送兩卷書。',164,'全唐诗/poet.song.162000.json','["凌晨带月上竹輿，荷君封送兩卷書。", "朦朧未省何文字，中道曉色來徐徐。", "乃是約齋甲乙藁，驚喜遽讀味新好。", "一篇一篇奇益奇，閒姿雅態雲生島。", "石泉竹月風蕭蕭，斗牛劍氣秋空高。", "意度橫出不可速，灑灑落落真詩豪。", "慇懃厚意何以報，熟復謹藏永爲好。", "大雅不作繼者誰，恐非少陵所可到。", "君心自是思無邪，何假於中植奇葩。", "男兒要當追配古聖賢，豈能更與凡卉爭春華。"]'),
('7599e180-7011-403c-b14c-7b193ff8c54d','富春龍門','楊簡','宋','宋诗','song-poetry','','[]','桑麻迤邐入高原，級級差差水落田。',64,'全唐诗/poet.song.162000.json','["桑麻迤邐入高原，級級差差水落田。", "樹色自分深淺綠，山光都在淡濃烟。", "竹輿漸近鐘鳴處，詩句來從鳥語邊。", "又是一番新樣致，如何寫得十分全。"]'),
('80885cb9-5b70-4c41-9f02-fb637e4c161f','丹桂','楊簡','宋','宋诗','song-poetry','','[]','世眼紛紛丹與黄，廣寒宮裏亦如常。',64,'全唐诗/poet.song.162000.json','["世眼紛紛丹與黄，廣寒宮裏亦如常。", "目前不作兩般見，筆下方騰萬丈光。", "且莫錙銖深淺色，也休斤兩淡濃香。", "靈根已入詩人手，不許嫦娥擅此芳。"]'),
('2a071d20-b5a8-4ef2-8e61-12e1c8d731ea','和胡鼓院郊臺致齋即事  其一','楊簡','宋','宋诗','song-poetry','','[]','聯篇傑作大音稀，雲朶低垂向巧枝。',64,'全唐诗/poet.song.162000.json','["聯篇傑作大音稀，雲朶低垂向巧枝。", "鈍學久嗟人去速，癡腸一任句來遲。", "斷無錦向詩中織，但有春從筆底滋。", "盡日齋宮雲聚散，不知步武是誰移。"]'),
('8c1624c0-0317-4b14-88a7-e963cf46d43d','和胡鼓院郊臺致齋即事  其二','楊簡','宋','宋诗','song-poetry','','[]','虛口徐行上短廊，拂簷巾角觸山光。',64,'全唐诗/poet.song.162000.json','["虛口徐行上短廊，拂簷巾角觸山光。", "高簷踴躍爭奇怪，巨笋逢迎效短長。", "山木剪裁青玉色，茶甌問答素馨香。", "是中空洞無邊際，收拾山川盡括囊。"]'),
('da1f2eb5-dbca-4923-945b-7a65de59aef0','和陳大著追九日之集','楊簡','宋','宋诗','song-poetry','','[]','起興家山翠作圍，紫宸垂旨未容歸。',64,'全唐诗/poet.song.162000.json','["起興家山翠作圍，紫宸垂旨未容歸。", "千峰來獻無窮妙，萬影相從不敢違。", "碧玉壺中丹葉舞，水晶宮裏白雲飛。", "憑欄相與謀荒政，第一言無罪歲饑。"]'),
('341c2e03-bd78-4eae-950b-9ef3999ad4c4','題將作軍器二監','楊簡','宋','宋诗','song-poetry','','[]','出入雲從二監中，新來盤薄翠玲瓏。',64,'全唐诗/poet.song.162000.json','["出入雲從二監中，新來盤薄翠玲瓏。", "飽觀大景金星洞，喚作慈湖鬢雪翁。", "石怪山奇誰造化，鳶飛魚躍我家風。", "只今笑語難聞見，灼與人心萬古同。"]'),
('8eb2d27e-dc2c-4b5d-b212-cc454164b0d5','伏蒙提舉秘書郎中以留題縣驛新篇封示惻隠惠愛之意自然著見可謂發情止義無愧古作道中不得即具申謝之儀夜還舍秉燭亟次崇韻庸見不敢虛辱大賜之誠非敢爲文某惶恐敬上','楊簡','宋','宋诗','song-poetry','','[]','我學如畝澮，纖流未距川。',204,'全唐诗/poet.song.162000.json','["我學如畝澮，纖流未距川。", "何如作難邑，衮衮膏火煎。", "學力未純固，誠不能不遷。", "所喪逮尋丈，所補無塵涓。", "是則百煉金，無復畏巨燃。", "不聞曾氏子，兢兢而虔虔。", "一貫融終始，虛明萬慮捐。", "此道甚簡易，勞苦無禹胼。", "體妙用亦妙，揚州十萬纏。", "不熟愧稊稗，未免世累攣。", "使者臨舊治，盛禮修同年。", "所道惟政事，握手意留連。", "車行眼偏矚，粟畦暨麥阡。", "父老亟來迎，喜色津津然。", "我非當世才，亦復見謂賢。", "臨違語益稠，不覺膝自前。", "更願所以諳，教我理婚田。"]'),
('5f2b0a6a-ce21-421a-b0c5-063422c6ff0d','賀朱倅','楊簡','宋','宋诗','song-poetry','','[]','舉杯話別幾時逢，此事分明鑑象中。',64,'全唐诗/poet.song.162000.json','["舉杯話別幾時逢，此事分明鑑象中。", "到處風光無遠近，毋言易道有西東。", "輕輕衣濕梅坡雨，款款舟行柳岸風。", "忽憶從遊談笑處，蘇公堤上躍花驄。"]'),
('75a3b3b4-8e56-4b6d-8689-26bca42c1975','送章大著出守衡陽','楊簡','宋','宋诗','song-poetry','','[]','濟濟衆賢俱，徐徐五馬驅。',48,'全唐诗/poet.song.162000.json','["濟濟衆賢俱，徐徐五馬驅。", "中司親鴈序，南岳佩魚符。", "吳楚從今異，參辰幸小殊。", "他時羣玉聚，相與話踟躕。"]'),
('25080a45-a667-4f31-bc20-4ef1fe99401b','賀王使君  其一','楊簡','宋','宋诗','song-poetry','','[]','南風薰兮，如其仁兮。',22,'全唐诗/poet.song.162000.json','["南風薰兮，如其仁兮。", "盎乎惠和，物之樂且欣兮。"]'),
('8c168a4d-53d6-4430-a13f-97c392bdc84b','賀王使君  其二','楊簡','宋','宋诗','song-poetry','','[]','南風薰兮，人之近兮。',25,'全唐诗/poet.song.162000.json','["南風薰兮，人之近兮。", "天溫厚之氣，以幸吾鄱江之民兮。"]'),
('6b6218f2-b670-4f14-bd49-a96ee14278ac','賀王使君  其三','楊簡','宋','宋诗','song-poetry','','[]','南風薰兮，於誕之辰兮。',23,'全唐诗/poet.song.162000.json','["南風薰兮，於誕之辰兮。", "何以壽之，有南山之椿兮。"]'),
('d6763f19-0f73-4dfe-83ce-ae5e8c16d15f','賀王使君  其四','楊簡','宋','宋诗','song-poetry','','[]','南風薰兮，我不靳兮。',24,'全唐诗/poet.song.162000.json','["南風薰兮，我不靳兮。", "無請弗獲，以幸吾樂平之民兮。"]'),
('b3650908-d7d7-4316-9291-1a4fc4c0fb95','上耿泉生朝  其一','楊簡','宋','宋诗','song-poetry','','[]','瞻彼雲臺，有那其武。',20,'全唐诗/poet.song.162000.json','["瞻彼雲臺，有那其武。", "祝阿發迹，中興元輔。"]'),
('a5972dff-73d3-4c93-b6fa-873c0cebee4f','上耿泉生朝  其二','楊簡','宋','宋诗','song-poetry','','[]','歷世藪卜，有孫惟良。',20,'全唐诗/poet.song.162000.json','["歷世藪卜，有孫惟良。", "愷悌君子，之紀之綱。"]'),
('9837ff81-b9a8-4bd3-8dbe-c0e7d9d4f129','上耿泉生朝  其三','楊簡','宋','宋诗','song-poetry','','[]','柔亦不茹，剛亦不吐。',20,'全唐诗/poet.song.162000.json','["柔亦不茹，剛亦不吐。", "有志而寬，夫誰敢侮。"]'),
('af282270-05e2-4121-a079-88e6855fa0cf','上耿泉生朝  其四','楊簡','宋','宋诗','song-poetry','','[]','天子曰於，亟來輔予。',30,'全唐诗/poet.song.162000.json','["天子曰於，亟來輔予。", "寘彼周行，爲上大夫。", "迺眷西顧，畀之節符。"]'),
('4915814f-f8f1-4413-8b72-c466d971e332','上耿泉生朝  其五','楊簡','宋','宋诗','song-poetry','','[]','是司九府，爰總數路。',25,'全唐诗/poet.song.162000.json','["是司九府，爰總數路。", "爰究爰度，阜豐化布，國用是裕。"]'),
('4c9640b5-54cf-4311-a226-1dcea012d346','上耿泉生朝  其六','楊簡','宋','宋诗','song-poetry','','[]','江左矜刑，獄平訟清。',25,'全唐诗/poet.song.162000.json','["江左矜刑，獄平訟清。", "惟清惟明，民用以寧，姦宄亦懲。"]'),
('22d1b1ae-4ab7-454c-b24b-7ed2ec73ca64','上耿泉生朝  其七','楊簡','宋','宋诗','song-poetry','','[]','迺撫徽人，惠綏千里。',25,'全唐诗/poet.song.162000.json','["迺撫徽人，惠綏千里。", "匪亟匪除，匪作匪異，而郡亦治。"]'),
('8cd25c65-3e55-4f61-8b80-94ea8b19225a','上耿泉生朝  其八','楊簡','宋','宋诗','song-poetry','','[]','泉課復艱，屬任斯難。',25,'全唐诗/poet.song.162000.json','["泉課復艱，屬任斯難。", "□□斧扆，節至累頒，公毋憚煩。"]'),
('5349fac9-e90d-4046-b3d2-e08e3c5bb218','上耿泉生朝  其九','楊簡','宋','宋诗','song-poetry','','[]','洎陽爲邑，實惟所臨。',40,'全唐诗/poet.song.162000.json','["洎陽爲邑，實惟所臨。", "寬簡雖至，威信亦深。", "敢不兢兢，治所賦金。", "以謹以程，以恪以忱。"]'),
('10918272-0087-4dcb-912a-bcd268459781','上耿泉生朝  其一○','楊簡','宋','宋诗','song-poetry','','[]','惟公誕彌，良月惟時。',55,'全唐诗/poet.song.162000.json','["惟公誕彌，良月惟時。", "地數盈成，夢維熊羆。", "何以壽之，南山維基，松柏維滋。", "毋祝毋祈，公自有之。", "某也作詩，于以敬之。"]'),
('6699031f-af4e-4bae-9b6c-79517a7292d9','上鄧憲生辰  其一','楊簡','宋','宋诗','song-poetry','','[]','維彼岷源，維深且長。',20,'全唐诗/poet.song.162000.json','["維彼岷源，維深且長。", "是爲大江，潤澤南方。"]'),
('7983aa65-8340-4666-b13f-522353eb2c61','上鄧憲生辰  其二','楊簡','宋','宋诗','song-poetry','','[]','維江之東，有賢使者。',20,'全唐诗/poet.song.162000.json','["維江之東，有賢使者。", "惠德似之，溥澤潤下。"]'),
('83c03a46-3e8d-416c-8336-aeaf8101f0d9','上鄧憲生辰  其三','楊簡','宋','宋诗','song-poetry','','[]','使者維何，有祖高密。',20,'全唐诗/poet.song.162000.json','["使者維何，有祖高密。", "雲臺第一，流芳泌泌。"]'),
('18e3c626-34e9-4a7c-b9a8-7915cc9387e6','上鄧憲生辰  其四','楊簡','宋','宋诗','song-poetry','','[]','有孫維良，秉德正方。',20,'全唐诗/poet.song.162000.json','["有孫維良，秉德正方。", "天子曰於，寘彼周行。"]'),
('0660a7b8-266c-48d5-b98d-6b93670713ff','上鄧憲生辰  其五','楊簡','宋','宋诗','song-poetry','','[]','古之遺直，亟輔予德。',20,'全唐诗/poet.song.162000.json','["古之遺直，亟輔予德。", "疾風勁草，歲寒松柏。"]'),
('13e73a95-94f0-4508-8667-64ef72f7fafc','上鄧憲生辰  其六','楊簡','宋','宋诗','song-poetry','','[]','迺眷西顧，金節畀之。',20,'全唐诗/poet.song.162000.json','["迺眷西顧，金節畀之。", "禮樂光華，亦王近畿。"]'),
('2cb90ba3-f889-4276-b368-df0278e534d9','上鄧憲生辰  其七','楊簡','宋','宋诗','song-poetry','','[]','欽哉祥刑，克寬克明。',20,'全唐诗/poet.song.162000.json','["欽哉祥刑，克寬克明。", "民罹旱虐，焦勞發情。"]'),
('80a7b468-d982-45f1-aade-cc385d442b7e','上鄧憲生辰  其八','楊簡','宋','宋诗','song-poetry','','[]','民饑毋恐，惠澤方湧。',20,'全唐诗/poet.song.162000.json','["民饑毋恐，惠澤方湧。", "適兼郡符，民有天寵。"]'),
('111d9db8-c3ec-416a-bc0c-d3ff1e91cc40','上鄧憲生辰  其九','楊簡','宋','宋诗','song-poetry','','[]','首白蠲租，寬博其模。',20,'全唐诗/poet.song.162000.json','["首白蠲租，寬博其模。", "大公靡私，匪畏匪拘。"]'),
('b20502c7-d4e3-4204-8f56-e9a7d29b8535','上鄧憲生辰  其一○','楊簡','宋','宋诗','song-poetry','','[]','僵者起之，骨者肉之。',20,'全唐诗/poet.song.162000.json','["僵者起之，骨者肉之。", "知畿千萬，父之母之。"]'),
('9fc92d1c-7ca2-4702-b037-d70c985bf1a1','上鄧憲生辰  其一一','楊簡','宋','宋诗','song-poetry','','[]','洎陽爲邑，罹旱則甚。',20,'全唐诗/poet.song.162000.json','["洎陽爲邑，罹旱則甚。", "故維私邑，蒙澤亦甚。"]'),
('68a8e4ea-4c53-4c47-9612-84c5949707b2','上鄧憲生辰  其一二','楊簡','宋','宋诗','song-poetry','','[]','維公誕彌，端月維時。',50,'全唐诗/poet.song.162000.json','["維公誕彌，端月維時。", "夢維熊羆，何以壽之。", "南山維基，大椿植之。", "毋祝毋祈，公自有之。", "某也作頌，于以敬之。"]'),
('1b6ea714-224c-4129-a187-772d34069b02','代馮似宗壽樓文昌  其一','楊簡','宋','宋诗','song-poetry','','[]','維山四明，涵奇孕英。',50,'全唐诗/poet.song.162000.json','["維山四明，涵奇孕英。", "或曰降神，爲今甫申。", "倬彼雲漢，昭囘其文。", "鳳鳴朝陽，决河崑崙。", "代天而言，粹其德音。"]'),
('68ea9854-2a81-400a-851c-73e4d1b209db','代馮似宗壽樓文昌  其二','楊簡','宋','宋诗','song-poetry','','[]','補衮大手，石色五有。',40,'全唐诗/poet.song.162000.json','["補衮大手，石色五有。", "砥柱中流，屹屹其守。", "爲人所難，一辭萬口。", "文昌大名，太山北斗。"]'),
('1471a2bc-257d-494e-8e8a-d04474f60864','代馮似宗壽樓文昌  其三','楊簡','宋','宋诗','song-poetry','','[]','雲歸星駕，持麾東下。',40,'全唐诗/poet.song.162000.json','["雲歸星駕，持麾東下。", "乘流御風，琳宮燕暇。", "山水清暉，親戚情話。", "不間遐賤，如某某者。"]'),
('e7ef5295-8414-48e5-9e45-bd0f2a06e368','代馮似宗壽樓文昌  其四','楊簡','宋','宋诗','song-poetry','','[]','肆筵設席，獲教蒙益。',30,'全唐诗/poet.song.162000.json','["肆筵設席，獲教蒙益。", "繾綣綢繆，問遺不息。", "萬金良藥，再生大德。"]'),
('74df97f1-1d26-47f9-ac18-ee845d1d8419','代馮似宗壽樓文昌  其五','楊簡','宋','宋诗','song-poetry','','[]','陽復之望，惟公誕辰。',30,'全唐诗/poet.song.162000.json','["陽復之望，惟公誕辰。", "何以貺之，秉國之鈞。", "何以壽之，南山之椿。"]'),
('c9dc2c8c-ff0f-4a79-a181-ae3c962e56a7','嘉定改元久旱得雨詩呈張令君  其一','楊簡','宋','宋诗','song-poetry','','[]','底事焦勞偃室中，耕農臯月未施工。',64,'全唐诗/poet.song.162000.json','["底事焦勞偃室中，耕農臯月未施工。", "兩龍會合千山暗，數日霖零百里同。", "舉手盡稱知縣雨，何心領略大王風。", "再生天造奚爲報，海有窮時此不窮。"]'),
('4cc0082d-bc4c-4aa5-bdeb-1a039ef84b89','嘉定改元久旱得雨詩呈張令君  其二','楊簡','宋','宋诗','song-poetry','','[]','兩日長憂積滿中，感深令禱格天工。',64,'全唐诗/poet.song.162000.json','["兩日長憂積滿中，感深令禱格天工。", "欣欣處處人人喜，渺渺茫茫畝畝同。", "不至傷如無極雅，行當改賦黍離風。", "邑民頌德千和萬，毫楮如何可以窮。"]'),
('b611811a-ee9a-4751-9d0d-ae50021d2dc9','喜雪次陳書韻','楊簡','宋','宋诗','song-poetry','','[]','簾垂不覺夜窗明，清曉從容始下平。',64,'全唐诗/poet.song.162000.json','["簾垂不覺夜窗明，清曉從容始下平。", "推戶忽驚瓊作地，登樓笑指玉爲京。", "暫停枰上猶賢弈，來作絃間太古聲。", "甚念衣單塵甑者，毋令彼此有虧成。"]'),
('3e06ca67-c8e8-42ff-bfca-892d11a58670','蒙檢討封送所與諸同朝倡酬盛作某老拙愧後礫某祗拜以呈','楊簡','宋','宋诗','song-poetry','','[]','原廟陪祠曉色開，從容復指綴衣來。',64,'全唐诗/poet.song.162000.json','["原廟陪祠曉色開，從容復指綴衣來。", "花填輦路驚何早，春向皇都特亟囘。", "聲贊俯躬千冠带，香浮夾道萬樓臺。", "傳聞歸燕隆親睦，天上雲韶拱玉杯。"]'),
('4fa796cd-9911-4d8f-b3ed-2b4344e53245','壽倅生辰  其一','楊簡','宋','宋诗','song-poetry','','[]','州家和氣藹新春，得所親賢蔚豹文。',64,'全唐诗/poet.song.162000.json','["州家和氣藹新春，得所親賢蔚豹文。", "天遣星辰爲二屏，我將風月作三分。", "碧梧翠竹來華胄，岳鳳溟鯤駕慶雲。", "敬爲同寅香一瓣，願言臭味等爐薰。"]'),
('596d65f9-0de1-4d67-be91-e0a749b5dc58','壽倅生辰  其二','楊簡','宋','宋诗','song-poetry','','[]','方飲屠蘇慶歲元，五開歷草又生賢。',64,'全唐诗/poet.song.162000.json','["方飲屠蘇慶歲元，五開歷草又生賢。", "沈檀鬭品來樽底，梅竹交光闖水邊。", "好把緋魚追舊事，肯同螃蟹話當年。", "聖賢德業歸方寸，穩取崇名上潑天。"]'),
('7566dac5-5eb8-4b27-9c27-9ad0e05cbf3e','賀傳憲生辰  其一','楊簡','宋','宋诗','song-poetry','','[]','奚必生申向嶽求，卧龍山水瑞光浮。',64,'全唐诗/poet.song.162000.json','["奚必生申向嶽求，卧龍山水瑞光浮。", "御風天上騎箕尾，持節人間占斗牛。", "巖下光芒驚走電，筆端河漢瀉新秋。", "精神已致鳴山雨，更願爲霖徧九州。"]'),
('62a6e141-99a9-4b0a-951c-45d77e12653d','賀傳憲生辰  其二','楊簡','宋','宋诗','song-poetry','','[]','鄱陽江上是瀛洲，中有神仙暫此遊。',64,'全唐诗/poet.song.162000.json','["鄱陽江上是瀛洲，中有神仙暫此遊。", "明月襟懷民善頌，浮雲喜怒我無留。", "蟠桃一熟三千歲，玉陛重瞻十二旒。", "諳盡民情並世道，從容借筯屬君侯。"]'),
('c30dc87f-1c2e-475d-9481-ebdfd6bc7aa3','壽趙泉使  其一','楊簡','宋','宋诗','song-poetry','','[]','孕秀鍾鼎慶源長，屬近親依日月光。',64,'全唐诗/poet.song.162000.json','["孕秀鍾鼎慶源長，屬近親依日月光。", "弧矢影侵槐陰綠，熊羆夢入藕花香。", "詩書博雅今平獻，政事精明古趙張。", "九府本根關大體，故分華節到鄱陽。"]'),
('f3f8b021-c57b-4465-a652-6d6a9c0bc5ef','壽趙泉使  其二','楊簡','宋','宋诗','song-poetry','','[]','來迎父老喜相扶，才大能令惠愛孚。',64,'全唐诗/poet.song.162000.json','["來迎父老喜相扶，才大能令惠愛孚。", "十道山川新約束，三樓風月舊規模。", "巖巖氣貌踰嵩華，坦坦胸襟有典謨。", "仰止光華申善頌，何當斂版向庭趨。"]'),
('ba291cb6-d044-427a-9b9f-d8351ae936ff','臨安張帥生辰詩  其一','楊簡','宋','宋诗','song-poetry','','[]','山野書生百不知，同官元有誕辰詩。',64,'全唐诗/poet.song.162000.json','["山野書生百不知，同官元有誕辰詩。", "怪他衙報來何晚，笑我詞源發處遲。", "坐想鼎來門下士，爭雄盡吐腹中奇。", "如何獨有關西後，只解揄揚撫恤辭。"]'),
('88bad885-8a8d-4ed5-8885-f6d8aae3dda0','臨安張帥生辰詩  其二','楊簡','宋','宋诗','song-poetry','','[]','爲恐他人未必知，故推善意入歌詩。',64,'全唐诗/poet.song.162000.json','["爲恐他人未必知，故推善意入歌詩。", "非誇輦轂先彈壓，肯把寬仁作鈍遲。", "不但輿情都喜愜，亦聞天語有褒奇。", "鋪張才美終難了，只此今朝祝頌辭。"]'),
('9c374efe-4cf7-431d-8edb-aef7c4bea1b4','次韻吳機宜','楊簡','宋','宋诗','song-poetry','','[]','十里松湖乘鴈歸，酒鄉近處一驚飛。',32,'全唐诗/poet.song.162000.json','["十里松湖乘鴈歸，酒鄉近處一驚飛。", "頗聞水月中泉石，笑我年來杖履稀。"]'),
('aeffaabc-9762-441b-81c1-201c6c96d7ac','次韻吳天機','楊簡','宋','宋诗','song-poetry','','[]','洪範論時常，心官職雨暘。',48,'全唐诗/poet.song.162000.json','["洪範論時常，心官職雨暘。", "分龍何效竭，負扆久憂傷。", "禾槁幾於白，苗蘇尚可蒼。", "焦勞殊未已，詔旨欲盈箱。"]'),
('3cbef7b2-0619-4721-ab13-084d62f572dd','偶成  其一','楊簡','宋','宋诗','song-poetry','','[]','風雲雨雪自何來，我有乾元大矣哉。',64,'全唐诗/poet.song.162000.json','["風雲雨雪自何來，我有乾元大矣哉。", "萬景出奇供杖履，羣峰環翠拱樓臺。", "興來吟詠誰裁剪，飯罷遊行豈去迴。", "信口道來俱妙妙，教人尋訪幾枝梅。"]'),
('bc517386-dc2d-4eac-b9a4-f8f3463c778a','偶成  其二','楊簡','宋','宋诗','song-poetry','','[]','中堂此景亦不惡，疊嶂窮林張翠幄。',64,'全唐诗/poet.song.162000.json','["中堂此景亦不惡，疊嶂窮林張翠幄。", "有時雲氣間出沒，誰能繪畫得此樂。", "詩人如麻筆如椽，擬待索紙莫莫莫。", "孔子明目尚不見，枉費精神去摸索。"]'),
('6735bb40-4661-4f2e-b6fa-1aa96e909572','示葉元吉','楊簡','宋','宋诗','song-poetry','','[]','元吉三更非鼓聲，慈湖一夜聽鵝鳴。',64,'全唐诗/poet.song.162000.json','["元吉三更非鼓聲，慈湖一夜聽鵝鳴。", "是同是異難聲說，何慮何思自混成。", "爐炭幾番來暖熱，天窗一點吐圓明。", "起來又覩無窮景，水檻澄光萬里清。"]'),
('9f842e29-fc0d-4a67-b4cf-bb5317056519','偶書  其一','楊簡','宋','宋诗','song-poetry','','[]','君子不必相與言，禮樂相示甚昭然。',64,'全唐诗/poet.song.162000.json','["君子不必相與言，禮樂相示甚昭然。", "禮樂相示無一言，物物事事妙莫宣。", "此妙自覺不可傳，可傳非覺亦非玄。", "風雨霜露無非教，哀樂相生先聖篇。"]'),
('07f71a25-5bd3-4a0e-ad20-04bf039f0b6d','偶書  其二','楊簡','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','無聲之樂聞四方，純德孔明即就將。',150,'全唐诗/poet.song.162000.json','["無聲之樂聞四方，純德孔明即就將。", "哀樂相生不可見，衾裘非燠箑非涼。", "秋毫莫大泰山小，殤子上壽彭祖夭。", "入門金作示吾情，於衛磬聲今不了。", "春秋冬夏風雨霜露無非教，胡爲自古學者恁莫曉。", "二十年來寖多曉，是殆天欲亨吾道。", "屈指何止數十人，知及仁守或可保。", "曲禮三千不可思，至哉忠信與孝慈。", "水哉水哉也大奇，孔聖無語孟不知。"]'),
('4f5a8110-2f3d-4cf3-9e1f-46a90c5197e7','偶書  其三','楊簡','宋','宋诗','song-poetry','','[]','自古挑才揚，暨漢多書木。',204,'全唐诗/poet.song.162000.json','["自古挑才揚，暨漢多書木。", "才木雖不同，一音貫吳蜀。", "大道無異同，奚庸析耳目。", "千載覺者幾，邇來帝錫福。", "所知餘百人，宗祖慈湖麓。", "天地吾施生，四時吾繼續。", "日月吾光明，變化吾機軸。", "夫人同此機，宇內皆吾族。", "惟日用不知，被褐而懷玉。", "禮三百三千，是誰不備足。", "父母誰不愛，弟幼誰不育。", "事上誰不敬，對賓誰不肅。", "步步在杏壇，句句香芬馥。", "羣峰穿白雲，碧流響松谷。", "諄諄帝誨我，敢不拱承囑。", "夙興筆此詩，既復從首讀。", "此讀人不聞，惟有庭前菊。"]'),
('4221c510-2a28-4a52-9dbf-f84486367421','慈溪金沙岡歌','楊簡','宋','宋诗','song-poetry','','[]','岡湧金沙來幾里，貼天衮衮白雲裏。',212,'全唐诗/poet.song.162000.json','["岡湧金沙來幾里，貼天衮衮白雲裏。", "雄峰健隴四奔馳，每每囘顧慈溪水。", "慈溪慈溪孝名美，即天之經地之義。", "子思不知萬物我發育，推與聖人自固蔽。", "己自固蔽禍猶小，固蔽後學禍甚大。", "孔子沒近二千年，未有一人措其愆，汩汩昏昏到今日。", "所幸慈溪却不然，灼見子思孟子病同源。", "不得已指其蔽，寫出世所不傳。", "大道蕩蕩而平平，聖訓至明至坦夷，一無荆棘相維纏。", "學子首肯斑斑焉，靜明莊敬非强參。", "學者多覺近二百，事體大勝於已前。", "學徒轉相啟告又未已，大道行乎詎非天。"]'),
('7e26b498-9219-4800-a48c-de3f0b4f9a12','大哉','楊簡','宋','宋诗','song-poetry','','[]','大哉孔聖之言，哀樂相生不可見，傾耳聽之不可聞。',235,'全唐诗/poet.song.162000.json','["大哉孔聖之言，哀樂相生不可見，傾耳聽之不可聞。", "不見乃真見，不聞乃真聞。", "子夏雖曰敢不承，實莫之承終於昏，誤認有子爲師道。", "曾子覺雖小，而悟孔聖之皜皜。", "濯之暴之覺之虧，即濯即暴無不妙。", "子思孟子亦近之，惜乎小覺而大非，其言多害道。", "二子名聲滿天下，指其非者何其少，滋惑後學何時了。", "安得朝家專主孔聖言，盡削異說明大道。", "比一二十年覺者寖寖多，幾二百人其天乎。", "春秋冬夏風雨霜露無非教，風霆流形庶物露生無非教。", "君子不必相與言，雖在畎畝之中，默然即聖無他巧。", "大哉孔聖之至言，罔極之德何以報。"]'),
('0007edb8-0923-49f8-90a6-464d1762d503','謁泰伯廟','楊簡','宋','宋诗','song-poetry','','[]','三以天下讓，先聖謂至德。',48,'全唐诗/poet.song.162000.json','["三以天下讓，先聖謂至德。", "某也拜廟下，太息復太息。", "三辭不難知，泰伯無人識。", "胡爲無得稱，萬象妙無極。"]'),
('ef5196c1-72f3-40dd-9c12-8e7dd71c77bf','偶作','楊簡','宋','宋诗','song-poetry','','[]','處處青山人不識，步步踏著此巖石。',32,'全唐诗/poet.song.162000.json','["處處青山人不識，步步踏著此巖石。", "妙妙妙妙不可言，可惜可惜大可惜。"]'),
('6da35517-e4f5-4c75-b168-53e63f020901','贈野牛','楊簡','宋','宋诗','song-poetry','','[]','曾將大手挽恒河，引得龍來地起波。',32,'全唐诗/poet.song.162000.json','["曾將大手挽恒河，引得龍來地起波。", "何待硯池藏滴水，工夫元不費揩磨。"]'),
('3368021d-8388-4c82-9412-87ae41672b0f','湍水巖禱雨詩  其一','楊簡','宋','宋诗','song-poetry','','[]','湍水龍潭古跡遺，不因老叟有誰知。',64,'全唐诗/poet.song.162000.json','["湍水龍潭古跡遺，不因老叟有誰知。", "鄉人禱雨無靈日，雲魃常羊尚在時。", "說與縣家誠且信，去從潭所宿爲期。", "囘頭甘澤蘇枯槁，插種工夫未是遲。"]'),
('67da9eba-1cf0-4381-80c5-994ea39820b4','湍水巖禱雨詩  其二','楊簡','宋','宋诗','song-poetry','','[]','精禱何須到處臨，只祈湍水沛甘霖。',64,'全唐诗/poet.song.162000.json','["精禱何須到處臨，只祈湍水沛甘霖。", "驅除旱魃無餘事，感召靈神在寸忱。", "庭砌已酣行蟻戰，山川能動老龍吟。", "當知一飽皆公賜，雷地何人無喜心。"]'),
('d36404a6-4069-43b8-bc63-15a28821e64c','蒙訓','楊簡','宋','宋诗','song-poetry','','[]','父母生子身，身是父母箇。',168,'全唐诗/poet.song.162000.json','["父母生子身，身是父母箇。", "如何却言我，言我大不可。", "父母在此坐，子則不敢坐。", "不坐乃當然，父母如天大。", "男兒立父旁，女兒立母旁。", "男兒拱手立，女兒斂衣裳。", "捧盥兼灑掃，將茶及奉湯。", "言語須低軟，依前立正方。", "兄姊惟恭敬，弟妹常愛慈。", "飲食先尊長，不敢遽有之。", "尊長若嗔我，嗔我是愛我。", "欲我爲君子，所以約束我。", "語話須誠實，步履學疎遲。", "頭容常正直，四體莫邪欹。"]'),
('8b1fc99d-4d49-460a-88c7-06cf1fdfae08','金明池','楊簡','宋','宋诗','song-poetry','','[]','燕語鶑啼，杏壇春色。',142,'全唐诗/poet.song.162000.json','["燕語鶑啼，杏壇春色。", "爲甚無人領略，又添箇山青水綠。", "是多多少少明明白白，對面不識。", "方且蕩然放逸，不亦文辭雕琢。", "聖人道君子不必相與言，但示以禮樂，禮樂無言莫穿鑿。", "一味融融，無窮靜樂。", "步步行行皆妙用，言言句句俱寂寞。", "舜曰道心，明心即道。", "百姓日用，不知不覺。", "從學者再三勤勤有請，也只不可說著。"]'),
('9684a462-3437-45ff-9cb0-d329b4718945','歷代詩 三皇五帝','楊簡','宋','宋诗','song-poetry','','[]','混沌鑿開知幾歲，洪荒莫考傳承裔。',64,'全唐诗/poet.song.162000.json','["混沌鑿開知幾歲，洪荒莫考傳承裔。", "但聞前史載三皇，伏義神農及黄帝。", "三皇之後五帝傳，少昊顓頊高辛繼。", "唐堯虞舜又繼之，天下於斯爲盛際。"]'),
('f13f57ea-5a07-45b3-9733-8b0609c19fa7','歷代詩 夏','楊簡','宋','宋诗','song-poetry','','[]','堯舜天位傳禹王，禹之子啟傳太康。',80,'全唐诗/poet.song.162000.json','["堯舜天位傳禹王，禹之子啟傳太康。", "仲康王相少康後，王宁王槐及王芒。", "王泄不降王扃立，王廑孔甲何淫荒。", "王臯之後有王發，桀放南巢夏始亡。", "十七君餘四百歲，夏之天下遂爲商。"]'),
('be83ebcb-ec79-4369-9a23-4f2c7476e0ca','歷代詩 商','楊簡','宋','宋诗','song-poetry','','[]','商湯興時民戴后，外丙仲壬繼其後。',144,'全唐诗/poet.song.162000.json','["商湯興時民戴后，外丙仲壬繼其後。", "太甲沃丁及太庚，小甲雍己及太戊。", "仲丁外壬河亶甲，祖乙祖辛傳沃甲。", "祖丁相繼有南庚，陽甲之後是盤庚。", "盤庚能復興商邑，不幸小辛小乙立。", "武丁有德號高宗，祖庚祖甲又無功。", "廩辛庚丁逢武乙，太丁帝乙衰王室。", "末有紂辛名曰受，民心遂歸周武后。", "六百餘年三十主，周得天下商遂亡。"]'),
('25be808c-c0a7-4d59-9adf-c648e0a01770','歷代詩 西周','楊簡','宋','宋诗','song-poetry','','[]','后稷文王世幾傳，武王方得天下全。',48,'全唐诗/poet.song.162000.json','["后稷文王世幾傳，武王方得天下全。", "成康昭穆及共懿，孝夷之後厲兼宣。", "幽王見殺平王立，以上凡經四百年。"]'),
('7033b8f3-cbf6-47b8-8a5c-99681f53d37c','歷代詩 東周','楊簡','宋','宋诗','song-poetry','','[]','平王避難遷洛陽，桓莊僖惠襄頃匡。',80,'全唐诗/poet.song.162000.json','["平王避難遷洛陽，桓莊僖惠襄頃匡。", "定簡靈景兼悼敬，二百餘年春秋王。", "春秋之後周之晚，元王貞定相承纂。", "哀考威烈遂傳安，夷烈顯聖慎靚赧。", "三十七主始爲秦，八百餘年誰謂短。"]'),
('78d7bd55-74d7-45ec-b22b-2881026d97da','歷代詩 泰','楊簡','宋','宋诗','song-poetry','','[]','始皇繼周稱皇帝，傳子胡亥爲二世。',32,'全唐诗/poet.song.162000.json','["始皇繼周稱皇帝，傳子胡亥爲二世。", "子嬰灞上降漢王，四十餘年非久計。"]'),
('dc5e04b9-d84a-4737-aee9-e787770798b4','歷代詩 西漢','楊簡','宋','宋诗','song-poetry','','[]','西漢十二君，高惠呂后文。',48,'全唐诗/poet.song.162000.json','["西漢十二君，高惠呂后文。", "景帝傳于武，遂及昭宣元。", "成哀平帝後，王莽乃爲君。", "昌邑兼孺子，二人不足云。"]'),
('76b3bdd3-45bd-456a-b870-4eb1bd627b38','歷代詩 東漢','楊簡','宋','宋诗','song-poetry','','[]','東漢之光武，高皇九世孫。',60,'全唐诗/poet.song.162000.json','["東漢之光武，高皇九世孫。", "誅莽中興後，依前十二傳。", "明章稱顯肅，乃及和殤安。", "順賢沖與質，桓靈極不君。", "終當孝獻帝，漢室遂三分。"]'),
('77aaea59-c695-48e1-99c8-3f31a23859d7','歷代詩 三國 其一','楊簡','宋','宋诗','song-poetry','','[]','兩漢四百載，分爲魏蜀吳。',36,'全唐诗/poet.song.162000.json','["兩漢四百載，分爲魏蜀吳。", "曹操始居鄴，劉備據成都。", "孫權在金陵，鼎足互相圖。"]'),
('0350d8f8-7cf5-461f-90af-f3286fb83690','歷代詩 三國 其二','楊簡','宋','宋诗','song-poetry','','[]','蜀從劉備傳後主，四十餘年爲魏虜。',64,'全唐诗/poet.song.162000.json','["蜀從劉備傳後主，四十餘年爲魏虜。", "吳傳孫亮至孫休，晉封孫皓歸命侯。", "魏有文明俱稱帝，齊王高貴還相繼。", "陳留王立共五君，大業卒傳司馬懿。"]'),
('0aea1b45-7898-49d2-9538-e4e824104f57','歷代詩 西晉','楊簡','宋','宋诗','song-poetry','','[]','晉人司馬氏，相魏敢專權。',48,'全唐诗/poet.song.162000.json','["晉人司馬氏，相魏敢專權。", "懿師昭不帝，追謚宣景文。", "武帝受魏禪，惠帝實童昏。", "劉聰害懷愍，由此失中原。"]'),
('05727035-aa0c-411d-b14c-bdd06545c592','歷代詩 東晉','楊簡','宋','宋诗','song-poetry','','[]','夷狄陷河洛，元帝南渡江。',72,'全唐诗/poet.song.162000.json','["夷狄陷河洛，元帝南渡江。", "宣帝之曾孫，立號都建康。", "明成康與穆，哀廢最堪傷。", "簡文武安後，桓玄暫稱王。", "卒聞恭帝世，遜位宋武皇。", "兩晉十五主，二百年而亡。"]'),
('80d597ff-8ac9-450e-9c10-2dd96df766ff','歷代詩 宋','楊簡','宋','宋诗','song-poetry','','[]','宋武是劉裕，傳位從東晉。',48,'全唐诗/poet.song.162000.json','["宋武是劉裕，傳位從東晉。", "滎陽與文帝，遂傳武帝駿。", "前廢乃有明，後廢乃立順。", "八主六十年，蕭齊因繼運。"]'),
('39fa1fa9-977e-432f-a0e1-8d8996c1e483','歷代詩 齊','楊簡','宋','宋诗','song-poetry','','[]','齊主蕭道成，乃是蕭何孫。',48,'全唐诗/poet.song.162000.json','["齊主蕭道成，乃是蕭何孫。", "武帝鬰林王，海陵鳴帝鸞。", "東昏至和帝，七主不足論。", "二十有四年，蕭梁遂建元。"]'),
('73767665-d1cf-4f80-88d3-752565c5e8e0','歷代詩 梁','楊簡','宋','宋诗','song-poetry','','[]','蕭衍梁武帝，其子號簡文。',36,'全唐诗/poet.song.162000.json','["蕭衍梁武帝，其子號簡文。", "孝元恭皇帝，前後共四君。", "五十有六載，大位俱于陳。"]'),
('2e62fdd7-2ffe-4279-9399-5167240bb893','歷代詩 陳','楊簡','宋','宋诗','song-poetry','','[]','陳武名霸先，文帝廢帝傳。',36,'全唐诗/poet.song.162000.json','["陳武名霸先，文帝廢帝傳。", "宣帝及後主，共三十二年。", "六朝至此滅，天下歸楊堅。"]'),
('ae8a1b76-d0b6-492f-8f6b-3d5af9d77e0b','歷代詩 隋','楊簡','宋','宋诗','song-poetry','','[]','楊堅隋高皇，煬帝遂淫荒。',36,'全唐诗/poet.song.162000.json','["楊堅隋高皇，煬帝遂淫荒。", "恭帝不足道，四海正擾攘。", "三主四十年，天下禪于唐。"]'),
('3996f1fb-c64c-4898-af56-492473be9243','歷代詩 唐','楊簡','宋','宋诗','song-poetry','','[]','唐祖是李淵，太宗高則天。',60,'全唐诗/poet.song.162000.json','["唐祖是李淵，太宗高則天。", "中宗曾見廢，睿宗傳與玄。", "肅代德順憲，穆敬文武宣。", "懿僖及昭哀，二十一君傳。", "二百九十四，朱梁稱元年。"]'),
('9a206e5c-1554-4c9e-a57c-cbb83b9c85a4','歷代詩 五代','楊簡','宋','宋诗','song-poetry','','[]','梁主是朱溫，篡唐都汴宋。',132,'全唐诗/poet.song.162000.json','["梁主是朱溫，篡唐都汴宋。", "友珪及末帝，滅于李克用。", "莊宗克用子，滅梁又稱唐。", "明宗與愍潞，滅于石敬瑭。", "敬瑭晉高祖，其子號少主。", "虜爲負義侯，契丹入中土。", "晉亡漢始立，知遠實姓劉。", "傳子稱隠帝，二世遂爲周。", "周家有太祖，姓郭乃名威。", "世宗及恭帝，僅能十載期。", "共五十三年，天命遂有歸。"]'),
('9473796c-8293-47f7-a77b-df810d1ab2be','歷代詩 宋','楊簡','宋','宋诗','song-poetry','','[]','太祖太宗兄授弟，兩派天源稱善繼。',80,'全唐诗/poet.song.162000.json','["太祖太宗兄授弟，兩派天源稱善繼。", "真宗嗣位及仁宗，以子傳孫皆聖裔。", "英宗有詔嗣濮王，次及神宗哲宗世。", "徽宗行道付欽宗，高宗南渡中興帝。", "孝宗之末嗣秀王，揖遜而朝誠鮮儼。"]'),
('c67ec04e-c938-42c5-8727-347461024450','凈土院','楊簡','宋','宋诗','song-poetry','','[]','此意分明有底深，蒲團斜倚滿鋪陰。',64,'全唐诗/poet.song.162000.json','["此意分明有底深，蒲團斜倚滿鋪陰。", "豈容俗子閒抬眼，只許清風得入林。", "我對此君無一事，自言幽處直千金。", "古人今已成陳跡，猶向當年擊處尋。"]'),
('598f326e-2969-4345-b24e-e19c4b2a8845','題華蓋仙山院默齋','楊簡','宋','宋诗','song-poetry','','[]','漸漸疎鐘動，幽深一徑開。',48,'全唐诗/poet.song.162000.json','["漸漸疎鐘動，幽深一徑開。", "炎光隔林麓，清興遶崔嵬。", "擬作臨流賦，應須倩雨催。", "小窗宜挂起，且放竹風來。"]'),
('34e81286-50a5-4a56-b62f-17b2e35073d6','題進月堂','楊簡','宋','宋诗','song-poetry','','[]','我有一輪月，不圓又不缺。',48,'全唐诗/poet.song.162000.json','["我有一輪月，不圓又不缺。", "更無晝與夜，光耀常洞徹。", "縱有蔀屋遮，亦莫之閒絕。", "將此以爲燭，難作進退說。"]'),
('6860eb26-af19-4823-bdb9-23355dc32f0b','絕句','楊簡','宋','宋诗','song-poetry','','[]','凈几橫琴曉寒，梅花落在絃間。',28,'全唐诗/poet.song.162000.json','["凈几橫琴曉寒，梅花落在絃間。", "我欲清吟無句，轉煩門外青山。"]'),
('6746be91-7fbe-4c67-b88e-ac2be393b559','明堂侍祠十絕  其一','楊簡','宋','宋诗','song-poetry','','[]','禮行肆類又稱禋，喜見承平景鑠信。',32,'全唐诗/poet.song.162000.json','["禮行肆類又稱禋，喜見承平景鑠信。", "堪笑漢人誇肸蠁，何如明德遠精純。"]'),
('8702a83b-d6b3-42a5-8df1-c419623f2e65','明堂侍祠十絕  其二','楊簡','宋','宋诗','song-poetry','','[]','先皇鴻烈冠重興，廟社依然總燕寧。',32,'全唐诗/poet.song.162000.json','["先皇鴻烈冠重興，廟社依然總燕寧。", "今日孝思嚴陟配，必知深妥在天靈。"]'),
('2f690eaa-7a9f-417d-8a69-5b6999b6a2bd','明堂侍祠十絕  其三','楊簡','宋','宋诗','song-poetry','','[]','玉軑纔馳霽色開，都人歡呼殷如雷。',32,'全唐诗/poet.song.162000.json','["玉軑纔馳霽色開，都人歡呼殷如雷。", "曰暘曰雨元無定，都自吾皇一念來。"]'),
('2be85e80-1575-4bc8-8543-7542a80baeb9','明堂侍祠十絕  其四','楊簡','宋','宋诗','song-poetry','','[]','唱徹嚴更鳳鑰開，侍祠濟濟列崇陔。',32,'全唐诗/poet.song.162000.json','["唱徹嚴更鳳鑰開，侍祠濟濟列崇陔。", "小臣亦忝廊西獻，惟秉溫恭對越來。"]'),
('9f1a76d3-edd1-4ef7-947f-7b34acb58cf2','明堂侍祠十絕  其五','楊簡','宋','宋诗','song-poetry','','[]','玉佩珊珊出禁扉，金蓮分炬散芳菲。',32,'全唐诗/poet.song.162000.json','["玉佩珊珊出禁扉，金蓮分炬散芳菲。", "祠班咫尺臨黄道，惹得天香滿袖歸。"]'),
('0a7b5d53-8a01-47c2-bb8e-be2c2ba4cec4','明堂侍祠十絕  其六','楊簡','宋','宋诗','song-poetry','','[]','登歌奏罷樂初成，懿懿芬芬薦德馨。',32,'全唐诗/poet.song.162000.json','["登歌奏罷樂初成，懿懿芬芬薦德馨。", "好是天心彰信順，故教華月吐青冥。"]'),
('f9ec91da-f1e4-40f3-8092-f9e75c8781a6','明堂侍祠十絕  其七','楊簡','宋','宋诗','song-poetry','','[]','合宮深敞匝脩廊，萬燭煇煇粲奉璋。',32,'全唐诗/poet.song.162000.json','["合宮深敞匝脩廊，萬燭煇煇粲奉璋。", "自有質文昭儉度，不須揚厲述齊房。"]'),
('549d0bf1-0d45-4884-9ef5-4dbfcfcee197','明堂侍祠十絕  其八','楊簡','宋','宋诗','song-poetry','','[]','左个明堂是集英，鵠袍曾此接文明。',32,'全唐诗/poet.song.162000.json','["左个明堂是集英，鵠袍曾此接文明。", "餕餘款聽鈞天奏，疑是吾伊雅頌聲。"]'),
('f9398b22-2c34-4989-9d10-f9072a1f692d','明堂侍祠十絕  其九','楊簡','宋','宋诗','song-poetry','','[]','千官移仗拱端門，一日鷄竿萬里春。',32,'全唐诗/poet.song.162000.json','["千官移仗拱端門，一日鷄竿萬里春。", "湯網本疏民自格，要知家法在深仁。"]'),
('ca917287-1c7e-4882-a731-d8065fd034d4','明堂侍祠十絕  其一○','楊簡','宋','宋诗','song-poetry','','[]','肸蠁豐融富媼釐，班迴長樂奉愉怡。',32,'全唐诗/poet.song.162000.json','["肸蠁豐融富媼釐，班迴長樂奉愉怡。", "休嘉最易生安逸，翼翼當如未祼時。"]'),
('08d3d9ad-ea96-41ae-aa38-3fd54261dad4','妙庭觀','楊簡','宋','宋诗','song-poetry','','[]','古人所棄今人慕，不謂蘇公亦世情。',32,'全唐诗/poet.song.162000.json','["古人所棄今人慕，不謂蘇公亦世情。", "此話若教天上聽，定須笑倒董雙成。"]'),
('d13c0aeb-dc54-4f58-9999-7bbf584d92cf','慶元二年冬後圃蔬莖連理籬楊殊木同枝又蓏生連實東園橘亦并蒂一年四瑞','楊簡','宋','宋诗','song-poetry','','[]','兄弟和氣與天通，連理蔬莖瑞鬰葱。',32,'全唐诗/poet.song.162000.json','["兄弟和氣與天通，連理蔬莖瑞鬰葱。", "造化神機非遠近，不當言異又言同。"]'),
('edf516c2-ad57-4eca-a444-e0f9d68ac0d3','句  其一','楊簡','宋','宋诗','song-poetry','','[]','山禽說我胸中事，煙柳藏他物外機。',16,'全唐诗/poet.song.162000.json','["山禽說我胸中事，煙柳藏他物外機。"]'),
('1c0f1c77-fa8b-4df2-8235-730b0d9cf6a3','句  其二','楊簡','宋','宋诗','song-poetry','','[]','萬里蒼茫融妙意，三杯虛白浴天真。',16,'全唐诗/poet.song.162000.json','["萬里蒼茫融妙意，三杯虛白浴天真。"]'),
('a172fbce-1dfc-4f5e-980f-46ee4d48f7d5','春辭','趙善扛','宋','宋诗','song-poetry','','[]','碧落初明月未收，露華香滴杏梢頭。',32,'全唐诗/poet.song.162000.json','["碧落初明月未收，露華香滴杏梢頭。", "玉闌干外東風暖，人在重雲第幾樓。"]'),
('39c7d087-8881-45bd-bb43-e9846d4ceeef','瑞雲雀偈','趙善扛','宋','宋诗','song-poetry','','[]','日日飛鳴宣妙旨，幻華起滅復何疑。',32,'全唐诗/poet.song.162000.json','["日日飛鳴宣妙旨，幻華起滅復何疑。", "可憐多少風塵客，去去來來只自欺。"]'),
('cfc74b98-eaba-4bde-bd8a-645b38b35d6d','麗人行','趙善扛','宋','宋诗','song-poetry','','[]','桃葉山前宮漏遲，宮人傍輦持花枝。',64,'全唐诗/poet.song.162000.json','["桃葉山前宮漏遲，宮人傍輦持花枝。", "君王喜憑絳仙立，殿脚爭畫雙長眉。", "欲抱琵琶彈出塞，結綺臨春時事改。", "井邊忽見張麗華，忍聽後庭歌一再。"]'),
('94ace529-84f2-4c8d-83b9-ea281074c0f9','題大安鋪','趙善扛','宋','宋诗','song-poetry','','[]','行役何時歇，崇安復大安。',48,'全唐诗/poet.song.162000.json','["行役何時歇，崇安復大安。", "已驚橋壹線，更畏嶺千盤。", "過雨吹烟碧，近風落葉丹。", "僧閑吾每羨，今日共蹣跚。"]'),
('30459792-c38a-4f74-a731-993524827650','句','趙善扛','宋','宋诗','song-poetry','','[]','相思情不極，有夢到愁邊。',12,'全唐诗/poet.song.162000.json','["相思情不極，有夢到愁邊。"]'),
('6b03a54d-7509-420c-ab40-ac62882d7436','宣化堂','王聞詩','宋','宋诗','song-poetry','','[]','聖主端居念遠民，盡將休戚寄斯文。',32,'全唐诗/poet.song.162000.json','["聖主端居念遠民，盡將休戚寄斯文。", "時來宣化堂中坐，應念田中正苦辛。"]'),
('e8051db8-2685-4136-847e-e9c6f87eccb1','題靈岩寺','趙善悉','宋','宋诗','song-poetry','','[]','江南多名山，雁蕩最崒嵂。',240,'全唐诗/poet.song.162000.json','["江南多名山，雁蕩最崒嵂。", "山中多古寺，靈岩渺無匹。", "天柱高摩雲，展旗巧障日。", "風榻卧石屏，霧窗涵卓筆。", "上有小龍湫，龍鼻清泉出。", "異哉諾詎羅，來此坐疊膝。", "我亦蕩中人，景象頗能悉。", "獨秀翫蒼翠，重臺聽蕭瑟。", "却穿水簾谷，衣襟寒慄慄。", "還入新月洞，意氣何飄逸。", "安期指瓜棗，羨門獻梨栗。", "飄瓦孰是非，臨歧置得失。", "平生方外遊，茲遊爲第一。", "謾登嶺三三，休跨盤七七。", "豈意山盡頭，時復有禪室。", "門並雙峰尖，路爽千榕密。", "觸石淺溪鳴，投林飛鳥入。", "傍人應笑我，觀山何時畢。", "笑話傍人道，恨我少登陟。", "作詩寄行役，吾非貪著述。"]'),
('7d499872-9793-453f-99d0-647675461760','震山巖','羅克開','宋','宋诗','song-poetry','','[]','身倚層巖興莫窮，若爲鬰鬰在樊籠。',64,'全唐诗/poet.song.162000.json','["身倚層巖興莫窮，若爲鬰鬰在樊籠。", "故人話別傷心裏，尊酒論文醉眼中。", "萬井疊鱗烟靄暝，一江如練水雲同。", "衛公慷慨風流在，却愧新詩力未工。"]'),
('44069479-d457-4275-983a-11a66c3cdc7c','句','羅克開','宋','宋诗','song-poetry','','[]','撫摩二字圭三復，公直一心衡不欺。',16,'全唐诗/poet.song.162000.json','["撫摩二字圭三復，公直一心衡不欺。"]'),
('5247d941-ac91-4c9d-a9a7-8dae0edc6522','句','王遇','宋','宋诗','song-poetry','','[]','不知何處雨，已覺此間凉。',12,'全唐诗/poet.song.162000.json','["不知何處雨，已覺此間凉。"]'),
('86bdc261-5690-4b77-b2a9-f80bf6246633','浮遠堂','吳漢英','宋','宋诗','song-poetry','','[]','天險東南限此江，支分暨水北爲陽。',64,'全唐诗/poet.song.162000.json','["天險東南限此江，支分暨水北爲陽。", "孤山不動嬰潮怒，客艇飛來說路長。", "檻外煙雲如出沒，坐中頃刻變炎凉。", "裴囘頓覺塵纓絆，一曲滄浪酬月光。"]'),
('b50931aa-c9b3-40cc-b935-f2415c355514','蕭尚書縱目樓','章穎','宋','宋诗','song-poetry','','[]','深居無事即神仙，况閲丹經第幾篇。',64,'全唐诗/poet.song.162000.json','["深居無事即神仙，况閲丹經第幾篇。", "桂樹花開臨舊國，榴皮書字徹新磚。", "瓊書玉篆行將見，鐵畫銀鈎粲可鎸。", "他日功成昇舉去，願分餘庇及姻聯。"]'),
('027ef0e8-1e5f-4630-ab83-3f3625a9dc64','桃源觀','章穎','宋','宋诗','song-poetry','','[]','繞館參天萬樹松，倚欄時見翠重重。',64,'全唐诗/poet.song.162000.json','["繞館參天萬樹松，倚欄時見翠重重。", "一坰曉霧浮天外，半夜秋濤落枕中。", "莫雨斷猿愁羃歷，夕陽飛鳥度屏風。", "采苓欲問長生訣，只恐雲迷路不通。"]'),
('ae485d0b-715c-492e-8828-4edea26e97d9','送長子琳連州刺史入覲','章穎','宋','宋诗','song-poetry','','[]','衝雪登長道，吾兒更勉旃。',48,'全唐诗/poet.song.162000.json','["衝雪登長道，吾兒更勉旃。", "人常談作郡，汝且去朝天。", "身歷窮閭久，條陳正宁前。", "故人如問我，爲說病彌年。"]'),
('9e9a4198-77de-46c6-bac4-5fbfc8ce1fcd','句','章穎','宋','宋诗','song-poetry','','[]','兩州南北護梅關，盡日人行石壁間。',16,'全唐诗/poet.song.162000.json','["兩州南北護梅關，盡日人行石壁間。"]'),
('b1f76296-148e-466b-840d-4e4a32427446','妙庭觀','曾表勳','宋','宋诗','song-poetry','','[]','小溪一曲繞山綠，虎遶龍蟠記丹熟。',32,'全唐诗/poet.song.162000.json','["小溪一曲繞山綠，虎遶龍蟠記丹熟。", "空想雲軿佩玉鳴，夜深屋角風吹竹。"]'),
('a6c482d0-26d4-40f0-bc57-05f6a8038e26','題妙庭觀','魏仲恭','宋','宋诗','song-poetry','','[]','九轉凡成吞絳雪，霓旌縹緲昇丹闕。',96,'全唐诗/poet.song.162000.json','["九轉凡成吞絳雪，霓旌縹緲昇丹闕。", "瑶池因到阿母家，笑傲壺中閑日月。", "蟠桃一熟千年久，爲君持獻流霞酒。", "不應移種上林春，紅顔聊駐人間壽。", "回首桑田幾翻覆，世上黄糧猶未熟。", "暫來仙館拂塵埃，靜對吟風幾竿竹。"]'),
('0d4d2ba9-17c0-421f-a6a8-ab8e00397658','和孟東野韻','范偃','宋','宋诗','song-poetry','','[]','散策欲薄暮，疏鐘猶殷牀。',48,'全唐诗/poet.song.162000.json','["散策欲薄暮，疏鐘猶殷牀。", "風煙函古趣，巖壑生幽香。", "仰首逼象緯，俯視渺川光。", "向來非突兀，幾成虎豹場。"]'),
('deacf890-a643-4351-9766-80d9e12abf57','和張承吉韻','范偃','宋','宋诗','song-poetry','','[]','飛閣臨無地，巨區可平吞。',48,'全唐诗/poet.song.162000.json','["飛閣臨無地，巨區可平吞。", "高巖聳怪石，老木纏雲根。", "人散魚蝦市，帆歸葭葦村。", "每來豁塵慮，不妨頻款門。"]'),
('e9ab7db6-7a93-41e4-9267-5e97aaac39c6','句','高之美','宋','宋诗','song-poetry','','[]','四郡甘棠清到底，一枝丹桂慶流芳。',16,'全唐诗/poet.song.162000.json','["四郡甘棠清到底，一枝丹桂慶流芳。"]'),
('07938a26-9582-416b-bee5-61d979f92a80','妙法庵二首  其一','趙良佐','宋','宋诗','song-poetry','','[]','乘興來遊古道場，遠村落日卧牛羊。',32,'全唐诗/poet.song.162000.json','["乘興來遊古道場，遠村落日卧牛羊。", "暫能擺脫塵埃念，瓦鼎烟消柏子香。"]'),
('b9111e44-32ae-4a9c-be3e-83270c5cf060','妙法庵二首  其二','趙良佐','宋','宋诗','song-poetry','','[]','蔓藤扶我過東岡，與客同登妙法堂。',64,'全唐诗/poet.song.162000.json','["蔓藤扶我過東岡，與客同登妙法堂。", "小院迴廊春已暮，茂林修竹夏初長。", "歸歟未辦買山計，健甚無庸却老方。", "都市山林總無累，此生此世底須忙。"]'),
('ce75a41c-749d-47b1-860f-32fe0e5673b5','句','陸世良','宋','宋诗','song-poetry','','[]','七相聲名俱屬此，尚期他日更添君。',16,'全唐诗/poet.song.162000.json','["七相聲名俱屬此，尚期他日更添君。"]'),
('845f85ef-1160-4689-9faa-44acd35d3709','橫溪堂春曉二首  其一','虞似良','宋','宋诗','song-poetry','','["\u5373\u666f", "\u7530\u56ed"]','一把新秧趁手青，輕煙漠漠雨冥冥。',32,'全唐诗/poet.song.162000.json','["一把新秧趁手青，輕煙漠漠雨冥冥。", "東風染盡三千頃，白鷺飛來無處停。"]'),
('920fa475-5b14-4707-8f9e-af956b158e62','橫溪堂春曉二首  其二','虞似良','宋','宋诗','song-poetry','','[]','田塍常滿雨常餘，綠遍溪南我獨無。',32,'全唐诗/poet.song.162000.json','["田塍常滿雨常餘，綠遍溪南我獨無。", "珍重天公不遺物，也分餘潤到菖蒲。"]'),
('77c57754-72da-4af8-b44d-180c285e42cd','詩一首','虞似良','宋','宋诗','song-poetry','','[]','一杯山茗雪花白，數片甘瓜碧玉香。',32,'全唐诗/poet.song.162000.json','["一杯山茗雪花白，數片甘瓜碧玉香。", "但得心閒無箇事，人生何地不清涼。"]'),
('12e66c2d-3f43-4a9e-babd-a3144ab679d4','消湖','虞似良','宋','宋诗','song-poetry','','[]','野草閑花洞口春，碧潭如鑑凈無塵。',32,'全唐诗/poet.song.162000.json','["野草閑花洞口春，碧潭如鑑凈無塵。", "江山好景携不得，漾入酒杯和月吞。"]'),
('56bc31c7-ad84-4318-a40b-639253f8f1cf','西樓','王亙','宋','宋诗','song-poetry','','[]','西江橫玉虹，西山羅畫屏。',60,'全唐诗/poet.song.162000.json','["西江橫玉虹，西山羅畫屏。", "荒城大如斗，此樓何崢嶸。", "炎嶺狀隴蜀，三州通蓬瀛。", "人烟幾村落，數點如晨星。", "誰識海一涯，好峰無數青。"]'),
('c8039a28-5b55-4db6-af23-a7c1c785384b','次胡澹庵題挹翠軒韻','王亙','宋','宋诗','song-poetry','','[]','西山排闥來，周遭自環翠。',132,'全唐诗/poet.song.162000.json','["西山排闥來，周遭自環翠。", "俗眼少見之，一覽忘世味。", "平生三徑心，盍早賦歸計。", "縱落塵土居，不與草木敝。", "公餘事幽尋，清風拂衣袂。", "最喜軒中人，所挹多爽氣。", "蓬蒿天地寬，萬境發詩思。", "白雲未能閒，時出過窗几。", "簷雨聽夜語，池草生春媚。", "山靈若相知，好風爲裂眥。", "餘光雖力挽，回次那得致。"]'),
('ce7c2eea-4493-4282-bedf-b27c2082ffe6','題翠巖亭','王亙','宋','宋诗','song-poetry','','[]','一壑盤蒼玉，峰巒尺五天。',48,'全唐诗/poet.song.162000.json','["一壑盤蒼玉，峰巒尺五天。", "人間怪泉石，嶺外好山川。", "寺近鯨宵吼，林深犢晝眠。", "謫仙三百載，此樂有誰傳。"]'),
('bbdcb219-cd2f-4b45-a856-b3df1d15424c','雲間閣留題壁間','張垓','宋','宋诗','song-poetry','','[]','清江一曲抱村流，古柏千莖遶幽。',63,'全唐诗/poet.song.162000.json','["清江一曲抱村流，古柏千莖遶幽。", "天畔峰巒俱秀峙，壁間珠玉爛凝眸。", "遥觀細菊重巖下，共作携壺九日遊。", "回首家山白雲外，遽興歸思漫悠悠。"]'),
('66f6f873-c526-4cc8-a6c5-b6f5d231dfbf','步同鄉張君垓壁韻','章崇簡','宋','宋诗','song-poetry','','[]','當年杜老最風流，來往清江逸興幽。',64,'全唐诗/poet.song.162000.json','["當年杜老最風流，來往清江逸興幽。", "西蜀好山宜入畫，南龕佳景遠舒眸。", "民安暫得琴書樂，歲宴間爲麋鹿遊。", "記得鄱陽張子韻，白雲紅日共悠悠。"]'),
('50c4f0d8-bcb4-4889-ae38-4a28a611f147','解印至大橋鋪寄邵陽父老','沈伯達','宋','宋诗','song-poetry','','[]','已過長亭一舍寬，送行猶自挽征鞍。',32,'全唐诗/poet.song.162000.json','["已過長亭一舍寬，送行猶自挽征鞍。", "我無惠政蘇凋瘵，何事邦人淚不乾。"]'),
('d47c9bb7-c66b-4985-a4f3-4cfd41f489a6','六月十七日夜寄邢子友','沈伯達','宋','宋诗','song-poetry','','[]','暑雨雖不足，涼風還有餘。',48,'全唐诗/poet.song.162000.json','["暑雨雖不足，涼風還有餘。", "樂此城陰夜，何殊山崦居。", "月明蒼檜立，露下芭蕉舒。", "試問澄虛閣，今夜復焉如。"]'),
('ac5fc0bd-bbae-4703-98ee-a32633857c9b','先寄邢子友','沈伯達','宋','宋诗','song-poetry','','[]','作客今年樂有餘，邵陽岐路不崎嶇。',64,'全唐诗/poet.song.162000.json','["作客今年樂有餘，邵陽岐路不崎嶇。", "山川好處欹紗帽，桃李香中度笋輿。", "欲見舊交驚歲月，剩排幽話說艱虞。", "人間書疏非吾事，一首新詩未可無。"]'),
('a6c4149a-15bd-4444-a02a-9faa06764fb5','句','傅晞儉','宋','宋诗','song-poetry','','[]','千年飽服長生藥，三朵長簪不老花。',16,'全唐诗/poet.song.162000.json','["千年飽服長生藥，三朵長簪不老花。"]'),
('722bbdec-053a-4175-b072-d4276da22593','句','李賓','宋','宋诗','song-poetry','','[]','自笑資中窮太守，每逢水竹便相親。',16,'全唐诗/poet.song.162000.json','["自笑資中窮太守，每逢水竹便相親。"]'),
('f3c1c356-8fd8-4ac1-8fd7-2873b8849a2e','臨終頌','釋法慈','宋','宋诗','song-poetry','','[]','無始劫來不曾生，今日當場又隨滅。',28,'全唐诗/poet.song.162000.json','["無始劫來不曾生，今日當場又隨滅。", "又隨滅，萬里炎天覓點雪。"]'),
('4e97b2ad-ee04-4ba9-a28e-b5192bf0237b','仙居洞','錢聞詩','宋','宋诗','song-poetry','','[]','仙客神人幾度行，環山岌嶪似重城。',32,'全唐诗/poet.song.162000.json','["仙客神人幾度行，環山岌嶪似重城。", "有門不掩寒溪月，終日水流無盡聲。"]'),
('f2c74db3-7930-4a32-8dca-e4e71e147204','嚴陵釣臺','錢聞詩','宋','宋诗','song-poetry','','[]','無復塵勞夢，猶蒙故舊知。',24,'全唐诗/poet.song.162000.json','["無復塵勞夢，猶蒙故舊知。", "寧辭萬鍾祿，不負一綸絲。"]'),
('ff90eaac-b8c3-417d-874d-dcca296e3f7a','文殊臺','錢聞詩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五臺山裏現文殊，人指此臺名似虛。',32,'全唐诗/poet.song.162000.json','["五臺山裏現文殊，人指此臺名似虛。", "正馬東峰有獅子，恐曾高跨入匡廬。"]'),
('5df43f14-0cdd-4679-a77a-f4450d6a2a28','再榮檜','錢聞詩','宋','宋诗','song-poetry','','[]','老檜中枯歲月深，外包一餘自成陰。',32,'全唐诗/poet.song.162000.json','["老檜中枯歲月深，外包一餘自成陰。", "能於箇裏知消息，不怕生身有死心。"]'),
('0ec96965-120f-4486-9993-1d0bc47d4dcd','湖舟','錢聞詩','宋','宋诗','song-poetry','','[]','一島如蓬江面浮，行人遥指是湖舟。',32,'全唐诗/poet.song.162000.json','["一島如蓬江面浮，行人遥指是湖舟。", "寂無檣艣艤沙岸，寧怕風濤不測憂。"]'),
('7980c902-049a-4146-a323-8fd428d70661','蔡真人搗藥臼','錢聞詩','宋','宋诗','song-poetry','','[]','一臼山根蚤暮樁，不知扶起幾羸癃。',32,'全唐诗/poet.song.162000.json','["一臼山根蚤暮樁，不知扶起幾羸癃。", "如言搗藥長生兔，應爲真人不桂宮。"]'),
('75debdbd-9a30-4672-b011-421a9a2be75a','虛白館','錢聞詩','宋','宋诗','song-poetry','','[]','雙溪飛溜出三峰，後有幽巖虎嘯風。',32,'全唐诗/poet.song.162000.json','["雙溪飛溜出三峰，後有幽巖虎嘯風。", "絕景要知虛白處，洞天別在一壺中。"]'),
('35be22e4-9897-43b3-a699-bd810c81f5d8','杏壇','錢聞詩','宋','宋诗','song-poetry','','[]','真人昇去寂無音，徒指空壇說杏林。',32,'全唐诗/poet.song.162000.json','["真人昇去寂無音，徒指空壇說杏林。", "講道雖非夫子惠，此心還是愛人心。"]'),
('8e543560-4306-4979-b520-82652aa11c3c','神林浦廟','錢聞詩','宋','宋诗','song-poetry','','[]','廟奉神龍樂施錢，薛君矯首亦行天。',64,'全唐诗/poet.song.162000.json','["廟奉神龍樂施錢，薛君矯首亦行天。", "爲霖遍澤一千里，感夢忽符三十年。", "盤饌勤勤禱祠客，桅檣戢戢待風船。", "我來三酹謝休德，馥郁金爐沉水煙。"]'),
('1ed8b786-532d-4393-8342-b4942d1c60f2','相思橋','錢聞詩','宋','宋诗','song-poetry','','[]','道術相忘過眼休，要將此意味莊周。',32,'全唐诗/poet.song.162000.json','["道術相忘過眼休，要將此意味莊周。", "橋邊莫起相思念，恐使遊人錯路頭。"]'),
('d7babcff-dfea-4aa3-b3a7-53abdeef805a','瀑布','錢聞詩','宋','宋诗','song-poetry','','[]','河漢遥分一派輕，望中渺渺白蛇形。',32,'全唐诗/poet.song.162000.json','["河漢遥分一派輕，望中渺渺白蛇形。", "誰教來自半天上，穿破千尋碧玉屏。"]'),
('bb988603-a8a2-4a76-b0f3-de5c72655568','滴滴泉','錢聞詩','宋','宋诗','song-poetry','','[]','不同瀑布瀉千山，數滴空餘坎井間。',32,'全唐诗/poet.song.162000.json','["不同瀑布瀉千山，數滴空餘坎井間。", "端是龍神閟珠味，故教滴滴與人慳。"]'),
('f5e2df59-3e26-4907-a2df-e4babb697515','天門','錢聞詩','宋','宋诗','song-poetry','','[]','兩岫如門久不關，皆言此路出麈寰。',32,'全唐诗/poet.song.162000.json','["兩岫如門久不關，皆言此路出麈寰。", "山人笑道誰曾到，只有煙雲空往還。"]'),
('c12bd7cc-3f21-4913-8636-e32f04096f61','次韻雲岫','錢聞詩','宋','宋诗','song-poetry','','[]','超然物外一身行，野鶴孤雲寄此生。',64,'全唐诗/poet.song.162000.json','["超然物外一身行，野鶴孤雲寄此生。", "蓬戶晝關春色暗，松窗夜敞月華明。", "濛濛山影暝將曉，款款溪聲雨欲晴。", "曾識山南雲岫隠，方知寵辱莫吾驚。"]'),
('07b28721-11b0-4898-8e89-db57e840ba1d','上霄峰','錢聞詩','宋','宋诗','song-poetry','','[]','傑出羌廬信不凡，一峰高入白雲間。',32,'全唐诗/poet.song.162000.json','["傑出羌廬信不凡，一峰高入白雲間。", "秦皇不解升霄去，留得空名與此山。"]'),
('2dc99f15-4f74-4570-9fcb-0a0fc43ecc18','朝斗石','錢聞詩','宋','宋诗','song-poetry','','[]','先生禮斗望乾門，拜石千年今尚存。',32,'全唐诗/poet.song.162000.json','["先生禮斗望乾門，拜石千年今尚存。", "料得一心存七曜，四時同運紫微垣。"]'),
('187d46ff-0385-4959-892c-6c4e8118a56f','明月泉','錢聞詩','宋','宋诗','song-poetry','','[]','團圓一井爲誰開，夜夜東隅月色來。',32,'全唐诗/poet.song.162000.json','["團圓一井爲誰開，夜夜東隅月色來。", "釀得新醅飲佳客，分明蟾影浸金盃。"]'),
('329c354d-113e-4205-adee-cafa41ab205c','鵝池','錢聞詩','宋','宋诗','song-poetry','','[]','逸少江州刺史歸，鸞溪溪上穴方池。',32,'全唐诗/poet.song.162000.json','["逸少江州刺史歸，鸞溪溪上穴方池。", "此時鶂鶂已堪玩，不待山陰道士遺。"]'),
('3db70411-1c3c-4865-8ef0-f27d79ed925e','白龜池','錢聞詩','宋','宋诗','song-poetry','','[]','僧義來庵穴一池，皆言池下有靈龜。',32,'全唐诗/poet.song.162000.json','["僧義來庵穴一池，皆言池下有靈龜。", "色如玉白隠難見，那使武昌人得之。"]'),
('67d69424-0090-469e-a43f-4e703e4835db','鳳凰山','錢聞詩','宋','宋诗','song-poetry','','[]','鳳兮未至德非衰，端爲漫山水去遲。',32,'全唐诗/poet.song.162000.json','["鳳兮未至德非衰，端爲漫山水去遲。", "翠竹成陰有新實，與君朝夕看來儀。"]'),
('55f1c2bd-5a99-4b79-be04-af09cbeef651','鶴鳴峰','錢聞詩','宋','宋诗','song-poetry','','[]','一峰崷崒插長空，雲樹煙蘿氣蔚葱。',32,'全唐诗/poet.song.162000.json','["一峰崷崒插長空，雲樹煙蘿氣蔚葱。", "洞府幽深無鳥雀，只聞仙鶴唳松風。"]'),
('c0666361-6154-4357-ba97-00976e481f07','虎跡','錢聞詩','宋','宋诗','song-poetry','','[]','淵明與虎兩相忘，虎至淵明在醉鄉。',32,'全唐诗/poet.song.162000.json','["淵明與虎兩相忘，虎至淵明在醉鄉。", "一嘯風生下山去，依然爪跡枕痕傍。"]'),
('df240c16-9c68-460f-9f77-a0b342cc0f26','鸞溪','錢聞詩','宋','宋诗','song-poetry','','[]','一溪高占翠嶙間，終日寒泉自往還。',32,'全唐诗/poet.song.162000.json','["一溪高占翠嶙間，終日寒泉自往還。", "要看儀儀同類舞，惜乎不接鳳凰山。"]'),
('3f4c60dc-eb7c-4bd6-bb8f-a5b94f262576','卧龍潭  其一','錢聞詩','宋','宋诗','song-poetry','','[]','長空匹練曳千林，來自幽巖幾萬尋。',32,'全唐诗/poet.song.162000.json','["長空匹練曳千林，來自幽巖幾萬尋。", "寄語神龍無久卧，爲嗔虐魃起爲霖。"]'),
('291755a6-371c-4a13-8c70-996bdbcfafb8','卧龍潭  其二','錢聞詩','宋','宋诗','song-poetry','','[]','山分巧石疊玲瓏，煙幕雲屏閟幾重。',32,'全唐诗/poet.song.162000.json','["山分巧石疊玲瓏，煙幕雲屏閟幾重。", "有竹參天長鱗角，欲陪高卧碧潭龍。"]'),
('529e9324-a98b-41f8-b496-0472f6e9f86b','馬尾泉','錢聞詩','宋','宋诗','song-poetry','','[]','短流色白燦瑶光，穿破山腰一株蒼。',32,'全唐诗/poet.song.162000.json','["短流色白燦瑶光，穿破山腰一株蒼。", "多少遊人來又去，從教袖裏有鞭長。"]'),
('d3e77eaf-ede6-4b55-8571-ae121d047b5b','龍穴','錢聞詩','宋','宋诗','song-poetry','','[]','丁君神靈斡天樞，一叱二龍遺戲珠。',80,'全唐诗/poet.song.162000.json','["丁君神靈斡天樞，一叱二龍遺戲珠。", "龍來求珠珠不與，吐下腥涎滿庭宇。", "僧繇畫柱真龍形，有龍來鬭風雷鳴。", "君篆靈符纔入鐵，龍走今存去時穴。", "予問此穴奚出龍，羽衣謂穴龍潭通。"]'),
('82f8aa74-8360-46e8-b6bb-a4c7f337205a','甜苦笋','錢聞詩','宋','宋诗','song-poetry','','[]','先生仙去擁霓旌，數宇猶存簡寂名。',32,'全唐诗/poet.song.162000.json','["先生仙去擁霓旌，數宇猶存簡寂名。", "還向箇中真得味，從教甜苦笋邊生。"]'),
('e92fa930-1bae-4cf1-9b18-26fba31f4e55','大夫松','錢聞詩','宋','宋诗','song-poetry','','[]','秦皇昔上上霄峰，正恐行行憩此松。',32,'全唐诗/poet.song.162000.json','["秦皇昔上上霄峰，正恐行行憩此松。", "莫道大夫惟爵五，誤恩疑更有加封。"]'),
('da1c9749-7ed4-4246-8a31-056abd92ee84','貞元杉','錢聞詩','宋','宋诗','song-poetry','','[]','鶴去凄然一古杉，傲霜凌雪幾年間。',32,'全唐诗/poet.song.162000.json','["鶴去凄然一古杉，傲霜凌雪幾年間。", "若非一種靈根異，安得青青不改顔。"]'),
('8bd24db0-aceb-4f14-8f73-be6f7ad56ac9','萬杉','錢聞詩','宋','宋诗','song-poetry','','[]','嗟乎老子啟精藍，樹下藤蘿手自芟。',32,'全唐诗/poet.song.162000.json','["嗟乎老子啟精藍，樹下藤蘿手自芟。", "遺愛不教終斷絕，山前山後長新杉。"]'),
('259cf6a3-3343-40e0-8a3a-06c7c9c93c42','二雙蓮  其一','錢聞詩','宋','宋诗','song-poetry','','[]','薰風吹蓮塘，灼灼萬朶芳。',48,'全唐诗/poet.song.162000.json','["薰風吹蓮塘，灼灼萬朶芳。", "中有并蒂出，翠幄眠鴛鴦。", "二橋鬌雲鬟，新浴香汗凉。", "老夫奚致哉，乃郡豐年祥。"]'),
('920f6ee5-f313-4f4e-b6fd-cb7a5cd1ba9c','二雙蓮  其二','錢聞詩','宋','宋诗','song-poetry','','[]','氣和高厚格，珍符開地脈。',48,'全唐诗/poet.song.162000.json','["氣和高厚格，珍符開地脈。", "匪禾匪禽魚，連枝比目翮。", "要先凈客呈，雙雙滿阡陌。", "今秋合穟禾，來春兩岐麥。"]'),
('cf23a275-ae9f-4a17-8f83-673558c7191b','射亭','錢聞詩','宋','宋诗','song-poetry','','[]','射圃亭開郡治東，欒城二詠紀元豐。',32,'全唐诗/poet.song.162000.json','["射圃亭開郡治東，欒城二詠紀元豐。", "品題一出大儒筆，觀者于今矍相同。"]'),
('e172c3a9-4ee7-4224-aecd-11fdb5f7d211','小閣','錢聞詩','宋','宋诗','song-poetry','','[]','淒涼一閣睨高空，倚檻幽奇景莫窮。',32,'全唐诗/poet.song.162000.json','["淒涼一閣睨高空，倚檻幽奇景莫窮。", "好是山腰抱松檜，一屏玉琢白雲中。"]'),
('4569c2fe-864c-45fd-beb0-ceee0f2941c8','玉淵亭','錢聞詩','宋','宋诗','song-poetry','','[]','路入棲賢步轉東，望中天末有雲從。',32,'全唐诗/poet.song.162000.json','["路入棲賢步轉東，望中天末有雲從。", "不緣白石淵名玉，祇爲淵深有玉龍。"]'),
('2d42a72a-ef9a-43d0-9d56-c3dbbea2e214','愛蓮堂','錢聞詩','宋','宋诗','song-poetry','','[]','懿哉周濂溪，昔攬星江符。',132,'全唐诗/poet.song.162000.json','["懿哉周濂溪，昔攬星江符。", "四時花卉多，獨以蓮自娛。", "公見太極初，學業周孔徒。", "如何心清浄，愛與釋氏俱。", "理是吾即爾，理非爾異吾。", "理與愛適同，彼釋我自儒。", "只疑牡丹時，貴客笑我愚。", "又恐菊花開，隠士斥我迂。", "彼此一是非，能問莊生無。", "坐看萬朵紅，翠蓋爭相扶。", "晚凉微雨來，亂落明月珠。"]'),
('87c65175-81da-4bce-98a4-73e9426ac378','折桂新亭','錢聞詩','宋','宋诗','song-poetry','','[]','面對三江背五峰，一亭屹屹睨其中。',32,'全唐诗/poet.song.162000.json','["面對三江背五峰，一亭屹屹睨其中。", "蓬萊弱水眼前是，不必思航大海東。"]'),
('966cafaa-3eca-4d6d-92ee-e533878c13ab','佚老亭','錢聞詩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','膠膠朝路七書考，請紱星江恨不早。',128,'全唐诗/poet.song.162000.json','["膠膠朝路七書考，請紱星江恨不早。", "昔詫廬山心未然，今見廬山真是好。", "子卜子家廬山傍，龐眉鶴髮商山皓。", "老而欲佚不得佚，此佚由來錫穹昊。", "江聲山色紛亭前，溢架詩書對花草。", "心閑日月自舒長，此身到處蓬萊島。", "不妨留客醉幕天，浩歌大笑尊罍倒。", "寄言五峰盍定交，伴此一翁呼六老。"]'),
('646b9ffb-89e0-42b3-a2ca-447f9cd242a5','彭蠡門','錢聞詩','宋','宋诗','song-poetry','','[]','何事何年敞此門，望中白浪湧山根。',32,'全唐诗/poet.song.162000.json','["何事何年敞此門，望中白浪湧山根。", "不知陽鳥攸居處，日落風高萬艣奔。"]'),
('f3501c36-6b11-431f-b2e7-2206bb1a16e8','雲錦閣','錢聞詩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','引目遥空碧玉屏，清風入座冷無塵。',64,'全唐诗/poet.song.162000.json','["引目遥空碧玉屏，清風入座冷無塵。", "斗傍句得一仙客，昴入名存五老人。", "雲霧散收無限意，林巒生落幾番新。", "廬山景物絕天下，盍倒尊罍醉坐賓。"]'),
('c92fa8b4-4e30-4700-8aa5-3aa1500b3552','漱玉亭','錢聞詩','宋','宋诗','song-poetry','','[]','有龍銜水下層霄，俯視浮屠潄海潮。',32,'全唐诗/poet.song.162000.json','["有龍銜水下層霄，俯視浮屠潄海潮。", "浄倚欄干清耳目，笙篁聲裏落瓊瑶。"]'),
('fe4bc88d-9f9e-4976-aefe-714afbcb9d33','白鹿洞書院','錢聞詩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','錫名有旨感皇明，百載荒基一日營。',64,'全唐诗/poet.song.162000.json','["錫名有旨感皇明，百載荒基一日營。", "白鹿雖無歸洞迹，青衿猶有讀書聲。", "塵中講貫似難入，靜裏工夫終易成。", "孕出廬山真秀氣，寧無渭釣與莘耕。"]'),
('550f665f-eae0-404e-a07f-c09775090107','登雲錦閣有感  其一','錢聞詩','宋','宋诗','song-poetry','','[]','雲錦同梯得舊遊，旋供簾月泛瓊甌。',32,'全唐诗/poet.song.162000.json','["雲錦同梯得舊遊，旋供簾月泛瓊甌。", "莫言官事兼私事，五老峰前一醉休。"]'),
('9f958ee6-cf2d-48ae-885a-00d77a2af1ac','登雲錦閣有感  其二','錢聞詩','宋','宋诗','song-poetry','','[]','五老峰前一醉休，長空目斷水雲浮。',32,'全唐诗/poet.song.162000.json','["五老峰前一醉休，長空目斷水雲浮。", "要將心地同山色，莫放煙嵐翳上頭。"]'),
('4b8e5737-1265-4848-b208-72aad93a1585','登雲錦閣有感  其三','錢聞詩','宋','宋诗','song-poetry','','[]','莫放煙嵐翳上頭，窮通皆樂我何憂。',32,'全唐诗/poet.song.162000.json','["莫放煙嵐翳上頭，窮通皆樂我何憂。", "眼前有景且歡醉，百歲光陰水上漚。"]'),
('80d32824-37b9-4bbd-869b-a06965cb71c9','醉書陳推官小閣','錢聞詩','宋','宋诗','song-poetry','','[]','五老來從西洛山，三江去接東溟水。',32,'全唐诗/poet.song.162000.json','["五老來從西洛山，三江去接東溟水。", "如何盡會此窗前，一引雙眸千萬里。"]'),
('de0d24c3-8101-45ce-b6ac-e630e303ef5d','歸去來館','錢聞詩','宋','宋诗','song-poetry','','[]','來兮歸去拂塵纓，引目家山一日程。',32,'全唐诗/poet.song.162000.json','["來兮歸去拂塵纓，引目家山一日程。", "柳菊知歸應改色，稚兒門候僕歡迎。"]'),
('1c5f6196-1325-4d0f-a82a-fe9032e7aa9c','落星寺','錢聞詩','宋','宋诗','song-poetry','','[]','望中呈一點，晃若出雲躔。',48,'全唐诗/poet.song.162000.json','["望中呈一點，晃若出雲躔。", "隕石是何宿，到江知幾年。", "鐘聲昏曉嶼，帆影去來船。", "此景分河漢，有槎須問天。"]'),
('c6703227-298b-4ab4-9629-64098fdb6ca1','疊石庵','錢聞詩','宋','宋诗','song-poetry','','[]','行行疊石正新秋，山氣清凉老火收。',64,'全唐诗/poet.song.162000.json','["行行疊石正新秋，山氣清凉老火收。", "雲出半天三五岫，江橫一水萬千洲。", "少休官裏文書冗，且向仙家洞府遊。", "白浪捲空瀾蠡岸，望中數點是歸舟。"]'),
('6bb4020f-197f-4904-b93c-aa62a6b103fe','耶舍塔','錢聞詩','宋','宋诗','song-poetry','','[]','耶舍浮屠願力深，特烹生鐵鑄高岑。',32,'全唐诗/poet.song.162000.json','["耶舍浮屠願力深，特烹生鐵鑄高岑。", "永教遐邇觀瞻者，盡發如來菩薩心。"]'),
('676e6352-560b-44df-b975-7dd754a30816','折桂庵','錢聞詩','宋','宋诗','song-poetry','','[]','李君館此舉明經，仕顯聲銷豈足榮。',32,'全唐诗/poet.song.162000.json','["李君館此舉明經，仕顯聲銷豈足榮。", "樹有菩提僧不命，却將折桂榜庵名。"]'),
('11b2dc14-5f36-4e39-ae14-602a5d9affd3','題米元暉萬里長江圖','錢聞詩','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u592a\u6e56"]','太湖水入霅溪寒，疊嶂連山幾萬般。',32,'全唐诗/poet.song.162000.json','["太湖水入霅溪寒，疊嶂連山幾萬般。", "此景古今無盡藏，總歸嬾拙一毫端。"]'),
('f5b3e1bb-47e0-4bec-adec-851385547321','獅子峰','錢聞詩','宋','宋诗','song-poetry','','[]','文殊心死冷如灰，何日乘騎下寶臺。',32,'全唐诗/poet.song.162000.json','["文殊心死冷如灰，何日乘騎下寶臺。", "自得雄名威萬古，更無一獸下山來。"]'),
('58f897bc-59ee-4d19-8322-5e43049c3ed7','三峽橋','錢聞詩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','生平有志在山水，得紱此邦非偶爾。',128,'全唐诗/poet.song.162000.json','["生平有志在山水，得紱此邦非偶爾。", "行行白鹿書院來，小輿竹逕松陰裏。", "輕雷急鼓山前聞，飛梁截截水下噴。", "有如蛟龍捲滄海，怒氣直欲山前吞。", "勸客倚欄同把盞，低頭千夫眩雙眼。", "自非建始决金隄，端是晉陽徹三板。", "手摩題石苔蘚斑，駐看未飽不忍還。", "誰能挽之出廬山，一洗塵俗清人間。"]'),
('950c1cda-e67d-44ed-a1d2-564f723c44ea','句','錢聞詩','宋','宋诗','song-poetry','','[]','今君試看錫山碑，天下何泉居第一。',16,'全唐诗/poet.song.162000.json','["今君試看錫山碑，天下何泉居第一。"]'),
('0fc61a99-2f45-4b30-99a7-8773a0409985','園鶴','游九言','宋','宋诗','song-poetry','','[]','擲米不盈掬，羣雀下階除。',96,'全唐诗/poet.song.162000.json','["擲米不盈掬，羣雀下階除。", "昂昂圃中鶴，飯糗不可呼。", "嬉翔白雲外，飲啄青山隅。", "日淡烟水鄉，風曬翎羽舒。", "羣雞汝自況，乘軒我何拘。", "秋原忽清唳，杳杳聞碧虛。", "志士甘水菽，三四羞猿狙。", "寄語飛鳴侶，悠悠差自如。"]'),
('0b2c7ad1-c92b-432c-9b77-28fa891b21b8','烏鵲','游九言','宋','宋诗','song-poetry','','[]','鴉烏鳴屋山，平生不爲惡。',72,'全唐诗/poet.song.162000.json','["鴉烏鳴屋山，平生不爲惡。", "乾鵲噪庭樹，一世常牢落。", "安有无妄福，凶災或無作。", "身貧乏名譽，屋漏無愧怍。", "春風拂茅簷，聽汝相嘲謔。", "禍福心悠悠，曲肱常自樂。"]'),
('41419144-342f-4487-a5a4-35dc10b53309','聞蟬','游九言','宋','宋诗','song-poetry','','[]','悄悄山郭暗，故園應掩扉。',24,'全唐诗/poet.song.162000.json','["悄悄山郭暗，故園應掩扉。", "蟬聲深樹起，林外夕陽稀。"]'),
('da4ca857-0843-4baf-9edd-094bc752f185','秋雨歎','游九言','宋','宋诗','song-poetry','','[]','戊午七月陰氣寒，重雲低濕天漫漫。',176,'全唐诗/poet.song.162000.json','["戊午七月陰氣寒，重雲低濕天漫漫。", "高簷流瀉下簷溢，旅人愁絕居人冤。", "市井滂沱豈足計，老農涕泣猶辛酸。", "兩年巨川舟楫亂，田萊風過生微瀾。", "會稽湧溢鑑湖水，黄岩移徙陶家山。", "積骸荒溝如敝屣，餘生骨立皮膚乾。", "秋來黄雲蔽滿野，瘦妻弱稚期朝餐。", "誰知造化不可料，恩加魚鱉嬉禾田。", "日光弗覩動逾月，瓦鳴晝夜愁珊珊。", "安得長梯掃氛翳，雲漢萬里清光還。", "腐儒撫事泥災變，頻搔白首空𩯮𩯮。"]'),
('1772354f-6e4b-421f-9f9f-19de3e5f1b70','遇雨','游九言','宋','宋诗','song-poetry','','[]','一雨摧時節，微凉暑氣通。',48,'全唐诗/poet.song.162000.json','["一雨摧時節，微凉暑氣通。", "天青雲澹薄，山迥日空濛。", "聽訟多餘暇，韋編足細窮。", "却慙爲宦拙，閒處得秋風。"]'),
('2b7b553b-1f98-4a23-86a3-29376d5773ac','暮春','游九言','宋','宋诗','song-poetry','','[]','已過清明穀雨天，燕忙鶑嬾蝶蜂翾。',64,'全唐诗/poet.song.162000.json','["已過清明穀雨天，燕忙鶑嬾蝶蜂翾。", "風和日暖才三月，花落春歸又一年。", "得意自應談事業，有懷誰肯卧林泉。", "荷鉏带月行歌處，付與孤蹤百世傳。"]'),
('2cb77fef-d7e9-4b18-9ebc-93e546a1b028','夜色','游九言','宋','宋诗','song-poetry','','[]','夜色正幽悄，夢回常自悲。',108,'全唐诗/poet.song.162000.json','["夜色正幽悄，夢回常自悲。", "悠悠節物改，冉冉心事非。", "兒嬉意不足，搔首忽成絲。", "炎寒扇洪罏，橐籥日煎治。", "冥鴻戲雲路，蝸蠅蝕昏卑。", "功名難力致，志勉與心期。", "旦晝多營營，至此盍停思。", "誰能澄夜氣，一息存端倪。", "五更百慮起，嘹嘹聽啼雞。"]'),
('231f0dc8-ac63-4605-bfed-b4b473cd7573','新作盆池戲書','游九言','宋','宋诗','song-poetry','','[]','瓦盆片石壘青蒼，興入湖山寄小窗。',32,'全唐诗/poet.song.162000.json','["瓦盆片石壘青蒼，興入湖山寄小窗。", "細看纖鱗無限樂，不妨斗水學西江。"]'),
('3df19e35-53c4-4132-be58-465b31da0885','引鏡','游九言','宋','宋诗','song-poetry','','[]','引鏡忽自照，山野良足嗤。',96,'全唐诗/poet.song.162000.json','["引鏡忽自照，山野良足嗤。", "定無貂蟬冠，罩此麋鹿姿。", "寒饑走世路，鬚髮罥蠶絲。", "歸來頻自嘆，久別舍前溪。", "輸與傍鄰子，釣舸弄漣漪。", "空懷萬卷富，共歎三綱欹。", "秋原山杳杳，脫葉風披披。", "早路已相失，好取桑榆西。"]'),
('7cc37475-b924-4631-9c18-7c202324f187','聽鄭三彈雙韻子歌','游九言','宋','宋诗','song-poetry','','[]','寒窗積雪生虛明，玉壺風折層簷冰。',192,'全唐诗/poet.song.162000.json','["寒窗積雪生虛明，玉壺風折層簷冰。", "朱霞秀色妙公子，理絃燈下聲亭亭。", "遊絲兩兩掛孤月，雙聲應手無留停。", "月寒照戶砌蟲泣，雲凍出浦邊鴻征。", "蒼蠅撲紙窗欲透，蜾蠃穴桑兒未成。", "琵琶寬詳雙韻切，含凄盡向絃中說。", "酒酣疏綺雜娛嬉，誰道壯夫心更折。", "一從敵騎下河南，學得聲容難辨別。", "鷓鴣金屋沸歌吹，鼠頭寶陌行靴襪。", "帕腰慢舞作彎弧，捉耳釂觴真折馘。", "眼前猶聽舊歌辭，鳳韶豈獨鏘虞時。", "罷彈三喟寢不熟，風定寒江靜夜悲。"]'),
('e23accf2-b7be-41b8-8982-08443e764c50','讀道書作','游九言','宋','宋诗','song-poetry','','[]','岩居秉貞操，所慕在玄虛。',72,'全唐诗/poet.song.162000.json','["岩居秉貞操，所慕在玄虛。", "清夜眠齋宇，終身觀道書。", "形忘氣自充，性達理不餘。", "於道雖未庶，已超名迹拘。", "至樂在襟懷，山水非所娛。", "寄語狂馳子，營營竟焉如。"]'),
('40a7751b-e1ff-4192-ba15-dcbda741228a','金陵野外廢寺','游九言','宋','宋诗','song-poetry','','[]','寒花窈嫋蔓頹牆，古寺蒼苔晝掩房。',64,'全唐诗/poet.song.162000.json','["寒花窈嫋蔓頹牆，古寺蒼苔晝掩房。", "犬吠屋頭山杳杳，蟲鳴階隙草荒荒。", "池塘淡日蒹葭冷，籬落西風橘柚黄。", "六代江山金碧地，斷碑留得管興亡。"]'),
('1eadcd5b-854c-448e-a4bf-50868978f6e0','題上藍西堂秀老壁','游九言','宋','宋诗','song-poetry','','[]','槎牙此老是枯松，衲破寒窗百病攻。',32,'全唐诗/poet.song.162000.json','["槎牙此老是枯松，衲破寒窗百病攻。", "贏得雪霜皮骨在，幾看桃李謝春風。"]'),
('267e04db-ca1b-4f6e-8493-c87ca767378c','讀法華經示巽上人','游九言','宋','宋诗','song-poetry','','[]','上上不須說，我法妙難思。',180,'全唐诗/poet.song.162000.json','["上上不須說，我法妙難思。", "汝師釋迦文，深欲警羣癡。", "有如優曇花，可玩不可持。", "瑶車駕大武，火宅鳴狐狸。", "中道息化城，寶坊須竟躋。", "將令脫塵網，誘設華多辭。", "吾事不須爾，父子相恬嬉。", "常行存日用，妙處參天倪。", "一性本昭徹，春臺自熙熙。", "汝亦有父母，棄去他人依。", "免懷報何日，敬養終無時。", "先靈爲餒鬼，由汝身披緇。", "如云識此心，有生皆秉彝。", "謂升兜率天，無路誰能知。", "試于清夜闌，回首誦吾詩。"]'),
('a862641b-b533-4ab5-941d-61ecdd4c89db','義靈廟迎享送神曲  其一','游九言','宋','宋诗','song-poetry','','[]','北固山兮朝暉，鼛鼓奏兮吹箎。',58,'全唐诗/poet.song.162000.json','["北固山兮朝暉，鼛鼓奏兮吹箎。", "盼夫君兮來止，紛老稚兮扶携。", "歛芳馨兮薦豆，君弗語笑兮我懷悽。", "聊相羊兮引釂，慰我願兮無違。"]'),
('14f79390-df70-492e-aa57-eaa5ae52c851','義靈廟迎享送神曲  其二','游九言','宋','宋诗','song-poetry','','[]','青溪煽兮氛妖，洶二浙兮波濤。',102,'全唐诗/poet.song.162000.json','["青溪煽兮氛妖，洶二浙兮波濤。", "花石粲兮江南驛騷，匪氓好亂兮生不聊。", "欻蠻方兮同嘯，紛醜類兮江臯。", "愬精誠兮上天，哀萬命兮孤墉。", "屬櫜鞬兮奮厲，忽並殪兮兩兇。", "嗟我父子兮耕農，何以報德兮維孝與忠，千齡萬代兮子孫之從。"]'),
('440f772e-44f0-4fba-9fc8-c708992dd708','義靈廟迎享送神曲  其三','游九言','宋','宋诗','song-poetry','','[]','巫覡醉兮君馬嘶，風雲驅兮吹靈旗。',59,'全唐诗/poet.song.162000.json','["巫覡醉兮君馬嘶，風雲驅兮吹靈旗。", "凌浩蕩兮將何之，山靡迤兮白鶴飛。", "歲歲今兮望君歸，君遊勿遠兮我民之依，山阿寂寞兮頹陽西。"]'),
('94570d4c-613b-45b1-9ff3-52aeb8f3237f','訪薛道士不值','游九言','宋','宋诗','song-poetry','','[]','三茅俯千山，杖藜山氣佳。',48,'全唐诗/poet.song.162000.json','["三茅俯千山，杖藜山氣佳。", "來尋薛道士，空房鎖烟霞。", "微霜染紅葉，晞露浥黄花。", "舞逐西風去，湖水夕陽斜。"]'),
('8c299672-c3a7-4de1-8b52-a233d78653d8','冬雨不止','游九言','宋','宋诗','song-poetry','','[]','忽忽時節改，白日藏光輝。',72,'全唐诗/poet.song.162000.json','["忽忽時節改，白日藏光輝。", "重陰潤九野，小雨紛微微。", "蒼山寒氣深，高林霜葉晞。", "田家秋成意，落落乖所期。", "曠望獨興懷，戚戚愁寒饑。", "事至當復遣，且掩荒園扉。"]'),
('064dcb9a-6634-4ef3-a219-5ecdae16c2d7','美人倚樓圖','游九言','宋','宋诗','song-poetry','','[]','簷頭燕子說春寒，蝴蝶悠悠午夢殘。',32,'全唐诗/poet.song.162000.json','["簷頭燕子說春寒，蝴蝶悠悠午夢殘。", "睡起高樓多少恨，天涯小雨怯闌干。"]'),
('8f26cbe0-65f8-48b9-a550-da695b0cad28','溪上','游九言','宋','宋诗','song-poetry','','[]','煙開曉日照溪頭，溪上人家岸下舟。',32,'全唐诗/poet.song.162000.json','["煙開曉日照溪頭，溪上人家岸下舟。", "啼鳥不知春已老，數聲自喜碧巖幽。"]'),
('3043a55c-fa99-48bb-b57f-8a4a88369310','登巾山','游九言','宋','宋诗','song-poetry','','[]','環走層岡馬脫鞿，兩峰平地玉頎頎。',64,'全唐诗/poet.song.162000.json','["環走層岡馬脫鞿，兩峰平地玉頎頎。", "南臨澥島金鼇涌，東望叢祠白鶴飛。", "日出市聲朝霧散，雲沈海氣暮潮歸。", "居塵却立塵埃表，徙倚天風振客衣。"]'),
('98c10ad3-d298-4ee3-a035-ecd477804ede','楊忠襄墓','游九言','宋','宋诗','song-poetry','','[]','山雲起兮陰陰，木嘯風兮蕭森。',255,'全唐诗/poet.song.162000.json','["山雲起兮陰陰，木嘯風兮蕭森。", "骨荒榛兮頹隧，野鳥怨兮清音。", "噫丙午兮燕安，藹薦紳兮多盤。", "繫苞桑兮弗戒，渝舊好兮開邊。", "釁生兮召戎，澒大地兮塵蒙。", "粲承干兮百載，莽夷門兮廟宮。", "我踰邠兮梁山，蛇洊食兮江干。", "擁貔貅兮首鼠，紛雅拜兮後先。", "獨立兮慨陳，人自靖兮此身。", "寧爲鬼兮趙氏，肯涅緇兮虜庭。", "肴醑飼兮苟哺，弗自知兮貌頳。", "握玉麟兮拜犬豕，曾莫嗅兮羶腥。", "豈曰余兮獨死，汝尸坐兮偷生。", "振英聲兮階下，氣烈動兮清寧。", "凜名義兮身世，九鼎重兮一羽輕。", "翳翳兮幽藏，頹陽照兮山荒。", "髮毛爪齒兮一世同腐，廟貌圭衮兮千古之光。", "春秋兮代謝，勿替兮烝嘗。"]'),
('b0156c97-9a0d-445f-b649-6d94883b100f','慶余思永冠  其一','游九言','宋','宋诗','song-poetry','','[]','聖經陳冠義，萬世示章程。',48,'全唐诗/poet.song.162000.json','["聖經陳冠義，萬世示章程。", "是禮最爲重，無喪始許行。", "三加儀特備，四行責非輕。", "此意知誰會，寥寥千古情。"]'),
('32b53537-52a1-4aa3-a956-59d76519fb4f','慶余思永冠  其二','游九言','宋','宋诗','song-poetry','','[]','今日□□仲，榮加首服新。',48,'全唐诗/poet.song.162000.json','["今日□□仲，榮加首服新。", "從今棄幼志，當自勉成人。", "處事與接物，從兄以事親。", "聖賢有謨訓，盍亦謹書紳。"]'),
('1dcb6d2f-bfe7-4745-8ead-4c5140d564e8','慶余思永冠  其三','游九言','宋','宋诗','song-poetry','','[]','禮儀今既備，告字亦攸宜。',48,'全唐诗/poet.song.162000.json','["禮儀今既備，告字亦攸宜。", "自昔學深造，莫非原自思。", "近而仁固在，□□□堪施。", "字子曰思永，欽哉保受之。"]'),
('ae5758ad-4a06-4a88-b4e2-ba28c9899dc4','華陽洞辭  其一','游九言','宋','宋诗','song-poetry','','[]','河漢澈，碧霄晴，九華仙子到凡塵。',32,'全唐诗/poet.song.162000.json','["河漢澈，碧霄晴，九華仙子到凡塵。", "凉夜山頭吹玉笛，纖雲卷盡月分明。"]'),
('d7005351-c640-4c1f-9e3c-dc19e89c9f5c','華陽洞辭  其二','游九言','宋','宋诗','song-poetry','','[]','香露濕，草晶熒，起看大地盡瑶璚。',32,'全唐诗/poet.song.162000.json','["香露濕，草晶熒，起看大地盡瑶璚。", "下界千門人寂寂，空山夜靜海波聲。"]'),
('014b2f4c-3fa9-4040-b08d-0c2fc2784f29','華陽洞辭  其三','游九言','宋','宋诗','song-poetry','','[]','仙子去，眇雲程，天風杳杳珮環清。',32,'全唐诗/poet.song.162000.json','["仙子去，眇雲程，天風杳杳珮環清。", "回望九州煙霧白，千山月落影縱橫。"]'),
('88c6aa15-1c6d-4a73-99b4-2135b9e5aa5d','秀州道中  其一','游九言','宋','宋诗','song-poetry','','[]','一春煙雨歇空濛，高下川原杳靄中。',32,'全唐诗/poet.song.162000.json','["一春煙雨歇空濛，高下川原杳靄中。", "畢竟春光遮不得，滿村花柳自青紅。"]'),
('a9ab9158-014c-4469-a170-de40b3e6a80d','秀州道中  其二','游九言','宋','宋诗','song-poetry','','[]','漠漠秋原禾黍空，藤蘿古木梵王宮。',32,'全唐诗/poet.song.162000.json','["漠漠秋原禾黍空，藤蘿古木梵王宮。", "孤村野水斜陽外，無數歸鴉落晚風。"]'),
('db9e475c-516b-41bd-83c8-02a132c89ef8','句  其一','游九言','宋','宋诗','song-poetry','','[]','春風未肯催桃李，留得疏籬淺淡香。',16,'全唐诗/poet.song.162000.json','["春風未肯催桃李，留得疏籬淺淡香。"]'),
('1a35dd6d-789b-4aa3-b8e7-b3e3bd8c94ab','句  其二','游九言','宋','宋诗','song-poetry','','[]','平生意思春風裏，信手題詩不用工。',16,'全唐诗/poet.song.162000.json','["平生意思春風裏，信手題詩不用工。"]'),
('2fddc316-cd2f-49e4-add7-e441ca06649f','句  其三','游九言','宋','宋诗','song-poetry','','[]','閒處謾憂當世事，靜中方識古人心。',16,'全唐诗/poet.song.162000.json','["閒處謾憂當世事，靜中方識古人心。"]'),
('63e5071e-1310-4525-b999-68b1bedeb898','廣壽','彭龜年','宋','宋诗','song-poetry','','[]','人孰爲壽，壽莫如德。',40,'全唐诗/poet.song.162000.json','["人孰爲壽，壽莫如德。", "日新又新，終古不息。", "學以明之，先正我心。", "所欲既寡，山崇海深。"]'),
('0ab513db-9bb5-4d74-ae4e-95d871ce42a7','許國公生辰  其一','彭龜年','宋','宋诗','song-poetry','','[]','入事其親，愉色融融。',40,'全唐诗/poet.song.162000.json','["入事其親，愉色融融。", "出事其君，惟命之從。", "威儀抑抑，曷不肅雍。", "有而弗恃，是之謂恭。"]'),
('6b0ff152-6e9e-489b-af0f-6f3d7c8109f3','許國公生辰  其二','彭龜年','宋','宋诗','song-poetry','','[]','天下之惡，不如一僭。',40,'全唐诗/poet.song.162000.json','["天下之惡，不如一僭。", "天下之善，不如一儉。", "物有不足，于我何欠。", "人欲無窮，儉乃防檢。"]'),
('00f20a64-4a90-4525-a12c-ad1ca4a0e560','許國公生辰  其三','彭龜年','宋','宋诗','song-poetry','','[]','人不自泰，以居故移。',40,'全唐诗/poet.song.162000.json','["人不自泰，以居故移。", "人不自奢，由養所爲。", "勝之有道，惟書與詩。", "願言君子，載思載惟。"]'),
('4cf1e09e-3657-4a63-be9c-fc287e2ee44a','許國公生辰  其四','彭龜年','宋','宋诗','song-poetry','','[]','恭自內出，儉非外飾。',40,'全唐诗/poet.song.162000.json','["恭自內出，儉非外飾。", "恭儉而實，是之謂德。", "作德日休，心廣體逸。", "何以曰壽，由是而積。"]'),
('c1924786-e0de-4d1a-9bdf-9bddeccefcd3','鶑鳴十章寄戚伯瑞  其一','彭龜年','宋','宋诗','song-poetry','','[]','有鳴其禽，其鳴維何。',20,'全唐诗/poet.song.162000.json','["有鳴其禽，其鳴維何。", "有懷其人，我心靡他。"]'),
('665ba75e-deee-4169-83e8-c4bb43ad9e31','鶑鳴十章寄戚伯瑞  其二','彭龜年','宋','宋诗','song-poetry','','[]','禽其鳴矣，惟其醜矣。',20,'全唐诗/poet.song.162000.json','["禽其鳴矣，惟其醜矣。", "我之懷矣，惟其友矣。"]'),
('c96f3b1e-77ea-452e-9aaa-fa2b0b9046f8','鶑鳴十章寄戚伯瑞  其三','彭龜年','宋','宋诗','song-poetry','','[]','惟動有幾，萬變形之。',20,'全唐诗/poet.song.162000.json','["惟動有幾，萬變形之。", "視聽與言，難遏者私。"]'),
('f37532bf-5194-435a-aefa-10857eb210da','鶑鳴十章寄戚伯瑞  其四','彭龜年','宋','宋诗','song-poetry','','[]','孰愛于母，惟善其善。',21,'全唐诗/poet.song.162000.json','["孰愛于母，惟善其善。", "孰友于兄弟，我獨終鮮。"]'),
('d06fa045-c67d-48c2-abcb-7f117cc926ca','鶑鳴十章寄戚伯瑞  其五','彭龜年','宋','宋诗','song-poetry','','[]','有水涓涓，石鑿鑿兮。',21,'全唐诗/poet.song.162000.json','["有水涓涓，石鑿鑿兮。", "日湔月濯，成此圓潔兮。"]'),
('f3d791b6-0f57-483b-84a2-81348859a88e','鶑鳴十章寄戚伯瑞  其六','彭龜年','宋','宋诗','song-poetry','','[]','有澤其涸，有山其落。',20,'全唐诗/poet.song.162000.json','["有澤其涸，有山其落。", "有木而桷，則以其斲。"]'),
('0c8c91a4-7454-433b-8cb5-999a3a45aa3b','鶑鳴十章寄戚伯瑞  其七','彭龜年','宋','宋诗','song-poetry','','[]','靜觀物理，式感我思。',20,'全唐诗/poet.song.162000.json','["靜觀物理，式感我思。", "有風淒兮，吹我裳衣。"]'),
('a361ee60-ec4a-4c80-806b-6732da7da90a','鶑鳴十章寄戚伯瑞  其八','彭龜年','宋','宋诗','song-poetry','','[]','春花粲兮，兩山之間。',20,'全唐诗/poet.song.162000.json','["春花粲兮，兩山之間。", "誰與我適，觴咏以還。"]'),
('8e677e84-a520-40a7-98c8-e72be30f2e24','鶑鳴十章寄戚伯瑞  其九','彭龜年','宋','宋诗','song-poetry','','[]','日升于東，月生于西。',21,'全唐诗/poet.song.162000.json','["日升于東，月生于西。", "惟神之馳，曾莫知所之。"]'),
('07e9f50e-b879-493c-89be-227704e238a0','鶑鳴十章寄戚伯瑞  其一○','彭龜年','宋','宋诗','song-poetry','','[]','莫克匪己，莫玩匪理。',22,'全唐诗/poet.song.162000.json','["莫克匪己，莫玩匪理。", "有懷于是，不知子之所止。"]'),
('a4d70ea3-4762-4d78-a0fb-23a543a70fe0','胡廣文以直養名堂余舉伊川之說問之往反數十言終未判也再以是訊焉','彭龜年','宋','宋诗','song-poetry','','[]','以物養物，如水沃木。',120,'全唐诗/poet.song.162000.json','["以物養物，如水沃木。", "推彼有餘，益此不足。", "惟直與氣，如木有根。", "本既充盛，枝葉自繁。", "氣言其形，直言其理。", "與生俱生，無彼無此。", "云何謂直，養此氣耶。", "直果外來，氣內出耶。", "孟氏此言，我知其自。", "則以告子，以義外計。", "謂直養氣，其差則同。", "疑其不然，願啟我蒙。"]'),
('62693115-d38f-4250-b7fd-18ad88737cdf','九日分韻得去字','彭龜年','宋','宋诗','song-poetry','','[]','昔從招提遊，岸柳擘新絮。',96,'全唐诗/poet.song.162000.json','["昔從招提遊，岸柳擘新絮。", "那知再到時，葉落滿庭署。", "爭如青青松，寒暑了不與。", "古榦屈龍蛇，依然舊遊處。", "觸物轉多時，何以消百慮。", "陶潛早解此，撒手賦歸去。", "紛紛世俗流，何用苦懽飫。", "試問皎然師，茶香得誰助。"]'),
('bac30921-190e-468f-ae4e-238a59e2a778','別趙運使二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','君子豈無欲，有欲未足憂。',72,'全唐诗/poet.song.162000.json','["君子豈無欲，有欲未足憂。", "百計護此短，此心尚可求。", "向來畏人言，言者不肯休。", "不畏固未可，無言我誰尤。", "事當究本源，瑣細不足籌。", "有疾不忌醫，膏肓尚能瘳。"]'),
('fb338ba5-3cd2-4f39-9487-a3d34a2065c3','別趙運使二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','用民如用馬，可御不可馳。',96,'全唐诗/poet.song.162000.json','["用民如用馬，可御不可馳。", "論人如論醫，貴常不貴奇。", "古來才智士，日與功名期。", "儻遂李廣侯，文帝數乃奇。", "先生盤石宗，一節江南歸。", "聖皇夜半席，寧以鬼神移。", "遥知清問下，萬里寄一辭。", "當使觳觫牛，不獨見乃知。"]'),
('29f89aa1-217e-4981-ba97-3b7ef8116a56','送廬陵李宰養直之官兼呈劉寺簿四首  其一','彭龜年','宋','宋诗','song-poetry','','[]','理財非鑿空，簡訟在謹始。',48,'全唐诗/poet.song.162000.json','["理財非鑿空，簡訟在謹始。", "林繁去冗根，巵漏無溢水。", "此理容可觀，妙處要深體。", "豈惟宰一邑，天下亦如此。"]'),
('1132cf00-6c21-4bea-a779-2da202c3a706','送廬陵李宰養直之官兼呈劉寺簿四首  其二','彭龜年','宋','宋诗','song-poetry','','[]','治邑即治家，愛民如愛己。',48,'全唐诗/poet.song.162000.json','["治邑即治家，愛民如愛己。", "不須馳廣莫，觀遠自近始。", "君才成風斤，鼻堊有餘地。", "吾言尚敢狂，快處須反視。"]'),
('fe0f523a-ccb2-426f-86a0-41fd497ae188','送廬陵李宰養直之官兼呈劉寺簿四首  其三','彭龜年','宋','宋诗','song-poetry','','[]','入仕不爲宰，無異面牆壁。',48,'全唐诗/poet.song.162000.json','["入仕不爲宰，無異面牆壁。", "如何今世人，指作富貴厄。", "區區爲身謀，反謂第一策。", "皇皇百里民，誰爲訪休戚。"]'),
('8762b783-bf79-4f4e-a104-f6976996b025','送廬陵李宰養直之官兼呈劉寺簿四首  其四','彭龜年','宋','宋诗','song-poetry','','[]','澡身有至理，面垢吾能索。',48,'全唐诗/poet.song.162000.json','["澡身有至理，面垢吾能索。", "負背膚所受，非人孰湔滌。", "詩人有良玉，猶藉他山石。", "況復吾所師，且喜得親炙。"]'),
('e9d31547-6514-4de8-80f9-ce8a4adead2d','別劉寺簿子澄赴岳州倅','彭龜年','宋','宋诗','song-poetry','','[]','新蟬鳴高柳，輕鷗弄晴川。',204,'全唐诗/poet.song.162000.json','["新蟬鳴高柳，輕鷗弄晴川。", "浮家作遠遊，觸熱豈所便。", "武昌古都會，形勝兩國肩。", "貔貅雜民居，烽火照敵邊。", "朝廷重牧守，尤需治中賢。", "君侯文章家，班馬不敢先。", "墨莊一種子，落實今幾年。", "瞠乎出其後，獨得道學傳。", "誠身自孝悌，玩理潛天淵。", "悠然靜中春，洶洶風濤前。", "四海滿譽望，諸公爭挽牽。", "容臺志不舒，別駕用未專。", "去就抑何心，行可吾亦然。", "余也溝瀆質，誤辱青黄妍。", "工夫懇切切，習氣猶拘攣。", "居然作別離，欲別思綿綿。", "歸鴻幾時來，江樹底晚烟。"]'),
('ba094ce1-d54b-4dae-bde9-0d18c0e322b3','別張袁州五首  其一','彭龜年','宋','宋诗','song-poetry','','[]','愛民有誠心，發用非己私。',72,'全唐诗/poet.song.162000.json','["愛民有誠心，發用非己私。", "齊王累己見，乃以小大移。", "冠履自貴賤，痛癢一體隨。", "萬事有定理，應之當坦夷。", "儻以我好惡，定非真是非。", "光風霽月中，寧許栽藩籬。"]'),
('d0192586-ae3a-4423-bf80-85f8ce430001','別張袁州五首  其二','彭龜年','宋','宋诗','song-poetry','','[]','富貴不可求，名節可不修。',72,'全唐诗/poet.song.162000.json','["富貴不可求，名節可不修。", "韓公三上書，所願略不酬。", "柳子百世文，莫洗一日羞。", "要須外無累，乃免罟獲憂。", "青青最高松，藤蘿所綢繆。", "繁陰豈足羨，試看風露秋。"]'),
('8a08f3cc-a447-4f66-99bd-02e9475f500e','別張袁州五首  其三','彭龜年','宋','宋诗','song-poetry','','[]','袁人思君侯，事事皆甘棠。',72,'全唐诗/poet.song.162000.json','["袁人思君侯，事事皆甘棠。", "君侯亦念之，疾苦如己傷。", "向來趣引輸，詔許仍舊章。", "抗疏論不足，古人所未嘗。", "此請久不下，公歸奏明光。", "渠儂未知公，尸祝無相忘。"]'),
('34ca51ad-9f93-44ad-bb1e-d63bcbe7e648','別張袁州五首  其四','彭龜年','宋','宋诗','song-poetry','','[]','弦急無和聲，行疾多窘步。',72,'全唐诗/poet.song.162000.json','["弦急無和聲，行疾多窘步。", "從容應萬變，乃有天下度。", "先生經綸才，所至祛百蠹。", "一州直易耳，治者弗敢措。", "弱翁霽威嚴，猶被功名誤。", "孰知觀過仁，一蹴超聖處。"]'),
('cf8fe9d9-bae7-4cce-bccb-5ff6fe0e7507','別張袁州五首  其五','彭龜年','宋','宋诗','song-poetry','','[]','平生學不力，莫移資稟偏。',72,'全唐诗/poet.song.162000.json','["平生學不力，莫移資稟偏。", "疎愚寡周防，戇直絀巧諞。", "出身仕官府，何幸依仁賢。", "樸樕本無庸，刻畫幾成妍。", "江湖政浩蕩，雲漢難攀緣。", "何以慰我思，一語當韋弦。"]'),
('300c725c-c054-4017-b1be-4dc4e049881e','別宜春柯宰','彭龜年','宋','宋诗','song-poetry','','[]','秋風掠梧桐，歲月去如擲。',192,'全唐诗/poet.song.162000.json','["秋風掠梧桐，歲月去如擲。", "功名趁强健，君子有行役。", "朝家政急賢，黼座不滿席。", "巍巍廟堂望，留客良獨惜。", "誰爲君蘭言，亦有子公力。", "居然懷墨綬，懽喜動顔色。", "宰邑世情難，指作富貴厄。", "公嘗爲我言，百里豈擯斥。", "雖無槐鼎貴，均是代天職。", "人方事趣辦，聲譽已赫赫。", "公獨安其常，容與不可迫。", "靜觀物議定，豈止較尋尺。", "願公充此心，壽此一世脈。", "行行見天子，清問下文石。", "區區嘗試語，要不若親歷。", "公看江南貧，此豈州縣責。"]'),
('e92de52c-9739-46bf-b9fe-91973d516a57','和向倅韻  其一','彭龜年','宋','宋诗','song-poetry','','[]','誤身利名場，無異一釜甑。',168,'全唐诗/poet.song.162000.json','["誤身利名場，無異一釜甑。", "置之水火間，謬以力取勝。", "人生具天則，發見亦有證。", "如水行地中，投隙即流迸。", "但恐人欲縱，勃若一民橫。", "志師儻自强，萬慮當退聽。", "誰能學禪伯，絕物以求定。", "吾聞至人言，當識動中靜。", "萬變不可齊，一念終難正。", "口耳固在我，視聽復誰令。", "須從事上學，寧有物外性。", "能用使太平，不用我何病。", "斯言聞亦多，究竟終未瑩。", "從今三爇香，願以公爲鏡。"]'),
('d58d561c-340c-40a5-8d28-efb0290387e3','和向倅韻  其二','彭龜年','宋','宋诗','song-poetry','','[]','今日若馭風，前日如負甑。',168,'全唐诗/poet.song.162000.json','["今日若馭風，前日如負甑。", "乘興試一出，意到即爲勝。", "薌林有高人，能識未病證。", "談鋒不可遏，勇若春筍迸。", "美名戒多取，夫子無太橫。", "鍾期不世出，誰作山水聽。", "人生具物則，天命我當定。", "起居孰非真，寂滅豈是靜。", "毫釐不密察，天地失其正。", "聖學有終始，謨訓嚴于令。", "窮理以致知，持敬乃成性。", "倘從口耳學，莫救膏肓病。", "大本若不立，寧論語未瑩。", "塗澤欲自妍，何以逃水鏡。"]'),
('2e15197b-dce6-403c-84c0-96810f9e5d1d','別孫隠甫','彭龜年','宋','宋诗','song-poetry','','[]','君家金石臺，我家富壽岡。',240,'全唐诗/poet.song.162000.json','["君家金石臺，我家富壽岡。", "十馹苦不遠，半世成相望。", "我爲一貧驅，觸熱來帝鄉。", "塵垢面未頮，鬰結志不强。", "下馬忽見君，喜劇幾欲狂。", "未語心已傾，既坐形俱忘。", "醒我醉夢中，祓我冰雪旁。", "主人知客深，對著夜雨牀。", "猶恐客意短，渠渠羅酒漿。", "蟹螯擘新肥，荔子含生香。", "晚歸候月影，早游趁湖光。", "都城六月中，公卿簿書忙。", "而我乃與君，專此風露涼。", "笑語雖雜亂，理到味自長。", "平生區區願，恰此一月償。", "遽然委我去，令人熱中腸。", "兒女惜別離，丈夫重行藏。", "敢因杯酒行，感慨徒悲傷。", "君去起我思，綵衣拜重陽。", "願言各努力，白髮行中堂。"]'),
('3ddfb081-3974-4dbe-b765-f22978f6c3a8','送劉寺簿知衡州','彭龜年','宋','宋诗','song-poetry','','[]','刺史官已尊，郴左郡尤古。',72,'全唐诗/poet.song.162000.json','["刺史官已尊，郴左郡尤古。", "太常墨莊家，帝命分竹五。", "扶摇負勁翮，巨浸落雙櫓。", "誰能極所至，千里看舉武。", "紛紛轓兩朱，局局印一組。", "世無元道州，萬物氣不吐。"]'),
('a4ce6cd1-a0c6-4ae5-9186-c731210db177','藥翁吟','彭龜年','宋','宋诗','song-poetry','','[]','有翁憂思深，挾藥救一世。',168,'全唐诗/poet.song.162000.json','["有翁憂思深，挾藥救一世。", "大聲疾其呼，負篋即都市。", "凝視徹河漢，覘色見腸胃。", "巍峨一男子，面澤勝粉膩。", "翁前亟與語，腠理中邪沴。", "再三猶不聞，掉臂若欲避。", "塗人競揶揄，毋乃太逐利。", "那知此翁心，肝腦作布施。", "厭見大官醫，十謁九不值。", "高車索禮貌，疑疾致金幣。", "侵尋疾已深，鍼達不可暨。", "却推主人癡，疾欲勝砭劑。", "天寒日以深，衰態日以至。", "稍覺念翁來，西風政憔悴。"]'),
('bfd3eeab-777c-4561-a91a-8b7d11a11b80','送楊誠齋赴江東漕','彭龜年','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','愛公喜公去，愛國喜公住。',192,'全唐诗/poet.song.162000.json','["愛公喜公去，愛國喜公住。", "公去不可留，一節江東路。", "停杯與公別，瑣瑣不足疏。", "金陵古都會，形勢天所付。", "江淮有前蔽，荆楚無後顧。", "矯首對山河，亦足發外懼。", "錢唐六十年，帖帖泰山措。", "繁華視舊都，無復郇瑕慮。", "郇瑕僅憂貧，雖貧猶未斁。", "安得小范老，前席借一箸。", "重畫汴洛謀，起此宴安痼。", "金粟互輸送，甲兵更守戍。", "去來徜習慣，緩急乃暇豫。", "耳聞不如見，公見況超悟。", "願公細平章，心期一言寤。", "從此日暮雲，不外錦囊句。"]'),
('6d112d88-965a-46f4-a239-1c73aa495c4d','壽張京尹','彭龜年','宋','宋诗','song-poetry','','[]','紫巖天下志，勇決如百川。',252,'全唐诗/poet.song.162000.json','["紫巖天下志，勇決如百川。", "一身扶三綱，百醜妬獨妍。", "南軒經世學，仰嗣千聖傳。", "匆匆造膝陳，衆鳥驚虛弦。", "油幢入楚澤，不復夢細旃。", "公乘一節朝，遇合君適然。", "物弛久必張，後美開諸先。", "區區人力衰，今乃還其天。", "夷夏早知名，家國嗟獨賢。", "用大力有餘，入細心愈研。", "三年尹王都，警柝清夜眠。", "忠言出荷橐，妙斡天機旋。", "反視班伯輩，但覺口語譞。", "要知源流異，孰似周公前。", "江湖秋已多，宇宙清無邊。", "氣凝萬類實，人亦體其全。", "況是嵩降辰，誰頌舂容篇。", "願公如紫巖，而復得君專。", "願公如南軒，而享箕翼年。", "赤手洗甲兵，黑頭出貂蟬。", "却從祝融峰，高處尋偓佺。"]'),
('f5be2257-612e-4978-a8e3-bbc6b40009e1','酒醒','彭龜年','宋','宋诗','song-poetry','','[]','世間顛倒事，一切自酒出。',72,'全唐诗/poet.song.162000.json','["世間顛倒事，一切自酒出。", "醒時清明心，醉後不可覓。", "醉時顛倒苗，或發醒時實。", "酒能醉人形，不能醉人心。", "心儻有主宰，萬變不可淫。", "大禹惡旨酒，拜善功最深。"]'),
('100c47b9-ffa6-4b22-83c7-047dadfb08a0','題王仲顯梅谷','彭龜年','宋','宋诗','song-poetry','','[]','樓前梅十圍，負背花千樹。',192,'全唐诗/poet.song.162000.json','["樓前梅十圍，負背花千樹。", "種花識花性，培養隨好惡。", "花無十日好，不憚千日慮。", "那知花已嬌，疲憊風能蠱。", "爭如歲寒操，盤結不擇土。", "時當氣栗烈，天地閉其戶。", "蓬蓬起南海，呼吸萬竅怒。", "向來桃李輩，縮氣不敢吐。", "惟有冰玉姿，秀發略不沮。", "靜觀萬物理，參差乃如許。", "不見千金子，宴坐危堂廡。", "一朝遇變故，倉猝失所措。", "不見陋巷士，脫齒甘捽茹。", "翛然天地間，了不識憂懼。", "達人善觀物，在我乃不喻。", "須上最高樓，方能了真趣。"]'),
('f5ed3403-d07e-48cd-a759-d26bd785abf6','送李眉州','彭龜年','宋','宋诗','song-poetry','','[]','出捧毛義檄，不違菽水歡。',168,'全唐诗/poet.song.162000.json','["出捧毛義檄，不違菽水歡。", "歸侍潘安輿，能宣詔條寬。", "古來忠孝事，兼此良獨難。", "是心無中邊，寧擇陸與盤。", "區區平反念，雖喜不勝殘。", "那知容色溫，足使田里安。", "韋編三絕書，十載胸中蟠。", "用處義自精，何適非其端。", "如水行地中，渾渾不可殫。", "尚恨斗大州，不足觀其瀾。", "我昔欲見君，恨不生羽翰。", "及茲與君別，一飲盟已寒。", "人生聚散情，欲語徒辛酸。", "惟此一寸心，萬里聊相觀。"]'),
('5cc3751d-52d2-458b-b66c-b88e92a27587','送張少卿知漢州用漢字韻','彭龜年','宋','宋诗','song-poetry','','[]','家傳張長公，直節可敬嘆。',288,'全唐诗/poet.song.162000.json','["家傳張長公，直節可敬嘆。", "居官不取容，安有鄙夫患。", "奏劾司馬門，乃翁寧可犯。", "驚蹕當罰金，法令戒反汗。", "奈何盜環人，使遭滅族難。", "惟摯有父風，彼美淵明贊。", "由來陰德深，雲仍繼名宦。", "西州清河家，簪紱誇里閈。", "我公翰墨英，蚤歲擢三館。", "立朝物望歸，駸駸歷華貫。", "蓴羹忽思歸，周邦喜良翰。", "三節歌皇華，風采肅廉按。", "召歸一再遷，卿月光有粲。", "廷尉天下平，異論乃冰炭。", "守道當守官，聞風志立懦。", "分符復西歸，顧憂寬宵旰。", "廣漢最繁麗，地望蜀郡冠。", "房湖天下稀，公餘可吟玩。", "十頃玻璃風，和氣來隔岸。", "過家亦足榮，觸熱去不憚。", "三世居此官，盛事聞見罕。", "甘棠百年思，蔽芾陰更滿。", "少城我從公，轉首歲六換。", "人生一浮萍，誰料聚與散。"]'),
('e87dd5ac-9b58-461f-87d8-ebfe9c2279b2','慈順堂','彭龜年','宋','宋诗','song-poetry','','[]','我官廣文館，門巷正蕭索。',120,'全唐诗/poet.song.162000.json','["我官廣文館，門巷正蕭索。", "王孫幸過我，開口有請託。", "索詩慈順堂，一再不可却。", "人心有太平，此豈易描摸。", "夭夭吹棘心，韡韡燦棣萼。", "君方大歡足，天地費酬酢。", "而我獨零丁，詩復那可作。", "因君索詩苦，謾薦嘗試藥。", "中庸十五章，此理非外鑠。", "反身若不誠，爲善終未樂。"]'),
('22b0742f-adf6-4ab0-a05f-030989e54e76','尚絅堂','彭龜年','宋','宋诗','song-poetry','','[]','人情畏所見，假善以自欺。',84,'全唐诗/poet.song.162000.json','["人情畏所見，假善以自欺。", "不畏或未死，心僞誰能醫。", "風雷動淵默，日月行屏幃。", "念起物自形，矢決猶可追。", "而乃如琴張，堂堂亦何爲。", "君子非惡文，文勝質乃衰。", "試看堂前草，安得青如茲。"]'),
('4841a04a-4586-4407-a82b-bdafeb45356e','同陳祕監諸丈送黄商伯守常州石叔訪守上饒會于艮山門張園以人生五馬貴莫受二毛侵分韻得貴字','彭龜年','宋','宋诗','song-poetry','','[]','惠山滋華池，玉山潤百卉。',168,'全唐诗/poet.song.162000.json','["惠山滋華池，玉山潤百卉。", "二賢競出守，山水亦自慰。", "人生別離難，朋舊走相謂。", "尅期會南湖，肯託簡書畏。", "敬酌萬石君，欲歎不敢愾。", "願如玉山高，物物飽生氣。", "又酌雙井公，一舉大白既。", "願如惠山清，滴滴濯腑胃。", "擇侯須擇賢，無乃拔其彙。", "帝城人欲入，競進去乃貴。", "誰無螻蟻心，早去亦有味。", "朝家急賢秋，人物欠經緯。", "想當分符時，欲遣意猶未。", "幸無疾其驅，有詔儻可暨。"]'),
('980015df-8046-4767-8132-e42e9abea027','送呂子約赴天台倅','彭龜年','宋','宋诗','song-poetry','','[]','少讀麗澤書，投老未盡識。',144,'全唐诗/poet.song.162000.json','["少讀麗澤書，投老未盡識。", "譬如涉大海，渺不見其極。", "去之若有失，從之了無得。", "約兄自西來，爲我倒胸臆。", "始知公輸巧，要不外繩墨。", "從茲往來頻，不辨主與客。", "去住寧有定，長恐使南北。", "誰題治中輿，別日忽相偪。", "欲留留不可，把袂三歎息。", "送君浙河西，狂濤立如植。", "君其穩駕浪，我亦理行幅。", "斯意莽無窮，所願各努力。"]'),
('77d5acc1-80e7-45db-8e9a-7c820b55abec','送何同叔赴湖南漕','彭龜年','宋','宋诗','song-poetry','','[]','疇昔登賢書，夫子持文衡。',156,'全唐诗/poet.song.162000.json','["疇昔登賢書，夫子持文衡。", "每見輒忽別，問端不能更。", "一從齒周行，後先佐司成。", "未幾奉辟書，復接臺中評。", "詞色陶春和，風味浥秋清。", "人生事好乖，歲晚意始傾。", "云何千里去，一節湘中行。", "留行我無說，脫去公方榮。", "人言轉輸重，我視錙銖輕。", "望之拾遺願，公豈少此情。", "向來否泰疏，上亦知忠誠。", "公身有內外，公意無虧盈。", "雁來書可慰，細數新豐程。"]'),
('74534ee3-7874-4f78-95c8-4d19e2c4aae1','送范文叔知彭州','彭龜年','宋','宋诗','song-poetry','','[]','吾友范文叔，家世岷峨州。',192,'全唐诗/poet.song.162000.json','["吾友范文叔，家世岷峨州。", "忠純自性分，耿耿明月秋。", "朅來聲利場，況與造物侔。", "汲引如不及，不進不肯休。", "酸鹹性難齊，委曲能調柔。", "一朝善類合，人亦多君謀。", "或者以己量，謂君相比周。", "在我亦何感，太空雲自浮。", "俄然動歸興，瞥去輕于鷗。", "始知進退間，君子得自由。", "聖主羅衆俊，巖穴窮冥搜。", "何以斗大州，著我第一流。", "無人子思側，殷勤爲王留。", "謬當豹尾間，對此誠包羞。", "五馬豈不貴，吾非爲君籌。", "君儻知我心，毋忘天下憂。"]'),
('44b03e7f-ce2c-4299-9732-322c2b1bda4f','別周侍郎五首  其一','彭龜年','宋','宋诗','song-poetry','','[]','東家十畝橘，治蠹苛于獄。',48,'全唐诗/poet.song.162000.json','["東家十畝橘，治蠹苛于獄。", "課童事剔決，生意長不足。", "不如西家農，末麥土已熟。", "一朝種子落，坐見天地綠。"]'),
('5d5acb43-267f-4171-9fba-fa1c75268665','別周侍郎五首  其二','彭龜年','宋','宋诗','song-poetry','','[]','人便適性事，醫乃逢其癡。',48,'全唐诗/poet.song.162000.json','["人便適性事，醫乃逢其癡。", "有藥不投疾，但欲甘于飴。", "安知萬全方，非取頰舌宜。", "誰能味此苦，恐厭功效遲。"]'),
('435cd5cc-f714-48df-a956-0dea78887bf5','別周侍郎五首  其三','彭龜年','宋','宋诗','song-poetry','','[]','太和到處萌，物各從所受。',48,'全唐诗/poet.song.162000.json','["太和到處萌，物各從所受。", "老農嘉穀心，自覺稊稗醜。", "道旁有荆棘，斤斧不得宥。", "移根著山阿，吾亦付薪槱。"]'),
('bed03a3a-fbd8-45d0-8c01-dae363cfaa4c','別周侍郎五首  其四','彭龜年','宋','宋诗','song-poetry','','[]','鵲有護巢心，鴉負奪巢力。',48,'全唐诗/poet.song.162000.json','["鵲有護巢心，鴉負奪巢力。", "紛爭互勝敗，卒乃覆其室。", "魯雞本非鵠，伏鷇出羽翼。", "我無拒爾心，萬物同一息。"]'),
('6863c9be-2e5a-4fcf-9106-29da3f0cc99d','別周侍郎五首  其五','彭龜年','宋','宋诗','song-poetry','','[]','創平痛方定，醉甚忽解酲。',48,'全唐诗/poet.song.162000.json','["創平痛方定，醉甚忽解酲。", "乃作翻然思，遽能免心驚。", "君子足遠慮，小人無隠情。", "有言儻可吐，守口何如瓶。"]'),
('1b861441-a5b7-4a11-b312-45ab2dfbc93d','讀書吟示鉉','彭龜年','宋','宋诗','song-poetry','','[]','吾聞讀書人，惜氣勝惜金。',144,'全唐诗/poet.song.162000.json','["吾聞讀書人，惜氣勝惜金。", "累累如貫珠，其聲和且平。", "忽然低復昂，似絕反可聽。", "有時靜以默，想見紬繹深。", "心潛與理會，不覺詠歎淫。", "昨夕汝讀書，厲響驚四鄰。", "方其氣盛時，聲能亂狂霖。", "倏忽氣已竭，口亦遂絕吟。", "體疲神自昏，思慮那得清。", "安能更雋永，溫故而知新。", "永歌詩有味，三復意轉精。", "勉汝諷誦餘，且學思深湛。"]'),
('5e4f2c38-c4cd-4f58-8423-926b2a19ba4b','土缶','彭龜年','宋','宋诗','song-poetry','','[]','土缶寡譏誚，白璧多瑕疵。',60,'全唐诗/poet.song.162000.json','["土缶寡譏誚，白璧多瑕疵。", "毀譽未必公，名起謗亦隨。", "天下有真是，不在愛惡時。", "青青荆棘場，拍拍蝴蝶飛。", "不如歲且寒，更試松柏姿。"]'),
('64b6013a-7a56-4b6f-a554-42f4726e4052','臨江郡齋邀凉亭分韻得居字','彭龜年','宋','宋诗','song-poetry','','[]','子猷猶愛竹，愛竹意已疎。',120,'全唐诗/poet.song.162000.json','["子猷猶愛竹，愛竹意已疎。", "著脚踏危機，肉相元未除。", "要識竹情性，顧我求其初。", "是中儻虛明，處處我與居。", "公侯胸中竹，不受富貴鋤。", "平生對此君，意足不願餘。", "炎天憩斯亭，灑灑涼風諸。", "涼風不可招，招得還躊躇。", "悠然忽相會，我適還似渠。", "明朝有公事，此意當何如。"]'),
('45bd97b0-0198-4c0f-bbf4-8f0ac5d9a6f6','輓張南軒先生八首  其一','彭龜年','宋','宋诗','song-poetry','','[]','妖氛動寥廓，白日漫沙塵。',108,'全唐诗/poet.song.162000.json','["妖氛動寥廓，白日漫沙塵。", "忠義不可沒，扶携憫如邠。", "人情易勇怯，鼓舞吾當伸。", "忽忘天地讎，却見玉帛鄰。", "淪胥五十年，銳氣日以堙。", "皇皇忠獻家，正議摩秋旻。", "隻手提三綱，一縷挽萬鈞。", "狂敵不足滅，頹俗何由仁。", "千載諸葛公，相望吾霑巾。"]'),
('4652ef13-445c-4b12-9ddd-04a47e1fe3be','輓張南軒先生八首  其二','彭龜年','宋','宋诗','song-poetry','','[]','世無鄒孟氏，聖道危于絲。',108,'全唐诗/poet.song.162000.json','["世無鄒孟氏，聖道危于絲。", "學者迷統緒，擾擾徒外馳。", "況有釋老輩，竊窺如鬼魑。", "苦彼疑似說，陷我高明資。", "偉然周與程，振手而一麾。", "源流雖未遠，淆濁亦已隨。", "公如一陽復，寒烈已可知。", "斯文續以傳，歲晚非公誰。", "傷哉後來者，此世亡此師。"]'),
('c571f406-563a-4d1e-82ba-b4853ecd1d91','輓張南軒先生八首  其三','彭龜年','宋','宋诗','song-poetry','','[]','邪正不兩立，何異蕕與薰。',108,'全唐诗/poet.song.162000.json','["邪正不兩立，何異蕕與薰。", "寧懷愛憎念，趣尚難同羣。", "向來閶闔疏，杯水沃烈焚。", "雖無撲滅期，固亦摧炎熏。", "黄鍾動孤管，衆樂知有君。", "祇今才數年，薈蔚朝隮雲。", "公身雖已殞，公言猶可聞。", "所期動九天，從此涇渭分。", "寧願如曲江，一尊酹孤墳。"]'),
('5fb97d3d-5544-45df-93fc-849dd2ca680a','輓張南軒先生八首  其四','彭龜年','宋','宋诗','song-poetry','','[]','時平有賸賊，人夥無寬鄉。',108,'全唐诗/poet.song.162000.json','["時平有賸賊，人夥無寬鄉。", "上下日逼趣，彫瘵誰得將。", "紛紛幾守宰，所較有短長。", "專利計錙銖，治法出一方。", "惟公作州牧，萬物驚初陽。", "仁心所發施，四達無門旁。", "丁庸省嚴瀨，鹽筴寬南荒。", "直惟此方人，歲時悲奉嘗。", "凡公不到處，今恨無甘棠。"]'),
('f50ab55d-6c15-44b6-9a16-354a73ffeb57','輓張南軒先生八首  其五','彭龜年','宋','宋诗','song-poetry','','[]','吳楚尚禨鬼，習俗久已尨。',96,'全唐诗/poet.song.162000.json','["吳楚尚禨鬼，習俗久已尨。", "淫詞張鬰氣，馳走如奔瀧。", "春秋嚴報祈，夜鼓紛逢逢。", "娛神雜羽翿，釃酒堆甖缸。", "間用次睢社，千金博奇庬。", "公能揭正理，開此一世憃。", "寧關祠有無，廬屋記崆㟅。", "要令冥行人，從茲得明釭。"]'),
('d584be96-7e61-4d3f-8825-02ee9847c656','輓張南軒先生八首  其六','彭龜年','宋','宋诗','song-poetry','','[]','平生中興念，渴飲而饑食。',108,'全唐诗/poet.song.162000.json','["平生中興念，渴飲而饑食。", "落落不可合，令人氣填臆。", "歸來牧桂州，才人用轉窄。", "撫摩日多暇，整整戎事飭。", "偏伍聯浮游，坐作親部勒。", "異時了劇寇，乃此諸校力。", "論兵較利鈍，夫豈謂深識。", "牛刀何施宜，功乃在鷄肋。", "誰知我公心，抆淚三歎息。"]'),
('5f8ffc0e-e35a-4f8d-9d15-f90a2742147e','輓張南軒先生八首  其七','彭龜年','宋','宋诗','song-poetry','','[]','拱璧墮泥塗，康瓠置壇墠。',108,'全唐诗/poet.song.162000.json','["拱璧墮泥塗，康瓠置壇墠。", "天心與人事，頗似好乖舛。", "賢愚真是非，每向死生辨。", "哀榮若相迕，遺恨常不免。", "前年建安公，罹此二氣沴。", "今年公復死，殞我一世善。", "龍文百斛鼎，功在白玉鉉。", "斯人太薄命，長苦樂事鮮。", "時因思賢憂，終夕長展轉。"]'),
('0b1ccee2-a3c3-4cd4-b63e-22043e1c3d09','輓張南軒先生八首  其八','彭龜年','宋','宋诗','song-poetry','','[]','昔年清江上，再拜投漫刺。',108,'全唐诗/poet.song.162000.json','["昔年清江上，再拜投漫刺。", "匆匆僅班荆，春風滿懷袂。", "自此成契闊，書郵剖疑義。", "此理有會通，萬徹而一致。", "縷縷爲我言，顛倒行間字。", "濯手時一觀，如烹大鼎胾。", "嘆我無持操，莫勵四方志。", "君子不再見，已負終身愧。", "從今一杯月，永墮湘中淚。"]'),
('b0320638-cd3c-40d9-a90a-f1fab0f2a483','登上封半山而霧大起歎而有作','彭龜年','宋','宋诗','song-poetry','','[]','憶昨雨霽投招提，五峰幻出如新沐。',192,'全唐诗/poet.song.162000.json','["憶昨雨霽投招提，五峰幻出如新沐。", "僧言一月無此奇，正直由公感通速。", "傾曦已沒暝靄生，竚立危亭看不足。", "遂扶晨策陵嶇嶔，要識祝融真面目。", "輕陰閣雨日將升，淺霧噴雲生半腹。", "晦明變化在俄頃，山鬼無端太翻覆。", "東西南北杳不知，天柱諸峰固難矚。", "因思世事無不然，氛垢時多少清淑。", "良辰一遇信可欣，濁世相遭匪予辱。", "湘纍爲此賦遠遊，要待棋終看結局。", "嗟我寧能待汝清，原隰征夫駕方趣。", "安得韓公劍倚天，決斷浮雲取新旭。"]'),
('834af0f9-132d-42e3-b780-b922f0d7b21a','送趙使君老父吟','彭龜年','宋','宋诗','song-poetry','','[]','使君朝天騎霜蹄，朔風獵獵吹裳衣。',288,'全唐诗/poet.song.162000.json','["使君朝天騎霜蹄，朔風獵獵吹裳衣。", "鉦鐃聒天山谷應，旌旂弄日龍蛇飛。", "邦人遮留留不得，壯兒截鐙小兒泣。", "老翁數十相扶携，喘若筒吹行轉疾。", "且行且止相歎嗟，若怨若慕言紛拏。", "一翁指我門前土，向時蓁莽今桑麻。", "自言新年年九十，舊使姓名多記憶。", "從頭屈指細平章，清靜安寧今第一。", "狡胥每欲挑民爭，能令衽席生五兵。", "我公平易與民近，智巧有盡苦難行。", "里中少年號刀筆，曾向公庭瞯消息。", "歸來語我使君明，胸中是非紙上律。", "吾農疾苦年來多，公今歸去誰撫摩。", "留公無計可奈何，呼兒起舞吾當歌。", "官家神聖似堯禹，蠖濩宮深有言路。", "借留誰格向來書，猶有民謠能取否。", "或聞朝廷虛柄臣，須公經濟難逡巡。", "延英奏對刻易下，囊封且說江南貧。"]'),
('043c54c6-89a6-4144-bc7e-4b0f53a63bcd','送王仲顯赴瓊州','彭龜年','宋','宋诗','song-poetry','','[]','朔風獵獵搜離思，千山木葉飛東西，山聲互答轟鼓鼙。',320,'全唐诗/poet.song.162000.json','["朔風獵獵搜離思，千山木葉飛東西，山聲互答轟鼓鼙。", "日影倒亂摩旌旗，瓊山太守行赤帷，父老出餞相扶携。", "把袂惜別車去遲，仙都散吏挈榼隨，洗醆酌酒歌別離。", "別離之歌歌聲希，兒女子態不願爲，聖皇擇守先南陲。", "朱崖況復環生黎，黎山插天海四圍，黎人出沒如鬼魑。", "兇鯨蚋集不可羈，無異生縛虎與羆，乃令錯處海一涯。", "一日萬變藏幾微，趙張縮手龔黄癡，良二千石非公誰。", "公行南方易如歸，公舉南事易如携，向來鹽筴一局棋。", "白黑紛亂楊朱岐，公能辨晰是與非，袖有長疏天下知。", "口不可惜人可悲，鬼魑虎羆日夜伺，此時此事分安危。", "想公再拜辭玉墀，睿意懇惻亦在茲，九重寄公萬里師。", "紛紛獄訟不足治，從馹遽聽東南馳，定知召節封金泥。", "不然鹽筴更疇咨，服嶺以南公一夔。", "與公離別歌此詞，愧不以頌而以規。"]'),
('bb21a5fa-cdfb-4268-9516-c5bc93781266','病足歌','彭龜年','宋','宋诗','song-poetry','','[]','馬有足，疲馳驅。',64,'全唐诗/poet.song.162000.json','["馬有足，疲馳驅。", "牛有足，勞畬菑。", "不如大閽無更好，終日兀坐如黏黐。", "人言猶有深意存，螣蛇無足終能飛。", "此心儻欲與日競，莫道有足無亦病。"]'),
('91b7aed6-c907-4846-b7fa-a70d6e0f7094','送曾無瑕改常州','彭龜年','宋','宋诗','song-poetry','','[]','夫君愛民如愛己，不愛公卿愛刺史。',160,'全唐诗/poet.song.162000.json','["夫君愛民如愛己，不愛公卿愛刺史。", "得州如斗喜不禁，拍手催兒治行李。", "朝家急賢不惜官，日日中書有除旨。", "周南留滯太史歎，目斷子公書一紙。", "夫君却不薄淮陽，此見寧輸三十里。", "庖丁雖欲善刀去，無奈世間多巨髀。", "晉陵繁夥視三輔，歷徧屏風無可使。", "未央對罷天一笑，今日無憂惠山水。", "未容遠去引自近，早晚賜環差易耳。", "九華却恐怨君王，誤我明年花柳喜。"]'),
('40d3e65c-c082-47aa-9ca9-c7e58d953b6d','次韵教授兄友惠柑','彭龜年','宋','宋诗','song-poetry','','[]','泮宮老潘賢且仁，分義濃如手足親。',64,'全唐诗/poet.song.162000.json','["泮宮老潘賢且仁，分義濃如手足親。", "懸知故人在千里，健步遠來緘墨新。", "黄柑霜後愈精好，香味宛如包貢珍。", "分賞且用滌煩渴，不救萊蕪炊甑塵。"]'),
('9daadcad-c00d-426c-8172-424c732cc2b5','送任守赴邕管','彭龜年','宋','宋诗','song-poetry','','[]','吾聞廣南東西四十州，諸蠻錯處如蚍蜉。',226,'全唐诗/poet.song.162000.json','["吾聞廣南東西四十州，諸蠻錯處如蚍蜉。", "東州之蠻富珠貝，西州有馬供羣騶。", "一從隴右失芻牧，萬里山蹊來作足。", "部分驛使視行廄，路遠疲農輸食粟。", "邊頭給估不敢慳，內地供億那得閒。", "匹馬中人五家産，歲入不足充軍頒。", "天子擇侯嚴五管，橫山之雄視方面。", "大賢不合著炎方，一馬直應勞遠算。", "往時此地驚智高，四海俶擾如抑搔。", "要荒易動古所畏，況復立制爭錐刀。", "年來馬質亂三物，廊廟謀深匹夫忽。", "達官喜事失拊循，機矢銛矛變倉猝。", "遠利安蠻福及人，公行公行南中春。", "一篇駉頌誰能寫，足用愛民功到馬。"]'),
('edfa61e7-9d6d-4575-9422-cd962378bc50','別袁州司戶司馬行二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','四海司馬氏，大州從事賢。',48,'全唐诗/poet.song.162000.json','["四海司馬氏，大州從事賢。", "剸裁無劇務，抑鬰已三年。", "人在甘棠裏，夢回春草邊。", "知音有當路，何日踐英躔。"]'),
('d71ce27d-9d52-4658-a939-1a66873fbfe0','別袁州司戶司馬行二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','一見已草草，那堪更別離。',48,'全唐诗/poet.song.162000.json','["一見已草草，那堪更別離。", "事當防快意，學亦進潛思。", "此道今誰語，如公豈我私。", "何時一窗下，重與論心期。"]'),
('bb2de65c-3bba-4e5c-a069-a6aa424d8114','送牛守赴藤州二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','五馬南中去，脩途一月寬。',48,'全唐诗/poet.song.162000.json','["五馬南中去，脩途一月寬。", "暮年憂國切，今日愛民難。", "志大人無小，政平人自安。", "端能掃蠻瘴，莫作偶然看。"]'),
('f7a22d11-1bec-4c48-935f-e13d2cb9d271','送牛守赴藤州二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','半世幾契闊，今年又別離。',48,'全唐诗/poet.song.162000.json','["半世幾契闊，今年又別離。", "我應嗟去遠，人已恨來遲。", "宿草青無限，野花紅欲窺。", "藩車行有詔，山路且逶迤。"]'),
('2ec3c30b-b54c-4e6b-9e3b-df992b1bd965','送梁憲易節漕蜀二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','雨露收江上，星辰下益州。',48,'全唐诗/poet.song.162000.json','["雨露收江上，星辰下益州。", "有賢容在外，爲國豈無謀。", "德旨頻將遠，君心頓減憂。", "不然那有此，定自啟金甌。"]'),
('d84dc747-9b12-4dbb-b3fa-fb2ebaeb0fed','送梁憲易節漕蜀二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','峽口大江急，劍門天下奇。',48,'全唐诗/poet.song.162000.json','["峽口大江急，劍門天下奇。", "不因逢使節，安得入公詩。", "萬里輕來去，一心無險夷。", "可憐門下士，猶惜別離私。"]'),
('9fc9e89c-c76b-49cc-ace2-24c4463b8ae3','寄黄商伯兼簡詹元善','彭龜年','宋','宋诗','song-poetry','','[]','今日蠻荒好，逢人說桂林。',48,'全唐诗/poet.song.162000.json','["今日蠻荒好，逢人說桂林。", "祇應一片雪，端在兩公心。", "祈望羅明月，生黎斸水沈。", "滔滔迷所往，莫望指南針。"]'),
('6f8da56b-e46a-4baf-8ede-e5a2396ae02c','挽益陽縣丞趙參議','彭龜年','宋','宋诗','song-poetry','','[]','一種銀潢秀，清名仰太虛。',48,'全唐诗/poet.song.162000.json','["一種銀潢秀，清名仰太虛。", "甲科嘗擢第，午夜尚觀書。", "已覺身非我，那堪丞負余。", "斯人無復見，掩涕一欷歔。"]'),
('f0eea9b6-0e68-4b54-98db-4d825fbb2acf','挽熊仲賢監酒二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','歎息熊公子，胸中亦自奇。',48,'全唐诗/poet.song.162000.json','["歎息熊公子，胸中亦自奇。", "典衣緣客至，沽酒趁花期。", "滿眼皆知己，平生却數奇。", "一官終未試，回首不堪思。"]'),
('7d415fec-e15b-48b2-8234-a331c146e1ab','挽熊仲賢監酒二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','舉世嗟浮薄，誰堪寄死生。',48,'全唐诗/poet.song.162000.json','["舉世嗟浮薄，誰堪寄死生。", "空餘交友恨，不見急難情。", "我昔爲遊子，公方作遠征。", "那知成永訣，灑淚閉佳城。"]'),
('940f3a8b-a53b-420f-9505-9ea92cea2d7f','挽楊邦寧','彭龜年','宋','宋诗','song-poetry','','[]','心事誰能識，交遊得細論。',48,'全唐诗/poet.song.162000.json','["心事誰能識，交遊得細論。", "有居多水竹，此世老丘園。", "遺恨成千古，無人作九原。", "晚來風政惡，不忍賦招魂。"]'),
('95d5f639-1abb-4209-a244-2ffb817736e1','挽歐陽幼立','彭龜年','宋','宋诗','song-poetry','','[]','行輩多名宦，鄉閭愛老成。',48,'全唐诗/poet.song.162000.json','["行輩多名宦，鄉閭愛老成。", "身名了無恨，韋布却爲榮。", "久矣追談笑，居然隔死生。", "朔風搜宇宙，何日閉佳城。"]'),
('317e664b-23f9-4622-876b-0c8a6af73eff','挽朱彥博二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','重惜夫君去，哀吟思不窮。',48,'全唐诗/poet.song.162000.json','["重惜夫君去，哀吟思不窮。", "江淮經畫裏，風雨笑談中。", "志大長違俗，才高無近功。", "蓋棺公論出，誰不羨豪雄。"]'),
('ae59f117-9923-4139-8b50-6d3d61c3ea3b','挽朱彥博二首  其二','彭龜年','宋','宋诗','song-poetry','','["\u897f\u6e56"]','對語窗飛雪，橫舟月在灘。',48,'全唐诗/poet.song.162000.json','["對語窗飛雪，橫舟月在灘。", "西湖今會少，里社此盟寒。", "諸子齒猶稚，慈堂寢未安。", "俱成無盡恨，一見一辛酸。"]'),
('73a5ed31-19d4-4db8-98bf-685f43f82656','挽沈漕宜之父主管','彭龜年','宋','宋诗','song-poetry','','[]','蟬蛻軒裳早，冰融義理深。',48,'全唐诗/poet.song.162000.json','["蟬蛻軒裳早，冰融義理深。", "但知捐世累，誰復識公心。", "宇宙終埋玉，哀榮有賜金。", "遥憐九原上，烟雨暗寒林。"]'),
('1d0e00f8-995b-4000-99cf-787a597c5062','挽尤尚書二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','太史病已革，君王意尚疑。',48,'全唐诗/poet.song.162000.json','["太史病已革，君王意尚疑。", "欲爲宣室召，深動畫堂思。", "共起云亡歎，空嗟大用遲。", "九原如可作，願賦百身詩。"]'),
('bc0ac901-5cd6-408f-bf49-73d00b4ba049','挽尤尚書二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','天子青宮友，清時法從賢。',48,'全唐诗/poet.song.162000.json','["天子青宮友，清時法從賢。", "典型諸老舊，人物中興前。", "鎖闥堆黄紙，金華疊細旃。", "奪公何太速，誰與問蒼天。"]'),
('e547d220-1716-4356-8514-a41898bf19e9','挽虞夫人','彭龜年','宋','宋诗','song-poetry','','[]','欲說夫人事，誰能與世論。',48,'全唐诗/poet.song.162000.json','["欲說夫人事，誰能與世論。", "諸郎名節立，千古婦言尊。", "共此傷心日，懷哉錫類恩。", "佳城何處是，烟雨政黄昏。"]'),
('244cce21-4cbf-4001-a8aa-68aa67cea1d6','挽余丞相四首  其一','彭龜年','宋','宋诗','song-poetry','','[]','憶昨隨南史，常窺侍帝垣。',48,'全唐诗/poet.song.162000.json','["憶昨隨南史，常窺侍帝垣。", "負牆須密命，垂涕進忠言。", "懇懇精誠到，巍巍廟社尊。", "至今天下誦，功業在調元。"]'),
('ca0ba725-801b-4ffe-bad2-0104083653af','挽余丞相四首  其二','彭龜年','宋','宋诗','song-poetry','','[]','慨惜三朝老，忠勤一代師。',48,'全唐诗/poet.song.162000.json','["慨惜三朝老，忠勤一代師。", "冕裳親奉日，鼎鼐手調時。", "揖遜承三節，安危繫一辭。", "世平今似水，却歎哲人萎。"]'),
('e41478ca-6ad4-49f7-b9ca-8075dc81e1ae','挽余丞相四首  其三','彭龜年','宋','宋诗','song-poetry','','[]','三絕今非少，元功人未知。',48,'全唐诗/poet.song.162000.json','["三絕今非少，元功人未知。", "豈云公有憾，時恐世傳疑。", "誰解吟成史，寧憂罪到詩。", "詩成終自愧，空恨一年遲。"]'),
('099c28de-bcab-4908-ac58-ca3387412baf','挽余丞相四首  其四','彭龜年','宋','宋诗','song-poetry','','[]','疇昔危疑日，嘗爲根本謀。',48,'全唐诗/poet.song.162000.json','["疇昔危疑日，嘗爲根本謀。", "不緣公一語，誰識我深憂。", "分閫因重見，忘言只對愁。", "無窮千古意，有淚付東流。"]'),
('63cdfb92-e80a-444f-a9c4-ccb1ecce3454','代張京尹賀皇太子生辰三首  其一','彭龜年','宋','宋诗','song-poetry','','[]','問寢隨天子，論經有帝孫。',48,'全唐诗/poet.song.162000.json','["問寢隨天子，論經有帝孫。", "千年幾神聖，四世一乾坤。", "盛德從心遠，靈源自古存。", "欲知天意近，九月似春溫。"]'),
('e0b959a5-7009-4f84-b1c6-8bf252a1a66a','代張京尹賀皇太子生辰三首  其二','彭龜年','宋','宋诗','song-poetry','','[]','神光開甲觀，寰海作重陽。',48,'全唐诗/poet.song.162000.json','["神光開甲觀，寰海作重陽。", "世盡占人瑞，天應發子祥。", "山河涵玉露，象緯瀉銀潢。", "有道如三代，寧須不老方。"]'),
('623a2e43-a28e-45ba-96aa-1949485e3227','代張京尹賀皇太子生辰三首  其三','彭龜年','宋','宋诗','song-poetry','','[]','青禁羅雞戟，朱明出虎闈。',48,'全唐诗/poet.song.162000.json','["青禁羅雞戟，朱明出虎闈。", "布宣當浩穰，簡樂著精微。", "有志窺成畫，無材守一圻。", "徒能歌聖子，重潤更重暉。"]'),
('43dd3f3c-3565-407d-a0cf-95b8c1a391e6','奉和御賜進士詩','彭龜年','宋','宋诗','song-poetry','','[]','昭回雲漢揭天章，忽到人間足寵光。',64,'全唐诗/poet.song.162000.json','["昭回雲漢揭天章，忽到人間足寵光。", "必有颺言興率作，不須擊筑歎飛揚。", "湛恩汪濊傾多士，密意綢繆際萬方。", "何幸小臣陪俊造，一如豐草在成康。"]'),
('dc7b14da-c637-44fa-b0e8-027390fc3a2d','和袁州張守鹿鳴宴韻','彭龜年','宋','宋诗','song-poetry','','[]','太守興賢極選掄，奏書飛上帝王閽。',64,'全唐诗/poet.song.162000.json','["太守興賢極選掄，奏書飛上帝王閽。", "幾年霧隠南山豹，今日風摶北海鯤。", "得士不孤天子詔，贈行仍有古人言。", "向來勸駕應無此，且喜成周禮樂存。"]'),
('e7ad8c43-0626-453b-9c76-a594ce32b01c','和臨江庚子鹿鳴宴詩韻','彭龜年','宋','宋诗','song-poetry','','[]','風流藴藉足儀型，小屈旌旗鎮列城。',64,'全唐诗/poet.song.162000.json','["風流藴藉足儀型，小屈旌旗鎮列城。", "筆下雄深過班馬，胸中灑落似張程。", "載賡宵雅推多士，寧許皇荂繼大聲。", "聞說河南詩有序，從今亦有口傳名。"]'),
('1dbcc388-db41-43b8-b456-227de8a3e27d','和李東老韻','彭龜年','宋','宋诗','song-poetry','','[]','胸中塵慮厭多多，强把詩書細刮摩。',64,'全唐诗/poet.song.162000.json','["胸中塵慮厭多多，强把詩書細刮摩。", "幸有長官憐拜起，苦無公事礙吟哦。", "自慚俗駕爭相逐，不識高軒肯見過。", "天闊雁寒人又遠，一杯相屬意如何。"]'),
('e02a3331-1cdf-4de8-b7b0-085e8c21d865','和臨江丙午鹿鳴宴詩韻','彭龜年','宋','宋诗','song-poetry','','[]','暖日輕霜作小春，冥冥鴻雁正來賓。',64,'全唐诗/poet.song.162000.json','["暖日輕霜作小春，冥冥鴻雁正來賓。", "異時大比興賢禮，今日元侯勸駕身。", "西漢循良知賈誼，菑川父老送平津。", "眼中俱是青雲客，著我空慚跡已陳。"]'),
('18c99c74-2c3d-4ddb-8271-f5939f32276e','挽無爲軍王守','彭龜年','宋','宋诗','song-poetry','','[]','再分符竹向淮濆，只得除書下帝閽。',64,'全唐诗/poet.song.162000.json','["再分符竹向淮濆，只得除書下帝閽。", "不見使車隨邸吏，忽傳鳴馬蹙都門。", "豐碑未盡平生恨，哀些誰招天末魂。", "木落山空風獵獵，不堪俛首奠黄昏。"]'),
('1be54793-b527-4c0b-a767-c762a1e7f827','挽傅德芳主簿','彭龜年','宋','宋诗','song-poetry','','[]','亭亭梁木遽然傾，吾里諸生失典型。',64,'全唐诗/poet.song.162000.json','["亭亭梁木遽然傾，吾里諸生失典型。", "已向東維次箕宿，定知南斗厭文星。", "書盈故篋墨猶濕，影掛虛堂燈自青。", "忍聽咿嗚哀挽罷，一川東去杳冥冥。"]'),
('f87dc3a5-19df-404a-a662-9cc8acd776fb','鄂渚和章同年元榮鄧教授友龍微字韵  其一','彭龜年','宋','宋诗','song-poetry','','[]','愚魯何妨與俗違，夷途方始識心歸。',64,'全唐诗/poet.song.162000.json','["愚魯何妨與俗違，夷途方始識心歸。", "源源自是淵泉出，杲杲寧關庭燎輝。", "莫向天涯尋墨客，須知海內有公非。", "一杯何得如前日，竹杖芒鞋語翠微。"]'),
('facb7784-189a-4ad8-8501-009b420a10f2','鄂渚和章同年元榮鄧教授友龍微字韵  其二','彭龜年','宋','宋诗','song-poetry','','[]','世情如水與天違，誰識春從嶽麓歸。',64,'全唐诗/poet.song.162000.json','["世情如水與天違，誰識春從嶽麓歸。", "衮衮源流知有自，紛紛華鄂看相輝。", "今人得似古時少，我拙從教俗子非。", "且倒一樽尋樂事，奇章臺上晚風微。"]'),
('4bcbadaa-030a-4c06-99a9-fd988f757017','挽陳迪功','彭龜年','宋','宋诗','song-poetry','','[]','一念超然與世違，新蔬翦雨自甘肥。',64,'全唐诗/poet.song.162000.json','["一念超然與世違，新蔬翦雨自甘肥。", "只因墮雁能忘味，不使驚鷗尚見機。", "有子明經那不壽，如公積善未應非。", "從教天定知何似，果見賢孫擢第歸。"]'),
('17932f94-47e5-4360-9f2d-60daa0ffcc5c','慶元戊午臨江勸駕多士凡由進士科進者皆預焉且沿鄉人飲酒之意敘坐以齒酒半使君又出傑句寵其行某陳人也偶睹盛事思有以記之敬嗣嚴韻二首極愧不工尚幾鎸削  其一','彭龜年','宋','宋诗','song-poetry','','[]','太守興賢隘九州，勸爲之駕盛炎劉。',64,'全唐诗/poet.song.162000.json','["太守興賢隘九州，勸爲之駕盛炎劉。", "方今神聖四門闢，即日英雄一網收。", "在藻久觀鱣發發，食苹又聽鹿呦呦。", "來年候對春風仗，企首同趨曉月浮。"]'),
('be3bd8bc-6146-4634-87eb-ea67af1d0569','慶元戊午臨江勸駕多士凡由進士科進者皆預焉且沿鄉人飲酒之意敘坐以齒酒半使君又出傑句寵其行某陳人也偶睹盛事思有以記之敬嗣嚴韻二首極愧不工尚幾鎸削  其二','彭龜年','宋','宋诗','song-poetry','','[]','黨里情疎孰繼周，義年僅署竹冠劉。',64,'全唐诗/poet.song.162000.json','["黨里情疎孰繼周，義年僅署竹冠劉。", "燕毛不見三王盛，古意驚從一日收。", "已許陳人觀易易，再賡宵雅詠呦呦。", "試將旅語從頭記，七字應無一字浮。"]'),
('8fd24b6f-4145-4854-bbc1-5e3ff0253ae2','重九','彭龜年','宋','宋诗','song-poetry','','[]','露下風高足感傷，天君著意寫重陽。',64,'全唐诗/poet.song.162000.json','["露下風高足感傷，天君著意寫重陽。", "建安能賦推諸子，楚國悲秋又九章。", "我爲催租閣詩思，誰能送酒沃愁腸。", "黄花不解知人意，開遍籬根數百行。"]'),
('0c5725bf-b95a-4460-9ca0-24c93c064fcd','病中招孫醫士','彭龜年','宋','宋诗','song-poetry','','[]','鼕鼕纔動熱蒸蒸，直到更初漸漸清。',64,'全唐诗/poet.song.162000.json','["鼕鼕纔動熱蒸蒸，直到更初漸漸清。", "臟腑始堅今反利，痰涎愈盛氣難平。", "形容凋瘦真如鬼，耳目聰明粗似人。", "自是虛勞無可說，更將經絡爲推明。"]'),
('cd291c69-1794-4013-b640-d309e708fe18','邀凉亭五首  其一','彭龜年','宋','宋诗','song-poetry','','[]','勁節不可拗，浄色不受污。',24,'全唐诗/poet.song.162000.json','["勁節不可拗，浄色不受污。", "平生今日交，屹屹老桂樹。"]'),
('667e9213-26aa-4fc6-b27a-3d361c0e2690','邀凉亭五首  其二','彭龜年','宋','宋诗','song-poetry','','[]','史君大雅資，胸中淡無欲。',24,'全唐诗/poet.song.162000.json','["史君大雅資，胸中淡無欲。", "尤物能移人，猶有此數竹。"]'),
('1083d36a-ca00-49aa-8c3b-38d64e9cb439','邀凉亭五首  其三','彭龜年','宋','宋诗','song-poetry','','[]','凉風不肯來，偃蹇如相要。',24,'全唐诗/poet.song.162000.json','["凉風不肯來，偃蹇如相要。", "悠悠天地間，捨我從誰邀。"]'),
('32431ceb-ea63-48df-a604-d75d2efc3a5e','邀凉亭五首  其四','彭龜年','宋','宋诗','song-poetry','','[]','未必柳柳州，有此一餉凉。',24,'全唐诗/poet.song.162000.json','["未必柳柳州，有此一餉凉。", "心清境自靜，內躁物亦强。"]'),
('169ad4e0-485f-4878-a243-459d716c69cc','邀凉亭五首  其五','彭龜年','宋','宋诗','song-poetry','','[]','簿書本不俗，安能礙凉颸。',24,'全唐诗/poet.song.162000.json','["簿書本不俗，安能礙凉颸。", "少陵冰壑心，却恨與事違。"]'),
('657e4160-5754-4ca0-b3db-3a3a9cc3dd68','上帥漕閔雨十首  其一','彭龜年','宋','宋诗','song-poetry','','[]','天子治平切，一賢遠王畿。',24,'全唐诗/poet.song.162000.json','["天子治平切，一賢遠王畿。", "朝廷豈不重，赤子貧無依。"]'),
('af6e928d-7cbf-4c6f-839b-e47fc7433f69','上帥漕閔雨十首  其二','彭龜年','宋','宋诗','song-poetry','','[]','九雨當一晴，燥濕未應革。',24,'全唐诗/poet.song.162000.json','["九雨當一晴，燥濕未應革。", "那知平疇間，已作龜兆坼。"]'),
('5f63e83c-d28f-4b82-9cb4-0a2175b1500f','上帥漕閔雨十首  其三','彭龜年','宋','宋诗','song-poetry','','[]','一冤旱三年，此理乃無欺。',24,'全唐诗/poet.song.162000.json','["一冤旱三年，此理乃無欺。", "乖和自相召，天意容何私。"]'),
('776c3902-813a-45c4-b512-a3fb4d59f3ef','上帥漕閔雨十首  其四','彭龜年','宋','宋诗','song-poetry','','[]','文移急征輸，追逮及圭撮。',24,'全唐诗/poet.song.162000.json','["文移急征輸，追逮及圭撮。", "安得語里胥，反手逐旱魃。"]'),
('31801efe-1043-44ab-ae68-b8f81c0bfb40','上帥漕閔雨十首  其五','彭龜年','宋','宋诗','song-poetry','','[]','豪家低昂心，常對時虧盈。',24,'全唐诗/poet.song.162000.json','["豪家低昂心，常對時虧盈。", "卓氏一窖粟，殺人眂長平。"]'),
('a4cdfec8-acd5-48ce-bd79-092b1563064c','上帥漕閔雨十首  其六','彭龜年','宋','宋诗','song-poetry','','[]','白粲十萬艘，日夜隨東流。',24,'全唐诗/poet.song.162000.json','["白粲十萬艘，日夜隨東流。", "常平貫雖朽，還作蘇民不。"]'),
('1d5b6387-c198-4884-bae6-847bab62d397','上帥漕閔雨十首  其七','彭龜年','宋','宋诗','song-poetry','','[]','饑民日嗸嗸，洶洶潰堤水。',24,'全唐诗/poet.song.162000.json','["饑民日嗸嗸，洶洶潰堤水。", "痛決未可知，無易此一蟻。"]'),
('11ea6a90-782a-4ffd-8893-9d8736c2978a','上帥漕閔雨十首  其八','彭龜年','宋','宋诗','song-poetry','','[]','羸然一老翁，一病一傷和。',24,'全唐诗/poet.song.162000.json','["羸然一老翁，一病一傷和。", "寒暑不可測，奈此根本何。"]'),
('e1b47807-99da-462a-b49e-c7249afe8952','上帥漕閔雨十首  其九','彭龜年','宋','宋诗','song-poetry','','[]','天時不可齊，天心不可違。',24,'全唐诗/poet.song.162000.json','["天時不可齊，天心不可違。", "君子能知天，手轉豐凶機。"]'),
('9f1f0406-7539-47c0-84b6-663fe39f3393','上帥漕閔雨十首  其一○','彭龜年','宋','宋诗','song-poetry','','[]','德意徧巖谷，純心對雲天。',24,'全唐诗/poet.song.162000.json','["德意徧巖谷，純心對雲天。", "辦此一爇香，從公作豐年。"]'),
('cacdd20e-3291-4538-a6cf-60c3c76c1d48','送趙介之赴舂陵十首  其一','彭龜年','宋','宋诗','song-poetry','','[]','訪舊知俗非，好書與理近。',24,'全唐诗/poet.song.162000.json','["訪舊知俗非，好書與理近。", "氣味既如此，況復少畦畛。"]'),
('89a009e4-9c7b-4216-9f69-b6b445953ca6','送趙介之赴舂陵十首  其二','彭龜年','宋','宋诗','song-poetry','','[]','少年擢兩科，才氣揜公行。',24,'全唐诗/poet.song.162000.json','["少年擢兩科，才氣揜公行。", "恨無東坡翁，爲君賦秋陽。"]'),
('5b379650-d72f-4e8e-8f9c-bf273cf6abd8','送趙介之赴舂陵十首  其三','彭龜年','宋','宋诗','song-poetry','','[]','百里不足騁，千里漫同流。',24,'全唐诗/poet.song.162000.json','["百里不足騁，千里漫同流。", "推君友于心，對此良優優。"]'),
('9a1a99e9-ec6f-4b7f-95dc-95c6882106bc','送趙介之赴舂陵十首  其四','彭龜年','宋','宋诗','song-poetry','','[]','君知作縣易，我知作縣難。',24,'全唐诗/poet.song.162000.json','["君知作縣易，我知作縣難。", "臨深以思險，願勿作易觀。"]'),
('f15491ac-6987-4405-bf97-821f5bc2db8d','送趙介之赴舂陵十首  其五','彭龜年','宋','宋诗','song-poetry','','[]','賦拙君能傳，政拙君當繼。',24,'全唐诗/poet.song.162000.json','["賦拙君能傳，政拙君當繼。", "爲問舂陵人，巧者竟誰似。"]'),
('cd40d847-d826-4e79-8b66-c57476313cae','送趙介之赴舂陵十首  其六','彭龜年','宋','宋诗','song-poetry','','[]','嘗聞居士語，丁寧有深旨。',24,'全唐诗/poet.song.162000.json','["嘗聞居士語，丁寧有深旨。", "要使眼高人，不識貴公子。"]'),
