('2587a630-48c0-4924-a984-fc36528d8087','和安成彭清老五首  其一','彭龜年','宋','宋诗','song-poetry','','[]','山有喬松隰有臺，胸中日月太平開。',32,'全唐诗/poet.song.162000.json','["山有喬松隰有臺，胸中日月太平開。", "安車不入申公念，祇恐詔從天上來。"]'),
('f1f832bd-2f3e-4abf-96bc-c9af377664c4','和安成彭清老五首  其二','彭龜年','宋','宋诗','song-poetry','','[]','閉戶長吟何水曹，人間富貴九牛毛。',32,'全唐诗/poet.song.162000.json','["閉戶長吟何水曹，人間富貴九牛毛。", "博山一縷清香永，餘子不知更幾刀。"]'),
('b7079f81-caae-48df-a439-552086d6a62b','和安成彭清老五首  其三','彭龜年','宋','宋诗','song-poetry','','[]','鏗鏘金石三千首，吐納雲烟四十年。',32,'全唐诗/poet.song.162000.json','["鏗鏘金石三千首，吐納雲烟四十年。", "自有山神回俗駕，不愁大尹觸吟鞭。"]'),
('9b15b3c6-f508-4438-a6ce-c7226fb5e6ff','和安成彭清老五首  其四','彭龜年','宋','宋诗','song-poetry','','[]','里中諸老皆公識，破戒相過問故人。',32,'全唐诗/poet.song.162000.json','["里中諸老皆公識，破戒相過問故人。", "顧我那能來重客，知公不薄少年新。"]'),
('52fec4ef-38fe-4177-a448-f4faada342de','和安成彭清老五首  其五','彭龜年','宋','宋诗','song-poetry','','[]','公餘几上詩書亂，事簡庭中雁鶩休。',32,'全唐诗/poet.song.162000.json','["公餘几上詩書亂，事簡庭中雁鶩休。", "乞我新篇洗凡俗，蕭蕭風雨打窗秋。"]'),
('082cc7f1-22a6-46c4-b04d-cd19e75c0d1e','送吉州詹守五首  其一','彭龜年','宋','宋诗','song-poetry','','[]','平生兩耳熟龔黄，今日身親識大方。',32,'全唐诗/poet.song.162000.json','["平生兩耳熟龔黄，今日身親識大方。", "太史若徵循吏傳，一篇氣脈在耕桑。"]'),
('8ddcc00a-8c69-4f40-9b46-517042ebcabc','送吉州詹守五首  其二','彭龜年','宋','宋诗','song-poetry','','[]','諫垣禮樂三千疏，窗下詩書六十年。',32,'全唐诗/poet.song.162000.json','["諫垣禮樂三千疏，窗下詩書六十年。", "莫訝勾吳留不住，解隨膏雨到江邊。"]'),
('684d4375-2247-4bcb-87e4-77f9cc10b8ea','送吉州詹守五首  其三','彭龜年','宋','宋诗','song-poetry','','[]','骨鯁嘉言憶舊臣，故應赴詔近嚴宸。',32,'全唐诗/poet.song.162000.json','["骨鯁嘉言憶舊臣，故應赴詔近嚴宸。", "席前若下清明問，且說江南一味貧。"]'),
('c6df3b15-45e6-4049-a7dd-ef46f11fb714','送吉州詹守五首  其四','彭龜年','宋','宋诗','song-poetry','','[]','烏龍山下曉風輕，白鷺洲前暮靄凝。',32,'全唐诗/poet.song.162000.json','["烏龍山下曉風輕，白鷺洲前暮靄凝。", "今日可能如昨日，廬陵還解似嚴陵。"]'),
('89e431d5-8b5b-4b53-b5ab-4198f14c4dd2','送吉州詹守五首  其五','彭龜年','宋','宋诗','song-poetry','','[]','柏移平地失崎嶇，培壅恩深報一無。',32,'全唐诗/poet.song.162000.json','["柏移平地失崎嶇，培壅恩深報一無。", "惟有依歸意難盡，不堪㶁㶁水循渠。"]'),
('64acbcee-7849-44a9-8f44-f680335ba2e3','勸輸租','彭龜年','宋','宋诗','song-poetry','','[]','佃氓輸課稍逡巡，排日呼來不厭頻。',32,'全唐诗/poet.song.162000.json','["佃氓輸課稍逡巡，排日呼來不厭頻。", "認取私家催米意，莫憎門外督租人。"]'),
('77d7dbc8-a883-4914-ad51-60a08eda6640','送鄭尚書守建安十首  其一','彭龜年','宋','宋诗','song-poetry','','[]','自從秉節簉明廷，讜論忠言四海傾。',32,'全唐诗/poet.song.162000.json','["自從秉節簉明廷，讜論忠言四海傾。", "何事不關天下念，此心無著世間名。"]'),
('0916db5b-bcbb-4ad8-b8d5-96de2cc2cf1c','送鄭尚書守建安十首  其二','彭龜年','宋','宋诗','song-poetry','','[]','親奉王明御六龍，合登宰路冠諸公。',32,'全唐诗/poet.song.162000.json','["親奉王明御六龍，合登宰路冠諸公。", "未應天子青宮友，猶滯黄幡豹尾中。"]'),
('940aa29d-bb52-41ee-ba0e-cfa0a33ae54b','送鄭尚書守建安十首  其三','彭龜年','宋','宋诗','song-poetry','','[]','聞上金華勸講班，啟心長是片言間。',32,'全唐诗/poet.song.162000.json','["聞上金華勸講班，啟心長是片言間。", "一從元祐諸公後，得此淵源自玉山。"]'),
('d5c64299-bc9a-4f58-9fc7-317a2ed0bd53','送鄭尚書守建安十首  其四','彭龜年','宋','宋诗','song-poetry','','[]','春來苦雪夏來寒，南去愁霖北去乾。',32,'全唐诗/poet.song.162000.json','["春來苦雪夏來寒，南去愁霖北去乾。", "又報豐年無一事，乞身遠去可能安。"]'),
('9a005d38-b6d6-4a4e-af8c-aae960acc3b7','送鄭尚書守建安十首  其五','彭龜年','宋','宋诗','song-poetry','','[]','一賢去國四方嗔，却恐猜疑到玉宸。',32,'全唐诗/poet.song.162000.json','["一賢去國四方嗔，却恐猜疑到玉宸。", "急把丐閒書報下，此行猶足律貪人。"]');
